/* AUTO-GENERATED — Florida Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["FL"] = {"code":"FL","name":"Florida","agency":"Florida FLHSMV","agencyShort":"FLHSMV","handbook":"https://www.flhsmv.gov/driver-licenses-id-cards/commercial-motor-vehicle-driver-licenses/","links":{},"en":[{"q":"On Florida highways, what is the maximum total outside width allowed for a vehicle or its load (excluding required safety devices) without an oversize permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","114 inches (9 feet 6 inches)"],"answer":1,"explanation":"Florida Statute 316.515 sets the maximum total outside width of any vehicle or its load at 102 inches (8 feet 6 inches), exclusive of safety devices. Exceeding this requires an FDOT oversize permit.","handbook":"","hbref":""},{"q":"What is the maximum height, including load, for a vehicle on Florida highways without a permit?","options":["13 feet","14 feet","14 feet 6 inches","13 feet 6 inches"],"answer":3,"explanation":"Under Florida Statute 316.515, no vehicle may exceed a height of 13 feet 6 inches, inclusive of load. (Automobile transporters are allowed up to 14 feet.) Florida law places responsibility for clearing overhead structures on the driver.","handbook":"","hbref":""},{"q":"In Florida, what is the maximum length of a semitrailer operating in a truck tractor-semitrailer combination on the State Highway System (before special length allowances apply)?","options":["48 feet","45 feet","53 feet","57 feet"],"answer":0,"explanation":"Florida Statute 316.515 limits a semitrailer in a truck tractor-semitrailer combination to 48 feet in extreme overall dimension; semitrailers over 48 but not more than 57 feet may operate only on roads not restricted by FDOT or local authorities.","handbook":"","hbref":""},{"q":"What is the maximum length of a single straight truck in extreme overall dimension under Florida law?","options":["35 feet","45 feet","40 feet","48 feet"],"answer":2,"explanation":"Florida Statute 316.515 limits a straight truck (single vehicle) to a length of 40 feet in extreme overall dimension.","handbook":"","hbref":""},{"q":"In a Florida truck tractor-semitrailer-trailer (double/twin trailer) combination, what is the maximum length of each individual trailer?","options":["24 feet","28 feet","33 feet","40 feet"],"answer":1,"explanation":"Florida Statute 316.515 provides that no semitrailer or trailer operating in a truck tractor-semitrailer-trailer combination may exceed a length of 28 feet, matching the federal standard for twin trailers.","handbook":"","hbref":""},{"q":"What is the maximum gross weight imposed on a Florida highway by the wheels of any one single axle of a vehicle?","options":["18,000 pounds","22,400 pounds","24,000 pounds","20,000 pounds"],"answer":3,"explanation":"Florida Statute 316.535 limits the gross weight imposed by the wheels of any one single axle to 20,000 pounds.","handbook":"","hbref":""},{"q":"What is the maximum overall gross weight, including all enforcement tolerances, for any vehicle or combination of vehicles on Florida highways?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"answer":2,"explanation":"Florida Statute 316.535 caps the overall gross weight of any vehicle or combination of vehicles at 80,000 pounds, including all enforcement tolerances. This matches the federal limit for the Interstate system.","handbook":"","hbref":""},{"q":"On Florida and Interstate highways, the maximum weight allowed on a tandem axle group (two consecutive axles spaced more than 40 inches but not more than 96 inches apart) is generally:","options":["34,000 pounds","30,000 pounds","40,000 pounds","44,000 pounds"],"answer":0,"explanation":"Under the federal weight standard applied in Florida, a tandem axle group is limited to 34,000 pounds. Florida applies the Federal Bridge Formula and the 80,000-pound gross cap of Statute 316.535 on the Interstate system.","handbook":"","hbref":""},{"q":"Florida uses the Federal Bridge Formula to limit weight based on axle spacing. In the formula W = 500[LN/(N-1) + 12N + 36], what does the letter 'L' represent?","options":["The legal load weight in pounds","The distance in feet between the extremes of a group of axles","The length of the trailer in inches","The licensed gross weight of the vehicle"],"answer":1,"explanation":"In the Federal Bridge Formula adopted in Florida Statute 316.535, L is the distance in feet between the extremes of any group of two or more consecutive axles, N is the number of axles in the group, and W is the gross weight allowed.","handbook":"","hbref":""},{"q":"The Federal Bridge Formula used in Florida is designed primarily to protect what?","options":["The vehicle's tires from overload","The driver from fatigue","The cargo from shifting","Bridges and roadway pavement from concentrated weight"],"answer":3,"explanation":"The Federal Bridge Formula in Florida Statute 316.535 spreads weight over a greater distance (more axles, longer spacing) to protect bridges and pavement; closely spaced axles concentrate load and must weigh less.","handbook":"","hbref":""},{"q":"Which Florida agency issues oversize and overweight permits for loads that exceed the legal size or weight limits?","options":["Florida Department of Highway Safety and Motor Vehicles (DHSMV)","Florida Highway Patrol (FHP)","Florida Department of Transportation (FDOT)","U.S. Federal Motor Carrier Safety Administration (FMCSA)"],"answer":2,"explanation":"The Florida Department of Transportation (FDOT) issues oversize/overweight permits through its Permit Office and online Permit Application System for loads exceeding the limits in Florida Statutes 316.515 and 316.535.","handbook":"","hbref":""},{"q":"A load is 110 inches wide. Before moving it on a Florida highway, the driver must:","options":["Obtain an FDOT oversize permit","Do nothing; 110 inches is legal","Only reduce speed by 10 mph","Get approval from local police only"],"answer":0,"explanation":"Because 110 inches exceeds the 102-inch (8'6\") legal width limit in Florida Statute 316.515, the move requires an FDOT oversize permit. Loads cannot exceed legal width without a permit.","handbook":"","hbref":""},{"q":"Which type of FDOT permit authorizes a single oversize/overweight move from one origin to one destination?","options":["Annual blanket permit","Trip (single-trip) permit","Route-specific blanket permit","Vehicle-specific blanket permit"],"answer":1,"explanation":"FDOT issues a trip (single-trip) permit for a single move; blanket permits (annual, route-specific, or vehicle-specific) cover repeated moves over a longer period. Trip permits are commonly valid for a limited number of days to complete the move.","handbook":"","hbref":""},{"q":"Under Florida/FDOT permit rules, at what width does an oversize load generally begin to require at least one escort (pilot) vehicle?","options":["Over 8 feet 6 inches","Over 10 feet","Over 12 feet","Over 16 feet"],"answer":2,"explanation":"Per FDOT oversize-load rules, loads over 12 feet wide generally require at least one escort vehicle; loads over 14 feet typically require two escorts, and the widest loads may require law-enforcement escort.","handbook":"","hbref":""},{"q":"An oversize load moving under an FDOT permit in Florida is generally required to display:","options":["Only headlights on during daylight","A green permit placard only","No special markings if under 12 feet wide","'OVERSIZE LOAD' signs and warning flags at the corners/extremities"],"answer":3,"explanation":"FDOT permit conditions require oversize loads to display 'OVERSIZE LOAD' warning signs and colored (red/orange) flags at the load's corners and widest points so other traffic can see the over-dimensional load.","handbook":"","hbref":""},{"q":"According to federal cargo securement rules followed in Florida, the aggregate working load limit (WLL) of the tiedowns must be at least what fraction of the weight of the cargo secured?","options":["One-half (50%)","One-quarter (25%)","Two-thirds (67%)","The full weight (100%)"],"answer":0,"explanation":"Federal cargo securement rules (49 CFR 393.106), which Florida enforces, require the aggregate working load limit of all tiedowns to be at least one-half (50%) of the weight of the article or cargo being secured.","handbook":"","hbref":""},{"q":"Under the cargo securement rules applied in Florida, an article of cargo 5 feet or less in length and weighing 1,100 pounds or less requires at least how many tiedowns?","options":["Two tiedowns","One tiedown","Three tiedowns","No tiedowns if blocked"],"answer":1,"explanation":"Under 49 CFR 393.110 (enforced in Florida), an article 5 feet or less in length and 1,100 pounds or less requires a minimum of one tiedown; longer or heavier articles require two or more.","handbook":"","hbref":""},{"q":"After loading and beginning a trip, when must a Florida CDL driver first inspect the cargo and securement devices?","options":["Within the first 25 miles","Within the first 100 miles","Within the first 50 miles","Only at the destination"],"answer":2,"explanation":"Federal rules followed in Florida (49 CFR 392.9) require the driver to inspect the cargo and securing devices within the first 50 miles after beginning a trip, and to re-examine them periodically thereafter.","handbook":"","hbref":""},{"q":"Florida law provides certain reduced-penalty or tolerance provisions on weight limits primarily for haulers of which type of load?","options":["General freight in dry vans","Hazardous materials","Household goods","Natural, unprocessed agricultural products"],"answer":3,"explanation":"Florida's traffic and weight statutes (Chapter 316) provide special tolerance/penalty provisions for transporting natural, unprocessed agricultural products, recognizing the seasonal, farm-related nature of these loads.","handbook":"","hbref":""},{"q":"A driver hauling a non-divisible load that is 14 feet wide and weighs 120,000 pounds in Florida must do what before the move?","options":["Obtain an FDOT oversize AND overweight permit","Nothing; non-divisible loads are exempt","Only travel at night","Reduce the load to legal limits even though it cannot be divided"],"answer":0,"explanation":"A non-divisible load that exceeds both the 102-inch width limit (316.515) and the 80,000-pound gross weight limit (316.535) requires an FDOT oversize/overweight permit, which also sets route, escort, and time-of-travel conditions.","handbook":"","hbref":""},{"q":"In Florida, which CDL class is required to operate a combination of vehicles with a gross combination weight rating of 26,001 lbs or more, where the towed unit exceeds 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"A Florida Class A CDL is required to operate truck/trailer combinations rated 26,001 lbs or more that tow a unit over 10,000 lbs (e.g., tractor-trailers). Source: FLHSMV Commercial Driver License page; FL CDL Handbook.","handbook":"","hbref":""},{"q":"A Florida driver wants to operate a single straight truck or bus rated at 26,001 lbs or more that is not towing a trailer over 10,000 lbs. Which CDL class fits?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"A Florida Class B CDL covers single (straight) trucks and buses rated 26,001 lbs or more that do not tow a unit over 10,000 lbs. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"Which Florida CDL class is required for a smaller vehicle (not meeting Class A or B weight) that is designed to transport 16 or more people or carries placarded hazardous materials?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"A Florida Class C CDL applies to vehicles not meeting Class A or B weight standards but designed to carry 16+ persons or transporting placarded hazardous materials. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Florida CDL restricted to intrastate (within-Florida) operation only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Florida allows a CDL at 18, but drivers under 21 are restricted to intrastate (within-state) operation. Source: FLHSMV Commercial Driver License page; Florida Statutes Ch. 322.","handbook":"","hbref":""},{"q":"A 19-year-old Florida CDL holder wants to drive across state lines (interstate) or haul hazardous materials. Why can't they?","options":["Interstate operation and hazmat require a minimum age of 21","Interstate operation requires a minimum age of 23","They must first hold an intrastate CDL for five years","Drivers under 25 may never haul any freight"],"answer":0,"explanation":"Florida CDL holders under 21 are limited to intrastate driving; interstate operation and transporting hazardous materials require a driver to be at least 21. Source: FLHSMV; federal 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Which endorsement does a Florida CDL holder need to transport placarded amounts of hazardous materials?","options":["N endorsement","T endorsement","P endorsement","H endorsement"],"answer":3,"explanation":"The H (Hazmat) endorsement authorizes transporting placarded hazardous materials and requires passing the hazmat knowledge test. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"Which endorsement is required to drive a tank vehicle in Florida?","options":["N (Tank Vehicles)","T (Double/Triple Trailers)","H (Hazmat)","S (School Bus)"],"answer":0,"explanation":"The N endorsement is issued to drivers who pass the required tank-vehicle knowledge test and will operate tank vehicles. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"A Florida driver plans to pull double or triple tractor-trailer combinations. Which endorsement is required?","options":["P (Passengers)","T (Double/Triple Trailers)","N (Tank Vehicles)","H (Hazmat)"],"answer":1,"explanation":"The T endorsement, earned by passing the required knowledge test, allows operation of double and triple trailer combinations. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"Which endorsement does Florida require to drive a vehicle designed to transport 16 or more people (more than 15 passengers including the driver)?","options":["S (School Bus)","P (Passengers)","N (Tank Vehicles)","T (Double/Triple Trailers)"],"answer":1,"explanation":"The P (Passenger) endorsement requires passing both knowledge and skills tests and is needed for passenger vehicles designed for more than 15 persons including the driver. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"To obtain a Florida School Bus (S) endorsement, what additional endorsement must the driver also hold?","options":["The H (Hazmat) endorsement","The N (Tank) endorsement","The P (Passenger) endorsement","The T (Double/Triple) endorsement"],"answer":2,"explanation":"Florida requires the P (Passenger) endorsement in addition to the S (School Bus) endorsement; the S endorsement requires passing its own knowledge and skills tests. Source: FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"Which Florida CDL endorsement requires a federal TSA security threat assessment, including fingerprinting and a national background check, before it can be issued?","options":["P (Passengers)","T (Double/Triple Trailers)","N (Tank Vehicles)","H (Hazmat)"],"answer":3,"explanation":"Under the USA PATRIOT Act, the H (Hazmat) endorsement requires applicants to be fingerprinted and pass a TSA background check before issuance; an additional fee applies. Source: FLHSMV Commercial Driver License page; TSA.","handbook":"","hbref":""},{"q":"How long must a driver hold a Florida Commercial Learner Permit (CLP) before being allowed to take the CDL skills (driving) test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"Federal rules adopted by Florida require holding the CLP for a minimum of 14 days before taking the CDL skills test. Source: FLHSMV; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"While practicing with a Florida CLP, who must accompany the permit holder in the commercial vehicle?","options":["Any licensed driver age 21 or older","A holder of a valid CDL with the proper class and endorsements, seated next to or near the driver","A certified CDL instructor only, on a closed course","No supervisor is required once the knowledge test is passed"],"answer":1,"explanation":"A CLP holder must be accompanied by a valid CDL holder with the appropriate group and endorsements, physically present beside (or, for buses, just behind) the driver under direct supervision. Source: FLHSMV; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What passenger restriction applies to a Florida CLP holder operating a commercial vehicle?","options":["They may carry up to 8 passengers for training purposes","They may carry passengers only during daylight hours","They may not carry passengers other than the supervising CDL holder","They may carry passengers if all wear seat belts"],"answer":2,"explanation":"A CLP holder may not operate a bus or vehicle occupied by passengers other than the accompanying valid CDL holder/mentor. Source: FLHSMV; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"If a Florida CDL applicant does not take and pass the air brakes knowledge test, what happens to their license?","options":["An 'L' restriction is added prohibiting vehicles with air brakes","A 'K' restriction limiting them to intrastate driving is added","The CDL is downgraded to a Class C automatically","No CDL can be issued until air brakes is passed"],"answer":0,"explanation":"Failing or skipping the air brakes test results in an 'L' restriction, prohibiting the driver from operating commercial vehicles equipped with air brakes. Source: FLHSMV; FL CDL Handbook.","handbook":"","hbref":""},{"q":"Under federal Entry-Level Driver Training (ELDT) rules adopted in Florida, which applicants must complete ELDT before testing?","options":["Only drivers who already hold an out-of-state CDL","First-time CDL applicants, Class B-to-A upgrades, and first-time H, P, or S endorsement seekers","Only drivers seeking the N or T endorsement","Only drivers over the age of 21"],"answer":1,"explanation":"ELDT is required for first-time CDL applicants, upgrades from Class B to Class A, and first-time Hazmat, Passenger, or School Bus endorsements (for CLPs obtained on or after Feb 7, 2022). Source: FMCSA ELDT rule; FLHSMV.","handbook":"","hbref":""},{"q":"Where must a Florida ELDT training provider be listed for a driver's training to count toward CDL eligibility?","options":["On the FMCSA Training Provider Registry","On the FLHSMV approved-school list only","On the TSA vendor registry","On any state community-college roster"],"answer":0,"explanation":"ELDT theory and behind-the-wheel training must be delivered by a provider listed on the FMCSA Training Provider Registry (TPR), which submits completion electronically. Source: FMCSA Training Provider Registry; FLHSMV.","handbook":"","hbref":""},{"q":"For the Hazmat (H) endorsement specifically, what ELDT step must a Florida applicant complete?","options":["Behind-the-wheel range training before the road test","The ELDT theory (knowledge) portion before taking the Hazmat knowledge test","A full skills test in a tank vehicle","No ELDT is ever required for Hazmat"],"answer":1,"explanation":"Hazmat applicants must complete the ELDT theory portion through a registered provider before taking the Hazmat knowledge exam. Source: FMCSA ELDT rule; FLHSMV.","handbook":"","hbref":""},{"q":"A Florida CDL driver who operates across state lines and is required to maintain a federal medical certificate would self-certify under which category?","options":["Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)"],"answer":3,"explanation":"Non-Excepted Interstate (NI) applies to drivers in interstate commerce who must hold a valid medical examiner's certificate from an FMCSA National Registry examiner. Source: FLHSMV self-certification; FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which document does Florida accept as a primary proof of identity for a REAL ID-compliant CDL application?","options":["A certified U.S. birth certificate or valid U.S. passport","A current utility bill in the applicant's name","A Florida voter registration card","An employer-issued photo ID badge"],"answer":0,"explanation":"For a REAL ID-compliant CDL, Florida requires a primary identity document such as a certified U.S. birth certificate or valid U.S. passport/passport card, plus proof of Social Security number and two proofs of residential address. Source: FLHSMV What to Bring / REAL ID.","handbook":"","hbref":""},{"q":"In Florida, what is the maximum blood alcohol concentration (BAC) at which a CDL holder may legally operate a commercial motor vehicle (CMV)?","options":["0.08 percent","0.02 percent","0.10 percent","0.04 percent"],"answer":3,"explanation":"It is illegal to operate a CMV in Florida if your BAC is 0.04 percent or more, which is half the 0.08 limit that applies to non-commercial drivers. Source: Florida CDL Handbook (FLHSMV), Driver Disqualifications; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Florida's implied-consent law, what happens the moment a person operates a commercial motor vehicle in the state?","options":["They must carry a separate breath-test permit at all times","They are deemed to have given consent to alcohol testing","They waive the right to a CDL hearing entirely","They are exempt from testing unless an accident occurs"],"answer":1,"explanation":"By operating a CMV in Florida, a driver is deemed to have given consent to testing for alcohol. Refusing the test carries the same disqualification as a DUI conviction. Source: Florida CDL Handbook (FLHSMV); Florida Statutes Ch. 322 (implied consent).","handbook":"","hbref":""},{"q":"A CDL holder is convicted of a first major offense, such as DUI, while NOT carrying hazardous materials. What is the minimum CDL disqualification period in Florida?","options":["60 days","3 years","1 year","Lifetime"],"answer":2,"explanation":"A first major offense (DUI, BAC 0.04 or higher in a CMV, refusing a test, leaving an accident scene, or using a vehicle to commit a felony) results in at least a 1-year CDL disqualification. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a first major offense occurs while a CDL driver is operating a CMV placarded for hazardous materials, what is the minimum disqualification period in Florida?","options":["3 years","1 year","120 days","Lifetime"],"answer":0,"explanation":"A first major offense committed while operating a CMV placarded for hazardous materials raises the minimum disqualification from 1 year to at least 3 years. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the consequence in Florida for a CDL holder who is convicted of a SECOND major offense at any time during their driving career?","options":["A 3-year disqualification","Loss of the CDL for life","A 1-year disqualification","A 120-day disqualification"],"answer":1,"explanation":"A second major offense results in a lifetime CDL disqualification. Florida may allow reinstatement consideration after a minimum period under limited circumstances, but the rule is a lifetime ban. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL driver in Florida is lawfully asked to submit to a blood alcohol test and refuses. How is this treated for CDL disqualification purposes?","options":["It is only a serious violation, disqualifying for 60 days","It is a major offense, disqualifying for at least 1 year","It carries no CDL penalty if the driver was off duty","It results in a 24-hour out-of-service order only"],"answer":1,"explanation":"Refusing to submit to alcohol testing is treated as a major offense, carrying the same minimum 1-year disqualification (3 years if placarded for HazMat) as a DUI conviction. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Florida CDL holder?","options":["Driving with a BAC of 0.04 percent in a CMV","Refusing a lawful alcohol test","Operating a CMV under an out-of-service order","Excessive speeding, 15 mph or more over the posted limit"],"answer":3,"explanation":"Excessive speeding (15 mph or more over the limit) is a serious traffic violation. The other choices are major offenses or out-of-service violations, which carry different, more severe penalties. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period will trigger a CDL disqualification in Florida, and for how long for the second one?","options":["2 violations result in at least a 120-day disqualification","3 violations result in at least a 60-day disqualification","2 violations result in at least a 60-day disqualification","2 violations result in at least a 1-year disqualification"],"answer":2,"explanation":"A second serious traffic violation within a 3-year period results in a disqualification of at least 60 days. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in Florida for a THIRD serious traffic violation committed within a 3-year period?","options":["60 days","1 year","120 days","30 days"],"answer":2,"explanation":"A third serious traffic violation within a 3-year period results in a disqualification of at least 120 days. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is a serious traffic violation rather than a major offense for a Florida CDL holder?","options":["Improper or erratic lane changes","Leaving the scene of an accident","Using a vehicle to commit a felony","Driving under the influence of a controlled substance"],"answer":0,"explanation":"Improper or erratic lane changes is a serious traffic violation. The other three are major offenses carrying a minimum 1-year (or lifetime) disqualification. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Florida and federal CDL rules, how is texting while driving a CMV classified for disqualification purposes?","options":["As a major offense with a 1-year disqualification","As a serious traffic violation","As an out-of-service order violation","As a non-CDL infraction with no disqualification effect"],"answer":1,"explanation":"Violating the law that prohibits texting while driving a CMV is a serious traffic violation. Combined with other serious violations within 3 years, it can lead to a 60- or 120-day disqualification. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51 and 392.80.","handbook":"","hbref":""},{"q":"Using a handheld mobile telephone while driving a CMV is prohibited for CDL drivers in Florida. For disqualification purposes, this offense is treated as:","options":["A major offense requiring lifetime disqualification","A railroad-crossing violation","A serious traffic violation","An out-of-service order violation"],"answer":2,"explanation":"Violating the law prohibiting use of a handheld mobile telephone while driving a CMV is a serious traffic violation; repeated serious violations within 3 years lead to 60- or 120-day disqualifications. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51 and 392.82.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a FIRST conviction of a railroad-highway grade crossing violation in Florida?","options":["120 days","60 days","1 year","30 days"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of at least 60 days. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Florida CDL holder commits a SECOND railroad-highway grade crossing violation within a 3-year period. What is the minimum disqualification?","options":["60 days","1 year","180 days","120 days"],"answer":3,"explanation":"A second railroad-highway grade crossing violation within 3 years results in a disqualification of at least 120 days. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a THIRD railroad-highway grade crossing violation within a 3-year period in Florida?","options":["120 days","60 days","1 year","Lifetime"],"answer":2,"explanation":"A third railroad-highway grade crossing violation within a 3-year period results in a disqualification of at least 1 year. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Florida CDL driver violates an out-of-service order for the FIRST time while not transporting hazardous materials or passengers. What is the minimum disqualification?","options":["180 days","60 days","90 days","120 days"],"answer":0,"explanation":"A first out-of-service order violation results in a disqualification of at least 180 days (longer if transporting HazMat or passengers). Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a SECOND out-of-service order violation within a 10-year period in Florida?","options":["180 days","1 year","3 years","2 years"],"answer":3,"explanation":"A second out-of-service order violation within a 10-year period results in a disqualification of at least 2 years. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Florida CDL driver commits a THIRD or subsequent out-of-service order violation within a 10-year period. What is the minimum disqualification?","options":["3 years","2 years","1 year","180 days"],"answer":0,"explanation":"A third or subsequent out-of-service order violation within a 10-year period results in a disqualification of at least 3 years. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a CDL driver in Florida is found to have ANY detectable amount of alcohol while on duty (below 0.04 BAC), what is the immediate consequence?","options":["Placed out of service for 24 hours","Permanent loss of the CDL","A 60-day disqualification","A mandatory 1-year disqualification"],"answer":0,"explanation":"A driver with any detectable amount of alcohol under 0.04 is placed out of service for 24 hours. A BAC of 0.04 or higher is a major offense disqualifying the driver for at least 1 year. Source: Florida CDL Handbook (FLHSMV); 49 CFR 392.5 and 383.51.","handbook":"","hbref":""},{"q":"Which offense results in a MANDATORY lifetime CDL disqualification with no possibility of reinstatement in Florida?","options":["A first DUI conviction in a CMV","Two serious traffic violations within 3 years","A first railroad-crossing violation","Using a CMV to manufacture, distribute, or dispense a controlled substance"],"answer":3,"explanation":"Using a CMV in the commission of a felony involving the manufacture, distribution, or dispensing of a controlled substance carries a mandatory lifetime disqualification with no reinstatement. Source: Florida CDL Handbook (FLHSMV); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Florida's Move Over Act, you are driving a tractor-trailer on a multi-lane highway and approach a stopped patrol car with emergency lights flashing. What does the law require you to do first?","options":["Come to a complete stop in your current lane until the emergency vehicle leaves","Vacate the lane closest to the emergency vehicle as soon as it is safe to do so","Sound your horn to warn the officer of your approach","Maintain your speed but turn on your hazard lights"],"answer":1,"explanation":"Florida's Move Over Act (Fla. Stat. 316.126) requires drivers on a multi-lane road to vacate the lane closest to the stopped emergency or service vehicle as soon as it is safe; only if moving over is not possible must you slow down.","handbook":"","hbref":""},{"q":"On a two-lane Florida road posted at 55 mph, you approach a stopped wrecker displaying amber lights and cannot safely change lanes. To how many miles per hour must you reduce your speed?","options":["45 mph","25 mph","35 mph","55 mph; no reduction is required on a two-lane road"],"answer":2,"explanation":"Under Fla. Stat. 316.126, when you cannot move over, you must slow to 20 mph below the posted limit when the posted speed is 25 mph or higher. On a 55 mph road that means 35 mph.","handbook":"","hbref":""},{"q":"Florida's Move Over Act requires reduced speed when you cannot change lanes. On a roadway where the posted speed limit is 20 mph or less, to what speed must you slow when passing a qualifying stopped vehicle?","options":["5 mph","10 mph","0 mph (full stop)","15 mph"],"answer":0,"explanation":"Fla. Stat. 316.126 provides that when the posted speed limit is 20 mph or less, a driver who cannot move over must slow to 5 mph when passing the stopped vehicle.","handbook":"","hbref":""},{"q":"In addition to emergency vehicles, Florida's Move Over law (Fla. Stat. 316.126) also protects which of the following stopped vehicles displaying proper signals?","options":["Sanitation, utility service, and road or bridge maintenance vehicles, and disabled vehicles with hazard lights","Only marked law enforcement and fire vehicles","Only ambulances and tow trucks","Any privately owned passenger car parked on the shoulder"],"answer":0,"explanation":"Fla. Stat. 316.126 extends Move Over protections to sanitation vehicles, utility service vehicles, wreckers, road and bridge maintenance/construction vehicles, and disabled motor vehicles displaying hazard lights, in addition to emergency vehicles.","handbook":"","hbref":""},{"q":"You are driving a bus carrying passengers and approach a railroad grade crossing in Florida. At what distance from the nearest rail must you stop?","options":["Between 5 and 15 feet","Between 50 and 100 feet","Between 15 and 50 feet","Exactly 25 feet, no closer and no farther"],"answer":2,"explanation":"Buses carrying passengers and placarded hazardous materials vehicles must stop no closer than 15 feet and no farther than 50 feet from the nearest rail, then look and listen before crossing (Florida CDL Handbook; FMCSR 392.10).","handbook":"","hbref":""},{"q":"Which commercial vehicle is required to make a mandatory stop at every railroad crossing in Florida unless an exception applies?","options":["An empty flatbed truck with no cargo","A vehicle transporting placarded amounts of hazardous materials","A delivery van carrying general freight","A dump truck hauling sand"],"answer":1,"explanation":"Under federal rules adopted in the Florida CDL Handbook (FMCSR 392.10), vehicles required to be placarded for hazardous materials, and buses carrying passengers, must stop at railroad crossings; ordinary freight vehicles are not required to stop.","handbook":"","hbref":""},{"q":"At which railroad crossing is a placarded hazmat driver or bus driver NOT required to stop?","options":["A crossing where a working traffic signal shows green, or that is marked with an official Exempt sign","Any crossing on a rural two-lane road","A crossing with crossbucks but no flashing lights","A crossing immediately after sunset"],"answer":0,"explanation":"The Florida CDL Handbook (FMCSR 392.10) lists exceptions to the mandatory stop: a green traffic-control signal, a crossing marked with an official Exempt sign, a crossing directed by a police officer or flagger, and tracks used only for streetcars or industrial switching.","handbook":"","hbref":""},{"q":"When crossing railroad tracks in a commercial vehicle with a manual transmission, what should you do?","options":["Shift to a higher gear midway across to clear the tracks faster","Stop on the tracks to check your mirrors before proceeding","Shift into neutral and coast across the tracks","Cross in a low gear and do not shift gears while on the tracks"],"answer":3,"explanation":"The Florida CDL Handbook instructs drivers to pick a gear that will get the vehicle completely across the tracks and to never shift gears while crossing, to avoid stalling on the tracks.","handbook":"","hbref":""},{"q":"On a Florida two-way street with no median or barrier, a school bus stops with its red lights flashing and stop arm out. What must traffic approaching from the opposite direction do?","options":["Slow to 10 mph but may continue past the bus","Continue normally because opposite-direction traffic never has to stop","Stop and remain stopped until the lights stop flashing and the stop arm is withdrawn","Stop only if children are visibly crossing the road"],"answer":2,"explanation":"Fla. Stat. 316.172 requires all traffic, including opposite-direction traffic on an undivided two-way roadway, to stop for a stopped school bus with flashing red lights, and to remain stopped until the lights stop and the stop arm withdraws.","handbook":"","hbref":""},{"q":"Under Florida law, drivers traveling in the opposite direction are NOT required to stop for a stopped school bus when the roadway is divided by which of the following?","options":["A single solid yellow center line","A painted two-way left-turn lane","A raised median, a physical barrier, or an unpaved space of at least 5 feet","A row of reflective lane markers"],"answer":2,"explanation":"Fla. Stat. 316.172(2) exempts opposite-direction traffic from stopping only when the divided highway separates traffic by a raised median, a physical barrier, or an unpaved space of at least 5 feet. Paint lines alone do not qualify.","handbook":"","hbref":""},{"q":"If you must stop your commercial motor vehicle on the shoulder of a one-way or divided Florida highway, where must you place your three emergency warning devices?","options":["5 feet, 50 feet, and 150 feet toward the approaching traffic","All three within 10 feet of the rear of the vehicle","25 feet, 75 feet, and 125 feet ahead of the vehicle","10 feet, 100 feet, and 200 feet toward the approaching traffic"],"answer":3,"explanation":"The Florida CDL Handbook (FMCSR 392.22) requires placing warning devices at 10 feet, 100 feet, and 200 feet toward approaching traffic on a one-way or divided highway.","handbook":"","hbref":""},{"q":"After stopping your commercial vehicle on the traveled portion or shoulder of a Florida highway, within how many seconds must you activate your hazard (four-way flasher) warning lights?","options":["Within 30 minutes, only at night","Only after warning triangles are already placed","Immediately, and place warning devices within 10 minutes","There is no time requirement for hazard lights"],"answer":2,"explanation":"Under FMCSR 392.22, adopted in the Florida CDL Handbook, a stopped CMV must immediately turn on its hazard warning flashers and place warning devices (triangles/flares) within 10 minutes.","handbook":"","hbref":""},{"q":"On a two-lane Florida road carrying traffic in both directions, where should warning triangles be placed when your CMV is stopped?","options":["Within 10 feet of the vehicle and 100 feet behind and ahead of it","Only 200 feet behind the vehicle","Only at the front bumper of the vehicle","50 feet behind and 50 feet ahead only"],"answer":0,"explanation":"The Florida CDL Handbook (FMCSR 392.22) directs that on a two-lane or undivided road you place one warning device within 10 feet of the vehicle and one 100 feet behind and one 100 feet ahead of the stopped vehicle.","handbook":"","hbref":""},{"q":"On a Florida roadway with three or more lanes in your direction, the general right-lane rule requires slower-moving vehicles, including trucks, to do what?","options":["Always travel in the center lane regardless of speed","Use the far-left lane to keep right-lane traffic clear","Choose any lane freely with no restriction","Keep to the right-hand lane except when overtaking, passing, or preparing for a left turn"],"answer":3,"explanation":"Fla. Stat. 316.081 requires any vehicle traveling slower than the normal speed of traffic to use the right-hand lane (or as close to the right edge as practicable) except when overtaking/passing or preparing for a left turn.","handbook":"","hbref":""},{"q":"Outside of business or residence districts, what is Florida's statutory default maximum speed limit where no other limit is posted?","options":["55 mph","70 mph","65 mph","45 mph"],"answer":0,"explanation":"Fla. Stat. 316.183/316.187 set the statutory maximum at 55 mph at locations outside business or residence districts unless a different limit is posted; 30 mph applies in business or residence districts.","handbook":"","hbref":""},{"q":"On a Florida interstate highway of at least four lanes posted at 70 mph, what is the statutory minimum speed limit?","options":["40 mph","55 mph","45 mph","50 mph"],"answer":3,"explanation":"Fla. Stat. 316.183 establishes a minimum speed of 50 mph on divided interstate highways of at least four lanes where the maximum posted limit is 70 mph.","handbook":"","hbref":""},{"q":"Under Florida's distracted driving law (Fla. Stat. 316.305), what is prohibited while operating a moving motor vehicle?","options":["Any use of a hands-free Bluetooth speaker for a phone call","Manually typing or reading data for nonvoice communication such as texting, e-mailing, or instant messaging","Listening to navigation voice directions","Having a mounted phone visible in the cab"],"answer":1,"explanation":"Fla. Stat. 316.305 prohibits manually typing or entering characters and sending or reading data on a wireless device for nonvoice interpersonal communication (texting, e-mail, instant messaging) while driving.","handbook":"","hbref":""},{"q":"Which statement about enforcement of Florida's texting-while-driving law (Fla. Stat. 316.305) is correct?","options":["It is a secondary offense requiring another violation first","It is a primary offense, so an officer may stop and cite a driver solely for texting","It applies only to drivers under 18 years of age","It applies only between sunset and sunrise"],"answer":1,"explanation":"Since 2019, Fla. Stat. 316.305 makes texting while driving a primary offense, authorizing officers to stop and cite a driver for that violation alone.","handbook":"","hbref":""},{"q":"When Florida activates Emergency Shoulder Use (ESU) on an evacuation route during a hurricane, which vehicles are NOT permitted to use the opened shoulder lane?","options":["Passenger cars and pickup trucks","Large trucks, buses, and trailers","Motorcycles and SUVs","All vehicles are allowed to use the shoulder equally"],"answer":1,"explanation":"Under Florida's FDOT Emergency Shoulder Use plan (which replaced contraflow), all motorists EXCEPT large trucks, buses, and trailers may use the paved shoulder as a temporary travel lane during a hurricane evacuation.","handbook":"","hbref":""},{"q":"Regarding extended idling of heavy-duty commercial vehicles, which statement reflects current Florida law?","options":["Florida bans all truck idling over 3 minutes statewide","Florida limits idling to 5 minutes statewide at all times","Florida requires engines off whenever a truck is parked anywhere in the state","Florida has no statewide heavy-duty vehicle idling-reduction limit; its prior idling rule was repealed"],"answer":3,"explanation":"Florida's heavy-duty vehicle idling-reduction rule (Fla. Admin. Code 62-285.420) was repealed, so there is no statewide idling time limit; drivers should still check for local ordinances. This differs from states with statewide anti-idling laws.","handbook":"","hbref":""},{"q":"Which agency issues commercial driver licenses (CDLs) in Florida?","options":["The Florida Department of Transportation (FDOT)","The Florida Department of Highway Safety and Motor Vehicles (FLHSMV)","The Federal Motor Carrier Safety Administration (FMCSA)","The U.S. Department of Motor Vehicles"],"answer":1,"explanation":"In Florida, CDLs are issued and administered by the Florida Department of Highway Safety and Motor Vehicles (FLHSMV). The FMCSA sets the federal standards, but the state agency issues the actual credential. Source: FLHSMV, Commercial Driver License page.","handbook":"","hbref":""},{"q":"When applying for an original Florida CDL or commercial learner permit, which set of documents must the applicant present to FLHSMV?","options":["Only a current Florida Class E driver license and a photo","A passport and a single utility bill, with no Social Security documentation","Only a DOT medical examiner's certificate and a fingerprint card","Proof of identity, proof of Social Security number, and two proofs of Florida residential address"],"answer":3,"explanation":"Under the federal REAL ID Act as implemented by FLHSMV, original CDL/CLP applicants must present original documents proving identity, their Social Security number, and two proofs of Florida residential address. Source: FLHSMV, What to Bring / Commercial Driver License pages.","handbook":"","hbref":""},{"q":"Florida CDL and CLP credentials are REAL ID compliant. What does the REAL ID Act require of applicants?","options":["Submitting a notarized affidavit instead of any identity documents","Presenting original documents that verify identity, Social Security number, and residential address","Providing a federal passport card as the only acceptable proof of all requirements","Completing an online identity quiz in place of in-person document review"],"answer":1,"explanation":"REAL ID requires applicants to present original documents validating identity, Social Security number, and residential address at first in-office issuance. Once provided, they generally need to be shown again only if the information changes. Source: FLHSMV, REAL ID page.","handbook":"","hbref":""},{"q":"How many proofs of Florida residential address must a CDL or CLP applicant present to FLHSMV?","options":["No proof of residential address is required for a CDL","Four proofs of residential address, all utility bills","One proof, but it must be a passport","Two proofs of residential address in the applicant's name"],"answer":3,"explanation":"FLHSMV requires CLP and CDL applicants to present two proofs of Florida residential address in their name (two from List A, or one from List A and one from List B). Source: FLHSMV, What to Bring page.","handbook":"","hbref":""},{"q":"Federal Motor Carrier Safety Regulations require every driver getting or renewing a CDL to self-certify with FLHSMV into how many categories of operation?","options":["Two categories","Four categories","Six categories","Three categories"],"answer":1,"explanation":"Drivers must self-certify into one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Source: FLHSMV, CDL Medical Certification page.","handbook":"","hbref":""},{"q":"Which of the following is one of the four CDL self-certification categories used by FLHSMV?","options":["Non-excepted interstate","Excepted federal hazmat","Restricted intrastate agricultural-only","Provisional interstate commerce"],"answer":0,"explanation":"The four valid self-certification categories are non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. 'Non-excepted interstate' is the category for drivers who must maintain a federal medical certificate. Source: FLHSMV, CDL Medical Certification page.","handbook":"","hbref":""},{"q":"A Florida CDL driver self-certifies as 'non-excepted interstate.' What ongoing medical obligation does this create?","options":["They are permanently exempt from any medical certification","They only need a medical exam once every fifteen years","They must obtain and keep a valid DOT medical examiner's certificate on file with FLHSMV","They must self-certify but never need a medical examiner's certificate"],"answer":2,"explanation":"Drivers certifying as non-excepted interstate (or non-excepted intrastate) must maintain a valid DOT medical examiner's certificate and keep it current on file with FLHSMV. Source: FLHSMV, CDL Medical Certification page.","handbook":"","hbref":""},{"q":"What is the DOT medical examiner's certificate (often called a 'Med Card') used for in the Florida CDL process?","options":["To prove the driver has completed entry-level driver training","To serve as the driver's proof of Florida residency","To replace the knowledge and skills tests for experienced drivers","To document that a driver meets the physical qualification standards to operate a commercial motor vehicle"],"answer":3,"explanation":"The DOT medical examiner's certificate documents that a certified medical examiner found the driver physically qualified to operate a commercial motor vehicle. It is separate from residency proof and from the knowledge/skills tests. Source: FLHSMV, CDL Medical Certification page.","handbook":"","hbref":""},{"q":"A Florida non-excepted interstate CDL holder needs to keep their self-certification and medical information current. What is an FLHSMV-provided way to manage this?","options":["Faxing the certificate to the FMCSA national office only","The online MyDMV Portal CDL medical self-certification service","Posting the certificate to a social media account","There is no way to update it; it cannot be changed after issuance"],"answer":1,"explanation":"FLHSMV offers a CDL Medical Self-Certification service through the MyDMV Portal where drivers can submit their self-certification category and medical information. Medical examiners are also now required to transmit DOT exam results electronically. Source: FLHSMV, CDL Medical Self-Certification (MyDMV Portal).","handbook":"","hbref":""},{"q":"What happens if a non-excepted CDL driver fails to keep a current medical certification on file with FLHSMV?","options":["The CDL privilege can be downgraded or disqualified until valid medical certification is restored","Nothing happens; the medical certificate is purely optional","The driver automatically receives a hazmat endorsement","The driver's CLP holding period is waived"],"answer":0,"explanation":"If a non-excepted driver's medical certification lapses, FLHSMV can downgrade the CDL to a non-commercial license or disqualify the commercial privilege until current medical documentation is provided. Source: FLHSMV, CDL Medical Certification page.","handbook":"","hbref":""},{"q":"Before testing for a first-time Class A or Class B CDL, what federal training requirement must a Florida applicant satisfy?","options":["Complete a four-year apprenticeship registered with the state","Pass a separate FBI background investigation","Complete Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry","Hold an unrestricted Class E license for ten years"],"answer":2,"explanation":"For commercial learner permits obtained on or after February 7, 2022, first-time Class A/B CDL applicants must complete ELDT from a provider listed on the FMCSA Training Provider Registry before taking the CDL skills test. Source: FMCSA Entry-Level Driver Training; FLHSMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"Which of these endorsement applications also triggers the ELDT (Entry-Level Driver Training) requirement before testing?","options":["First-time hazardous materials (H), passenger (P), or school bus (S) endorsement","Renewing an existing combination vehicle privilege","Adding a motorcycle endorsement to a Class E license","Replacing a lost CDL with the same endorsements"],"answer":0,"explanation":"ELDT is required for first-time applicants seeking a hazardous materials (H), passenger (P), or school bus (S) endorsement, in addition to first-time Class A/B CDL applicants and Class B-to-Class A upgrades. Source: FMCSA Entry-Level Driver Training; FLHSMV.","handbook":"","hbref":""},{"q":"After an applicant completes ELDT, how does FLHSMV learn that the training was finished?","options":["The applicant mails a paper diploma directly to the Governor's office","FLHSMV physically inspects the truck the driver trained in","The training provider submits the certification to the FMCSA Training Provider Registry, which the state checks before testing","No verification occurs; the applicant simply states it was completed"],"answer":2,"explanation":"The training provider electronically submits the driver's ELDT completion to the FMCSA Training Provider Registry, and the state verifies the record before allowing the skills (or, for H, the knowledge) test. Source: FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"What is the first credential a person typically obtains on the path to a Florida CDL, allowing them to practice driving a commercial vehicle?","options":["A full unrestricted CDL issued immediately","A hazardous materials endorsement card","A DOT medical examiner's certificate","A Commercial Learner Permit (CLP)"],"answer":3,"explanation":"Applicants first obtain a Commercial Learner Permit (CLP) by passing the required knowledge tests; the CLP lets them practice on public roads with a qualified CDL holder before taking the skills test. Source: FLHSMV, Commercial Driver License page.","handbook":"","hbref":""},{"q":"Under federal rules followed by Florida, what is the minimum time a driver must hold a CLP before taking the CDL skills test?","options":["At least 90 days","There is no minimum waiting period","At least 14 days","At least one full year"],"answer":2,"explanation":"Federal regulation requires a CLP holder to wait a minimum of 14 days after the CLP is issued before taking the CDL skills test. Source: FMCSA 49 CFR 383.25; FLHSMV CDL process.","handbook":"","hbref":""},{"q":"How long may a Commercial Learner Permit remain valid before a new application is required?","options":["Up to one year from the date of issuance, with renewal allowed within that year","Up to ten years, like a passport","Only 48 hours from issuance","It never expires once issued"],"answer":0,"explanation":"Federal rules allow a CLP to be valid for up to one year from initial issuance; a CLP issued for less than a year may be renewed so long as it is not valid more than one year total. Source: FMCSA 49 CFR 383.25; FLHSMV.","handbook":"","hbref":""},{"q":"The Florida CDL skills test is made up of which three parts?","options":["Written essay, oral interview, and a typing test","Pre-trip vehicle inspection, basic vehicle control, and on-road driving","Vision screening, hearing test, and reaction-time test","Tire change, oil change, and engine rebuild"],"answer":1,"explanation":"The CDL skills test consists of three parts: a pre-trip vehicle inspection, a basic vehicle control test, and an on-road driving test. Source: FLHSMV, Commercial Driver License page.","handbook":"","hbref":""},{"q":"In what language must the Florida CDL skills test be conducted?","options":["Any language the applicant chooses","Spanish only","English","It is not conducted in any spoken language"],"answer":2,"explanation":"FLHSMV requires the CDL skills test to be conducted in English, consistent with federal requirements that commercial drivers be able to understand traffic signs and communicate in English. Source: FLHSMV, Commercial Driver License page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Florida CDL, and what restriction applies to drivers under 21?","options":["At least 18 years old, but drivers under 21 are generally restricted to intrastate operation","At least 16 years old, with no operational restrictions","At least 25 years old for any CDL class","At least 21 years old, with no exceptions allowed"],"answer":0,"explanation":"Florida CDL applicants must be at least 18 years old; those under 21 are generally limited to intrastate (within-Florida) commerce until they turn 21. Source: FLHSMV, Commercial Driver License page.","handbook":"","hbref":""},{"q":"How often must a Florida CDL holder renew their commercial driver license?","options":["Every six months","Every twenty years","Only once, because a CDL never expires","Every eight years"],"answer":3,"explanation":"Florida driver licenses, including CDLs, must be renewed every eight years; CDLs must be renewed and cannot be extended. Exact fees can change, so check FLHSMV for current amounts. Source: FLHSMV, Renew or Replace Your Florida Driver License page.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина, разрешённая на автодорогах Флориды для транспортного средства или его груза (исключая обязательные устройства безопасности) без разрешения на негабаритный груз?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","114 дюймов (9 футов 6 дюймов)"],"explanation":"Статут Флориды §316.515 устанавливает максимальную общую внешнюю ширину любого транспортного средства или его груза в 102 дюйма (8 футов 6 дюймов), за исключением устройств безопасности. Превышение этого предела требует разрешения FDOT на негабаритный груз."},"1":{"q":"Какова максимальная высота, включая груз, для транспортного средства на автодорогах Флориды без разрешения?","options":["13 футов","14 футов","14 футов 6 дюймов","13 футов 6 дюймов"],"explanation":"Согласно статуту Флориды §316.515, ни одно транспортное средство не может превышать высоту 13 футов 6 дюймов, включая груз. (Автовозам разрешено до 14 футов.) Закон Флориды возлагает ответственность за проезд под надземными сооружениями на водителя."},"2":{"q":"Какова во Флориде максимальная длина полуприцепа, эксплуатируемого в составе автопоезда «тягач-полуприцеп» в системе автодорог штата (до применения специальных допусков по длине)?","options":["48 футов","45 футов","53 фута","57 футов"],"explanation":"Статут Флориды §316.515 ограничивает полуприцеп в составе автопоезда «тягач-полуприцеп» предельным габаритом в 48 футов; полуприцепы свыше 48, но не более 57 футов, могут эксплуатироваться только на дорогах, не имеющих ограничений со стороны FDOT или местных властей."},"3":{"q":"Какова максимальная длина одиночного грузовика-фургона в предельном габарите согласно закону Флориды?","options":["35 футов","45 футов","40 футов","48 футов"],"explanation":"Статут Флориды §316.515 ограничивает грузовик-фургон (одиночное транспортное средство) длиной в 40 футов в предельном габарите."},"4":{"q":"Какова во Флориде в составе автопоезда «тягач-полуприцеп-прицеп» (сдвоенный/двойной прицеп) максимальная длина каждого отдельного прицепа?","options":["24 фута","28 футов","33 фута","40 футов"],"explanation":"Статут Флориды §316.515 предусматривает, что ни один полуприцеп или прицеп, эксплуатируемый в составе автопоезда «тягач-полуприцеп-прицеп», не может превышать длину в 28 футов, что соответствует федеральному стандарту для сдвоенных прицепов."},"5":{"q":"Какова максимальная полная нагрузка, создаваемая на автодорогу Флориды колёсами любой одиночной оси транспортного средства?","options":["18 000 фунтов","22 400 фунтов","24 000 фунтов","20 000 фунтов"],"explanation":"Статут Флориды §316.535 ограничивает полную нагрузку, создаваемую колёсами любой одиночной оси, до 20 000 фунтов."},"6":{"q":"Какова максимальная общая полная масса, включая все допуски правоприменения, для любого транспортного средства или состава транспортных средств на автодорогах Флориды?","options":["73 280 фунтов","76 000 фунтов","80 000 фунтов","88 000 фунтов"],"explanation":"Статут Флориды §316.535 ограничивает общую полную массу любого транспортного средства или состава транспортных средств до 80 000 фунтов, включая все допуски правоприменения. Это соответствует федеральному пределу для системы межштатных автодорог."},"7":{"q":"На автодорогах Флориды и межштатных автодорогах максимальная масса, допустимая для группы сдвоенных осей (две последовательные оси, расположенные на расстоянии более 40 дюймов, но не более 96 дюймов друг от друга), как правило, составляет:","options":["34 000 фунтов","30 000 фунтов","40 000 фунтов","44 000 фунтов"],"explanation":"Согласно федеральному стандарту массы, применяемому во Флориде, группа сдвоенных осей ограничена 34 000 фунтов. Флорида применяет Федеральную мостовую формулу и предел полной массы в 80 000 фунтов согласно статуту §316.535 в системе межштатных автодорог."},"8":{"q":"Флорида использует Федеральную мостовую формулу для ограничения массы в зависимости от расстояния между осями. В формуле W = 500[LN/(N-1) + 12N + 36] что обозначает буква «L»?","options":["Допустимую массу груза в фунтах","Расстояние в футах между крайними осями группы осей","Длину прицепа в дюймах","Зарегистрированную полную массу транспортного средства"],"explanation":"В Федеральной мостовой формуле, принятой в статуте Флориды §316.535, L — это расстояние в футах между крайними осями любой группы из двух или более последовательных осей, N — количество осей в группе, а W — допустимая полная масса."},"9":{"q":"Федеральная мостовая формула, применяемая во Флориде, предназначена в первую очередь для защиты чего?","options":["Шин транспортного средства от перегрузки","Водителя от усталости","Груза от смещения","Мостов и дорожного покрытия от концентрированной нагрузки"],"explanation":"Федеральная мостовая формула в статуте Флориды §316.535 распределяет массу на большее расстояние (больше осей, большее расстояние между ними) для защиты мостов и покрытия; близко расположенные оси концентрируют нагрузку и должны весить меньше."},"10":{"q":"Какое ведомство Флориды выдаёт разрешения на негабаритные и сверхтяжёлые грузы, превышающие законные пределы по размеру или массе?","options":["Департамент безопасности дорожного движения и транспортных средств Флориды (DHSMV)","Дорожный патруль Флориды (FHP)","Департамент транспорта Флориды (FDOT)","Федеральная администрация безопасности автоперевозчиков США (FMCSA)"],"explanation":"Департамент транспорта Флориды (FDOT) выдаёт разрешения на негабаритные/сверхтяжёлые грузы через своё Управление разрешений и онлайн-систему подачи заявок на разрешения для грузов, превышающих пределы, установленные статутами Флориды §316.515 и §316.535."},"11":{"q":"Груз имеет ширину 110 дюймов. Прежде чем перевозить его по автодороге Флориды, водитель должен:","options":["Получить разрешение FDOT на негабаритный груз","Ничего не делать; 110 дюймов — это законно","Только снизить скорость на 10 миль/ч","Получить одобрение только от местной полиции"],"explanation":"Поскольку 110 дюймов превышают законный предел ширины в 102 дюйма (8 футов 6 дюймов) согласно статуту Флориды §316.515, перевозка требует разрешения FDOT на негабаритный груз. Грузы не могут превышать законную ширину без разрешения."},"12":{"q":"Какой тип разрешения FDOT санкционирует одну перевозку негабаритного/сверхтяжёлого груза из одного пункта отправления в один пункт назначения?","options":["Годовое генеральное разрешение","Разовое (на одну поездку) разрешение","Генеральное разрешение для конкретного маршрута","Генеральное разрешение для конкретного транспортного средства"],"explanation":"FDOT выдаёт разовое (на одну поездку) разрешение для одной перевозки; генеральные разрешения (годовые, для конкретного маршрута или для конкретного транспортного средства) охватывают повторные перевозки в течение более длительного периода. Разовые разрешения обычно действительны в течение ограниченного количества дней для завершения перевозки."},"13":{"q":"Согласно правилам выдачи разрешений Флориды/FDOT, при какой ширине негабаритный груз обычно начинает требовать как минимум одного сопровождающего (пилотного) транспортного средства?","options":["Свыше 8 футов 6 дюймов","Свыше 10 футов","Свыше 12 футов","Свыше 16 футов"],"explanation":"Согласно правилам FDOT для негабаритных грузов, грузы шириной более 12 футов обычно требуют как минимум одного сопровождающего транспортного средства; грузы более 14 футов обычно требуют двух сопровождающих, а самые широкие грузы могут требовать сопровождения правоохранительных органов."},"14":{"q":"Негабаритный груз, перевозимый по разрешению FDOT во Флориде, как правило, должен иметь:","options":["Только включённые фары в дневное время","Только зелёную табличку разрешения","Никаких специальных обозначений, если ширина менее 12 футов","Знаки «OVERSIZE LOAD» и предупреждающие флажки на углах/крайних точках"],"explanation":"Условия разрешения FDOT требуют, чтобы негабаритные грузы имели предупреждающие знаки «OVERSIZE LOAD» и цветные (красные/оранжевые) флажки на углах и в самых широких точках груза, чтобы другие участники движения могли видеть негабаритный груз."},"15":{"q":"Согласно федеральным правилам крепления груза, применяемым во Флориде, совокупный рабочий предел нагрузки (WLL) креплений должен составлять не менее какой доли от массы закрепляемого груза?","options":["Половины (50%)","Четверти (25%)","Двух третей (67%)","Полной массы (100%)"],"explanation":"Федеральные правила крепления груза (49 CFR 393.106), которые Флорида применяет, требуют, чтобы совокупный рабочий предел нагрузки всех креплений составлял не менее половины (50%) от массы закрепляемого предмета или груза."},"16":{"q":"Согласно правилам крепления груза, применяемым во Флориде, предмет груза длиной 5 футов или менее и массой 1 100 фунтов или менее требует как минимум сколько креплений?","options":["Два крепления","Одно крепление","Три крепления","Никаких креплений при блокировке"],"explanation":"Согласно 49 CFR 393.110 (применяется во Флориде), предмет длиной 5 футов или менее и массой 1 100 фунтов или менее требует минимум одного крепления; более длинные или тяжёлые предметы требуют двух или более."},"17":{"q":"После погрузки и начала поездки, когда водитель CDL во Флориде должен впервые осмотреть груз и крепёжные устройства?","options":["В пределах первых 25 миль","В пределах первых 100 миль","В пределах первых 50 миль","Только в пункте назначения"],"explanation":"Федеральные правила, применяемые во Флориде (49 CFR 392.9), требуют, чтобы водитель осмотрел груз и крепёжные устройства в пределах первых 50 миль после начала поездки и периодически проверял их в дальнейшем."},"18":{"q":"Закон Флориды предусматривает определённые положения о сниженных штрафах или допусках по пределам массы в первую очередь для перевозчиков какого типа груза?","options":["Генеральных грузов в сухих фургонах","Опасных материалов","Предметов домашнего обихода","Натуральной, необработанной сельскохозяйственной продукции"],"explanation":"Транспортные и весовые статуты Флориды (глава 316) предусматривают специальные положения о допусках/штрафах для перевозки натуральной, необработанной сельскохозяйственной продукции, учитывая сезонный, связанный с фермерством характер этих грузов."},"19":{"q":"Водитель, перевозящий неделимый груз шириной 14 футов и массой 120 000 фунтов во Флориде, должен сделать что перед перевозкой?","options":["Получить разрешение FDOT на негабаритный И сверхтяжёлый груз","Ничего; неделимые грузы освобождены","Перевозить только ночью","Уменьшить груз до законных пределов, даже если его нельзя разделить"],"explanation":"Неделимый груз, превышающий как предел ширины в 102 дюйма (§316.515), так и предел полной массы в 80 000 фунтов (§316.535), требует разрешения FDOT на негабаритный/сверхтяжёлый груз, которое также устанавливает условия по маршруту, сопровождению и времени перевозки."},"20":{"q":"Какой класс CDL требуется во Флориде для управления составом транспортных средств с полной массой состава 26 001 фунтов или более, где буксируемый блок превышает 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Класс A CDL Флориды требуется для управления составами «грузовик/прицеп» с номинальной массой 26 001 фунтов или более, буксирующими блок свыше 10 000 фунтов (например, тягачи с прицепами). Источник: страница коммерческих водительских прав FLHSMV; Руководство CDL Флориды."},"21":{"q":"Водитель Флориды хочет управлять одиночным грузовиком-фургоном или автобусом с номинальной массой 26 001 фунтов или более, не буксирующим прицеп свыше 10 000 фунтов. Какой класс CDL подходит?","options":["Класс A","Класс B","Класс C","Класс E"],"explanation":"Класс B CDL Флориды охватывает одиночные (фургонные) грузовики и автобусы с номинальной массой 26 001 фунтов или более, которые не буксируют блок свыше 10 000 фунтов. Источник: страница коммерческих водительских прав FLHSMV."},"22":{"q":"Какой класс CDL Флориды требуется для меньшего транспортного средства (не соответствующего весовым требованиям класса A или B), предназначенного для перевозки 16 или более человек или перевозящего опасные материалы, требующие табличек?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"Класс C CDL Флориды применяется к транспортным средствам, не соответствующим весовым стандартам класса A или B, но предназначенным для перевозки 16+ человек или перевозящим опасные материалы, требующие табличек. Источник: страница коммерческих водительских прав FLHSMV."},"23":{"q":"Каков минимальный возраст для получения CDL Флориды с ограничением только на внутриштатные (в пределах Флориды) перевозки?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Флорида разрешает получение CDL в 18 лет, но водители младше 21 года ограничены внутриштатными (в пределах штата) перевозками. Источник: страница коммерческих водительских прав FLHSMV; Статуты Флориды, глава 322."},"24":{"q":"19-летний обладатель CDL Флориды хочет ездить через границы штатов (межштатные перевозки) или перевозить опасные материалы. Почему он не может?","options":["Межштатные перевозки и перевозка опасных материалов требуют минимального возраста 21 год","Межштатные перевозки требуют минимального возраста 23 года","Сначала они должны иметь внутриштатный CDL в течение пяти лет","Водители младше 25 лет никогда не могут перевозить никакие грузы"],"explanation":"Обладатели CDL Флориды младше 21 года ограничены внутриштатными перевозками; межштатные перевозки и перевозка опасных материалов требуют, чтобы водителю было не менее 21 года. Источник: FLHSMV; федеральный 49 CFR 391.11."},"25":{"q":"Какое подтверждение (эндорсмент) нужно обладателю CDL Флориды для перевозки опасных материалов в количествах, требующих табличек?","options":["Подтверждение N","Подтверждение T","Подтверждение P","Подтверждение H"],"explanation":"Подтверждение H (HazMat) санкционирует перевозку опасных материалов, требующих табличек, и требует сдачи теста на знание перевозки опасных материалов. Источник: страница коммерческих водительских прав FLHSMV."},"26":{"q":"Какое подтверждение требуется для управления цистерной во Флориде?","options":["N (Цистерны)","T (Сдвоенные/строенные прицепы)","H (HazMat)","S (Школьный автобус)"],"explanation":"Подтверждение N выдаётся водителям, которые сдали необходимый тест на знание управления цистернами и будут управлять цистернами. Источник: страница коммерческих водительских прав FLHSMV."},"27":{"q":"Водитель Флориды планирует буксировать сдвоенные или строенные составы тягач-прицеп. Какое подтверждение требуется?","options":["P (Пассажиры)","T (Сдвоенные/строенные прицепы)","N (Цистерны)","H (HazMat)"],"explanation":"Подтверждение T, получаемое путём сдачи необходимого теста на знание, позволяет управлять сдвоенными и строенными составами прицепов. Источник: страница коммерческих водительских прав FLHSMV."},"28":{"q":"Какое подтверждение требует Флорида для управления транспортным средством, предназначенным для перевозки 16 или более человек (более 15 пассажиров, включая водителя)?","options":["S (Школьный автобус)","P (Пассажиры)","N (Цистерны)","T (Сдвоенные/строенные прицепы)"],"explanation":"Подтверждение P (Пассажиры) требует сдачи как теста на знание, так и теста на навыки, и необходимо для пассажирских транспортных средств, предназначенных для более чем 15 человек, включая водителя. Источник: страница коммерческих водительских прав FLHSMV."},"29":{"q":"Чтобы получить подтверждение на школьный автобус (S) во Флориде, какое дополнительное подтверждение должен также иметь водитель?","options":["Подтверждение H (HazMat)","Подтверждение N (Цистерны)","Подтверждение P (Пассажиры)","Подтверждение T (Сдвоенные/строенные)"],"explanation":"Флорида требует подтверждение P (Пассажиры) в дополнение к подтверждению S (Школьный автобус); подтверждение S требует сдачи собственных тестов на знание и навыки. Источник: страница коммерческих водительских прав FLHSMV."},"30":{"q":"Какое подтверждение CDL Флориды требует федеральной оценки угрозы безопасности TSA, включая снятие отпечатков пальцев и национальную проверку биографии, перед выдачей?","options":["P (Пассажиры)","T (Сдвоенные/строенные прицепы)","N (Цистерны)","H (HazMat)"],"explanation":"Согласно Закону США «ПАТРИОТ», подтверждение H (HazMat) требует, чтобы заявители прошли снятие отпечатков пальцев и проверку биографии TSA перед выдачей; применяется дополнительный сбор. Источник: страница коммерческих водительских прав FLHSMV; TSA."},"31":{"q":"Как долго водитель должен иметь коммерческое ученическое разрешение Флориды (CLP), прежде чем ему будет разрешено сдавать тест на навыки (вождение) CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Федеральные правила, принятые Флоридой, требуют наличия CLP в течение минимум 14 дней перед сдачей теста на навыки CDL. Источник: FLHSMV; 49 CFR 383.25."},"32":{"q":"Во время практики с CLP Флориды кто должен сопровождать обладателя разрешения в коммерческом транспортном средстве?","options":["Любой лицензированный водитель в возрасте 21 года или старше","Обладатель действительного CDL с надлежащим классом и подтверждениями, сидящий рядом с водителем или поблизости","Только сертифицированный инструктор CDL, на закрытой площадке","Никакого надзора не требуется после сдачи теста на знание"],"explanation":"Обладатель CLP должен сопровождаться обладателем действительного CDL с соответствующей группой и подтверждениями, физически присутствующим рядом (или, для автобусов, непосредственно за водителем) под прямым надзором. Источник: FLHSMV; 49 CFR 383.25."},"33":{"q":"Какое ограничение по пассажирам применяется к обладателю CLP Флориды, управляющему коммерческим транспортным средством?","options":["Они могут перевозить до 8 пассажиров в учебных целях","Они могут перевозить пассажиров только в светлое время суток","Они не могут перевозить пассажиров, кроме сопровождающего обладателя CDL","Они могут перевозить пассажиров, если все пристёгнуты ремнями безопасности"],"explanation":"Обладатель CLP не может управлять автобусом или транспортным средством, занятым пассажирами, кроме сопровождающего обладателя действительного CDL/наставника. Источник: FLHSMV; 49 CFR 383.25."},"34":{"q":"Если заявитель на CDL Флориды не сдаёт тест на знание пневматических тормозов, что происходит с его правами?","options":["Добавляется ограничение «L», запрещающее транспортные средства с пневматическими тормозами","Добавляется ограничение «K», ограничивающее их внутриштатными перевозками","CDL автоматически понижается до класса C","CDL не может быть выдан, пока не сдан тест по пневматическим тормозам"],"explanation":"Несдача или пропуск теста по пневматическим тормозам приводит к ограничению «L», запрещающему водителю управлять коммерческими транспортными средствами, оснащёнными пневматическими тормозами. Источник: FLHSMV; Руководство CDL Флориды."},"35":{"q":"Согласно федеральным правилам обучения водителей начального уровня (ELDT), принятым во Флориде, какие заявители должны пройти ELDT перед тестированием?","options":["Только водители, уже имеющие CDL другого штата","Впервые подающие на CDL, переходящие с класса B на A, и впервые получающие подтверждения H, P или S","Только водители, получающие подтверждение N или T","Только водители старше 21 года"],"explanation":"ELDT требуется для впервые подающих на CDL, перехода с класса B на класс A и впервые получающих подтверждения HazMat, Пассажиры или Школьный автобус (для CLP, полученных 7 февраля 2022 года или позже). Источник: правило ELDT FMCSA; FLHSMV."},"36":{"q":"Где должен быть указан поставщик обучения ELDT Флориды, чтобы обучение водителя засчитывалось для получения права на CDL?","options":["В Реестре поставщиков обучения FMCSA","Только в списке утверждённых школ FLHSMV","В реестре поставщиков TSA","В любом реестре общественного колледжа штата"],"explanation":"Теоретическое и практическое (за рулём) обучение ELDT должно проводиться поставщиком, указанным в Реестре поставщиков обучения FMCSA (TPR), который подаёт сведения о завершении в электронном виде. Источник: Реестр поставщиков обучения FMCSA; FLHSMV."},"37":{"q":"Конкретно для подтверждения HazMat (H), какой этап ELDT должен пройти заявитель во Флориде?","options":["Практическое обучение на площадке перед дорожным тестом","Теоретическую часть ELDT (знание) перед сдачей теста на знание перевозки опасных материалов","Полный тест на навыки на цистерне","ELDT никогда не требуется для HazMat"],"explanation":"Заявители на HazMat должны пройти теоретическую часть ELDT через зарегистрированного поставщика перед сдачей экзамена на знание перевозки опасных материалов. Источник: правило ELDT FMCSA; FLHSMV."},"38":{"q":"Водитель CDL Флориды, который осуществляет перевозки через границы штатов и обязан иметь федеральный медицинский сертификат, проходит самосертификацию по какой категории?","options":["Исключённый межштатный (EI)","Исключённый внутриштатный (EA)","Неисключённый внутриштатный (NA)","Неисключённый межштатный (NI)"],"explanation":"Неисключённый межштатный (NI) применяется к водителям в межштатной коммерции, которые должны иметь действительный сертификат медицинского эксперта от эксперта Национального реестра FMCSA. Источник: самосертификация FLHSMV; FMCSA 49 CFR 383.71."},"39":{"q":"Какой документ Флорида принимает как основное подтверждение личности для заявки на CDL, соответствующий REAL ID?","options":["Заверенное свидетельство о рождении США или действительный паспорт США","Текущий счёт за коммунальные услуги на имя заявителя","Карта регистрации избирателя Флориды","Удостоверение личности с фотографией, выданное работодателем"],"explanation":"Для CDL, соответствующего REAL ID, Флорида требует основной документ, удостоверяющий личность, такой как заверенное свидетельство о рождении США или действительный паспорт/паспортную карту США, плюс подтверждение номера социального страхования и два подтверждения адреса проживания. Источник: FLHSMV «Что взять с собой»/REAL ID."},"40":{"q":"Какова во Флориде максимальная концентрация алкоголя в крови (BAC), при которой обладатель CDL может законно управлять коммерческим транспортным средством (CMV)?","options":["0,08 процента","0,02 процента","0,10 процента","0,04 процента"],"explanation":"Управлять CMV во Флориде незаконно, если ваш BAC составляет 0,04 процента или более, что вдвое меньше предела 0,08, применяемого к некоммерческим водителям. Источник: Руководство CDL Флориды (FLHSMV), Дисквалификации водителей; 49 CFR 383.51."},"41":{"q":"Согласно закону Флориды о подразумеваемом согласии, что происходит в тот момент, когда человек управляет коммерческим транспортным средством в штате?","options":["Они должны постоянно иметь при себе отдельное разрешение на тест дыхания","Считается, что они дали согласие на тестирование на алкоголь","Они полностью отказываются от права на слушание по CDL","Они освобождаются от тестирования, если не произошло ДТП"],"explanation":"Управляя CMV во Флориде, водитель считается давшим согласие на тестирование на алкоголь. Отказ от теста влечёт ту же дисквалификацию, что и осуждение за вождение в нетрезвом виде. Источник: Руководство CDL Флориды (FLHSMV); Статуты Флориды, глава 322 (подразумеваемое согласие)."},"42":{"q":"Обладатель CDL осуждён за первое серьёзное правонарушение, такое как вождение в нетрезвом виде (DUI), НЕ перевозя опасные материалы. Каков минимальный срок дисквалификации CDL во Флориде?","options":["60 дней","3 года","1 год","Пожизненно"],"explanation":"Первое серьёзное правонарушение (DUI, BAC 0,04 или выше в CMV, отказ от теста, оставление места ДТП или использование транспортного средства для совершения тяжкого преступления) приводит к дисквалификации CDL как минимум на 1 год. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"43":{"q":"Если первое серьёзное правонарушение происходит, когда водитель CDL управляет CMV с табличками опасных материалов, каков минимальный срок дисквалификации во Флориде?","options":["3 года","1 год","120 дней","Пожизненно"],"explanation":"Первое серьёзное правонарушение, совершённое при управлении CMV с табличками опасных материалов, повышает минимальную дисквалификацию с 1 года до как минимум 3 лет. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"44":{"q":"Каковы последствия во Флориде для обладателя CDL, осуждённого за ВТОРОЕ серьёзное правонарушение в любой момент его водительской карьеры?","options":["Дисквалификация на 3 года","Лишение CDL пожизненно","Дисквалификация на 1 год","Дисквалификация на 120 дней"],"explanation":"Второе серьёзное правонарушение приводит к пожизненной дисквалификации CDL. Флорида может допускать рассмотрение восстановления после минимального периода при ограниченных обстоятельствах, но правилом является пожизненный запрет. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"45":{"q":"Водителя CDL во Флориде законно просят пройти тест на содержание алкоголя в крови, и он отказывается. Как это расценивается для целей дисквалификации CDL?","options":["Это только серьёзное нарушение, дисквалифицирующее на 60 дней","Это серьёзное правонарушение, дисквалифицирующее как минимум на 1 год","Это не влечёт штрафа по CDL, если водитель был не при исполнении","Это приводит только к 24-часовому предписанию о выводе из эксплуатации"],"explanation":"Отказ от прохождения тестирования на алкоголь расценивается как серьёзное правонарушение, влекущее ту же минимальную дисквалификацию на 1 год (3 года при наличии табличек HazMat), что и осуждение за DUI. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"46":{"q":"Какое из следующих классифицируется как «серьёзное нарушение правил дорожного движения» для обладателя CDL Флориды?","options":["Вождение с BAC 0,04 процента в CMV","Отказ от законного теста на алкоголь","Управление CMV под предписанием о выводе из эксплуатации","Превышение скорости на 15 миль/ч или более сверх установленного предела"],"explanation":"Значительное превышение скорости (на 15 миль/ч или более сверх предела) является серьёзным нарушением правил дорожного движения. Остальные варианты — серьёзные правонарушения или нарушения предписания о выводе из эксплуатации, влекущие иные, более строгие наказания. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"47":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода повлекут дисквалификацию CDL во Флориде, и на какой срок за второе?","options":["2 нарушения приводят к дисквалификации как минимум на 120 дней","3 нарушения приводят к дисквалификации как минимум на 60 дней","2 нарушения приводят к дисквалификации как минимум на 60 дней","2 нарушения приводят к дисквалификации как минимум на 1 год"],"explanation":"Второе серьёзное нарушение правил дорожного движения в течение 3-летнего периода приводит к дисквалификации как минимум на 60 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"48":{"q":"Какова минимальная дисквалификация CDL во Флориде за ТРЕТЬЕ серьёзное нарушение правил дорожного движения, совершённое в течение 3-летнего периода?","options":["60 дней","1 год","120 дней","30 дней"],"explanation":"Третье серьёзное нарушение правил дорожного движения в течение 3-летнего периода приводит к дисквалификации как минимум на 120 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"49":{"q":"Какое из следующих является серьёзным нарушением правил дорожного движения, а не серьёзным правонарушением, для обладателя CDL Флориды?","options":["Неправильная или беспорядочная смена полос движения","Оставление места ДТП","Использование транспортного средства для совершения тяжкого преступления","Вождение под воздействием контролируемого вещества"],"explanation":"Неправильная или беспорядочная смена полос движения является серьёзным нарушением правил дорожного движения. Остальные три — серьёзные правонарушения, влекущие минимальную дисквалификацию на 1 год (или пожизненно). Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"50":{"q":"Согласно правилам CDL Флориды и федеральным правилам, как классифицируется отправка текстовых сообщений за рулём CMV для целей дисквалификации?","options":["Как серьёзное нарушение с дисквалификацией на 1 год","Как серьёзное нарушение правил дорожного движения","Как нарушение приказа о выводе из эксплуатации (out-of-service)","Как нарушение без статуса CDL, не влияющее на дисквалификацию"],"explanation":"Нарушение закона, запрещающего отправку текстовых сообщений за рулём CMV, является серьёзным нарушением правил дорожного движения. В сочетании с другими серьёзными нарушениями в течение 3 лет это может привести к дисквалификации на 60 или 120 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51 и 392.80."},"51":{"q":"Использование ручного мобильного телефона за рулём CMV запрещено для водителей CDL во Флориде. Для целей дисквалификации это нарушение рассматривается как:","options":["Серьёзное нарушение, требующее пожизненной дисквалификации","Нарушение на железнодорожном переезде","Серьёзное нарушение правил дорожного движения","Нарушение приказа о выводе из эксплуатации (out-of-service)"],"explanation":"Нарушение закона, запрещающего использование ручного мобильного телефона за рулём CMV, является серьёзным нарушением правил дорожного движения; повторные серьёзные нарушения в течение 3 лет приводят к дисквалификации на 60 или 120 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51 и 392.82."},"52":{"q":"Какова минимальная дисквалификация CDL за ПЕРВОЕ осуждение за нарушение на железнодорожном переезде во Флориде?","options":["120 дней","60 дней","1 год","30 дней"],"explanation":"Первое нарушение на железнодорожном переезде влечёт за собой дисквалификацию на срок не менее 60 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"53":{"q":"Обладатель CDL Флориды совершает ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["60 дней","1 год","180 дней","120 дней"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт за собой дисквалификацию на срок не менее 120 дней. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"54":{"q":"Какова минимальная дисквалификация CDL за ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода во Флориде?","options":["120 дней","60 дней","1 год","Пожизненно"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3-летнего периода влечёт за собой дисквалификацию на срок не менее 1 года. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"55":{"q":"Водитель CDL Флориды ВПЕРВЫЕ нарушает приказ о выводе из эксплуатации (out-of-service), не перевозя опасные материалы или пассажиров. Какова минимальная дисквалификация?","options":["180 дней","60 дней","90 дней","120 дней"],"explanation":"Первое нарушение приказа о выводе из эксплуатации влечёт за собой дисквалификацию на срок не менее 180 дней (дольше при перевозке HazMat или пассажиров). Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"56":{"q":"Какова минимальная дисквалификация CDL за ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service) в течение 10-летнего периода во Флориде?","options":["180 дней","1 год","3 года","2 года"],"explanation":"Второе нарушение приказа о выводе из эксплуатации в течение 10-летнего периода влечёт за собой дисквалификацию на срок не менее 2 лет. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"57":{"q":"Водитель CDL Флориды совершает ТРЕТЬЕ или последующее нарушение приказа о выводе из эксплуатации (out-of-service) в течение 10-летнего периода. Какова минимальная дисквалификация?","options":["3 года","2 года","1 год","180 дней"],"explanation":"Третье или последующее нарушение приказа о выводе из эксплуатации в течение 10-летнего периода влечёт за собой дисквалификацию на срок не менее 3 лет. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"58":{"q":"Если у водителя CDL во Флориде обнаружено ЛЮБОЕ заметное количество алкоголя во время несения службы (ниже 0,04 BAC), каково немедленное последствие?","options":["Вывод из эксплуатации на 24 часа","Постоянная утрата CDL","Дисквалификация на 60 дней","Обязательная дисквалификация на 1 год"],"explanation":"Водитель с любым заметным количеством алкоголя ниже 0,04 выводится из эксплуатации на 24 часа. BAC 0,04 или выше является серьёзным нарушением, дисквалифицирующим водителя не менее чем на 1 год. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 392.5 и 383.51."},"59":{"q":"Какое нарушение влечёт за собой ОБЯЗАТЕЛЬНУЮ пожизненную дисквалификацию CDL без возможности восстановления во Флориде?","options":["Первое осуждение за DUI в CMV","Два серьёзных нарушения правил дорожного движения в течение 3 лет","Первое нарушение на железнодорожном переезде","Использование CMV для производства, распространения или сбыта контролируемого вещества"],"explanation":"Использование CMV при совершении тяжкого преступления, связанного с производством, распространением или сбытом контролируемого вещества, влечёт за собой обязательную пожизненную дисквалификацию без восстановления. Источник: Руководство CDL Флориды (FLHSMV); 49 CFR 383.51."},"60":{"q":"Согласно закону Флориды Move Over Act, вы едете на тягаче с прицепом по многополосной автомагистрали и приближаетесь к остановившемуся патрульному автомобилю с мигающими аварийными огнями. Что закон требует сделать в первую очередь?","options":["Полностью остановиться в текущей полосе, пока аварийный автомобиль не уедет","Освободить полосу, ближайшую к аварийному автомобилю, как только это станет безопасно","Подать звуковой сигнал, чтобы предупредить офицера о вашем приближении","Сохранить скорость, но включить аварийную сигнализацию"],"explanation":"Закон Флориды Move Over Act (Fla. Stat. 316.126) требует от водителей на многополосной дороге освободить полосу, ближайшую к остановившемуся аварийному или служебному автомобилю, как только это станет безопасно; только если перестроиться невозможно, необходимо снизить скорость."},"61":{"q":"На двухполосной дороге Флориды с разрешённой скоростью 55 миль/ч вы приближаетесь к остановившемуся эвакуатору с жёлтыми огнями и не можете безопасно перестроиться. До какой скорости в милях в час вы должны снизить скорость?","options":["45 миль/ч","25 миль/ч","35 миль/ч","55 миль/ч; на двухполосной дороге снижение не требуется"],"explanation":"Согласно Fla. Stat. 316.126, если вы не можете перестроиться, вы должны снизить скорость на 20 миль/ч ниже разрешённого ограничения, когда разрешённая скорость составляет 25 миль/ч или выше. На дороге с ограничением 55 миль/ч это означает 35 миль/ч."},"62":{"q":"Закон Флориды Move Over Act требует снижения скорости, когда вы не можете перестроиться. На дороге, где разрешённая скорость составляет 20 миль/ч или менее, до какой скорости вы должны снизить скорость при проезде мимо подходящего под условия остановившегося автомобиля?","options":["5 миль/ч","10 миль/ч","0 миль/ч (полная остановка)","15 миль/ч"],"explanation":"Fla. Stat. 316.126 предусматривает, что, когда разрешённая скорость составляет 20 миль/ч или менее, водитель, который не может перестроиться, должен снизить скорость до 5 миль/ч при проезде мимо остановившегося автомобиля."},"63":{"q":"Помимо аварийных автомобилей, закон Флориды Move Over (Fla. Stat. 316.126) также защищает какие из следующих остановившихся автомобилей с надлежащими сигналами?","options":["Санитарные, коммунальные служебные автомобили, а также автомобили дорожного или мостового обслуживания и неисправные автомобили с аварийной сигнализацией","Только маркированные автомобили правоохранительных органов и пожарной службы","Только машины скорой помощи и эвакуаторы","Любой частный легковой автомобиль, припаркованный на обочине"],"explanation":"Fla. Stat. 316.126 распространяет защиту Move Over на санитарные автомобили, коммунальные служебные автомобили, эвакуаторы, автомобили дорожного и мостового обслуживания/строительства, а также на неисправные механические транспортные средства с включённой аварийной сигнализацией, в дополнение к аварийным автомобилям."},"64":{"q":"Вы управляете автобусом с пассажирами и приближаетесь к железнодорожному переезду во Флориде. На каком расстоянии от ближайшего рельса вы должны остановиться?","options":["Между 5 и 15 футами","Между 50 и 100 футами","Между 15 и 50 футами","Ровно 25 футов, не ближе и не дальше"],"explanation":"Автобусы с пассажирами и автомобили с табличками (placard) для опасных материалов должны останавливаться не ближе 15 футов и не дальше 50 футов от ближайшего рельса, затем смотреть и слушать перед переездом (Руководство CDL Флориды; FMCSR 392.10)."},"65":{"q":"Какое коммерческое транспортное средство обязано совершать обязательную остановку на каждом железнодорожном переезде во Флориде, если не применяется исключение?","options":["Пустой бортовой грузовик без груза","Транспортное средство, перевозящее опасные материалы в количествах, требующих табличек (placard)","Фургон доставки, перевозящий обычные грузы","Самосвал, перевозящий песок"],"explanation":"Согласно федеральным правилам, принятым в Руководстве CDL Флориды (FMCSR 392.10), транспортные средства, обязанные иметь таблички (placard) для опасных материалов, и автобусы с пассажирами должны останавливаться на железнодорожных переездах; обычные грузовые транспортные средства останавливаться не обязаны."},"66":{"q":"На каком железнодорожном переезде водитель с табличками опасных материалов (placarded hazmat) или водитель автобуса НЕ обязан останавливаться?","options":["На переезде, где работающий светофор показывает зелёный сигнал, или который обозначен официальным знаком Exempt","На любом переезде на сельской двухполосной дороге","На переезде с крестообразными знаками (crossbucks), но без мигающих огней","На переезде сразу после захода солнца"],"explanation":"Руководство CDL Флориды (FMCSR 392.10) перечисляет исключения из обязательной остановки: зелёный сигнал светофора, переезд, обозначенный официальным знаком Exempt, переезд под управлением полицейского или регулировщика, а также пути, используемые только для трамваев или промышленного маневрирования."},"67":{"q":"При пересечении железнодорожных путей на коммерческом транспортном средстве с механической коробкой передач что вы должны делать?","options":["Переключиться на повышенную передачу на середине, чтобы быстрее покинуть пути","Остановиться на путях, чтобы проверить зеркала перед продолжением движения","Включить нейтраль и накатом пересечь пути","Пересекать на низкой передаче и не переключать передачи на путях"],"explanation":"Руководство CDL Флориды инструктирует водителей выбирать передачу, которая позволит транспортному средству полностью пересечь пути, и никогда не переключать передачи во время пересечения, чтобы избежать остановки на путях."},"68":{"q":"На двусторонней улице Флориды без разделительной полосы или барьера школьный автобус останавливается с мигающими красными огнями и выдвинутым знаком «стоп». Что должен сделать транспорт, приближающийся с противоположного направления?","options":["Снизить скорость до 10 миль/ч, но может продолжить движение мимо автобуса","Продолжать движение в обычном режиме, поскольку встречный транспорт никогда не обязан останавливаться","Остановиться и оставаться на месте, пока огни не перестанут мигать, а знак «стоп» не будет убран","Остановиться, только если дети явно переходят дорогу"],"explanation":"Fla. Stat. 316.172 требует, чтобы весь транспорт, включая встречный транспорт на неразделённой двусторонней проезжей части, останавливался перед остановившимся школьным автобусом с мигающими красными огнями и оставался на месте, пока огни не погаснут, а знак «стоп» не будет убран."},"69":{"q":"Согласно закону Флориды, водители, движущиеся в противоположном направлении, НЕ обязаны останавливаться перед остановившимся школьным автобусом, когда проезжая часть разделена чем из следующего?","options":["Одной сплошной жёлтой осевой линией","Размеченной полосой для двустороннего левого поворота","Приподнятой разделительной полосой, физическим барьером или немощёным пространством шириной не менее 5 футов","Рядом светоотражающих дорожных маркеров"],"explanation":"Fla. Stat. 316.172(2) освобождает встречный транспорт от остановки только тогда, когда разделённая автомагистраль разделяет потоки приподнятой разделительной полосой, физическим барьером или немощёным пространством шириной не менее 5 футов. Одни лишь линии разметки не подходят под условия."},"70":{"q":"Если вы должны остановить своё коммерческое механическое транспортное средство на обочине автомагистрали Флориды с односторонним движением или разделённой автомагистрали, где вы должны разместить три аварийных предупреждающих устройства?","options":["В 5 футах, 50 футах и 150 футах в сторону приближающегося транспорта","Все три в пределах 10 футов от задней части транспортного средства","В 25 футах, 75 футах и 125 футах впереди транспортного средства","В 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта"],"explanation":"Руководство CDL Флориды (FMCSR 392.22) требует размещения предупреждающих устройств в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта на автомагистрали с односторонним движением или разделённой автомагистрали."},"71":{"q":"После остановки вашего коммерческого транспортного средства на проезжей части или обочине автомагистрали Флориды, в течение скольких секунд вы должны включить аварийную сигнализацию (четыре мигающих указателя)?","options":["В течение 30 минут, только ночью","Только после того, как уже выставлены предупреждающие треугольники","Немедленно, а предупреждающие устройства выставить в течение 10 минут","Требований по времени для аварийной сигнализации нет"],"explanation":"Согласно FMCSR 392.22, принятому в Руководстве CDL Флориды, остановившееся CMV должно немедленно включить аварийную сигнализацию и выставить предупреждающие устройства (треугольники/сигнальные огни) в течение 10 минут."},"72":{"q":"На двухполосной дороге Флориды с движением в обоих направлениях, где следует размещать предупреждающие треугольники, когда ваше CMV остановлено?","options":["В пределах 10 футов от транспортного средства, а также в 100 футах позади и впереди него","Только в 200 футах позади транспортного средства","Только у переднего бампера транспортного средства","Только в 50 футах позади и 50 футах впереди"],"explanation":"Руководство CDL Флориды (FMCSR 392.22) предписывает на двухполосной или неразделённой дороге размещать одно предупреждающее устройство в пределах 10 футов от транспортного средства, одно в 100 футах позади и одно в 100 футах впереди остановившегося транспортного средства."},"73":{"q":"На дороге Флориды с тремя или более полосами в вашем направлении общее правило правой полосы требует от медленно движущихся транспортных средств, включая грузовики, делать что?","options":["Всегда двигаться в центральной полосе независимо от скорости","Использовать крайнюю левую полосу, чтобы держать правую полосу свободной","Свободно выбирать любую полосу без ограничений","Держаться правой полосы, кроме случаев обгона, проезда или подготовки к левому повороту"],"explanation":"Fla. Stat. 316.081 требует, чтобы любое транспортное средство, движущееся медленнее обычного потока, использовало правую полосу (или как можно ближе к правому краю), кроме случаев обгона/проезда или подготовки к левому повороту."},"74":{"q":"За пределами деловых или жилых районов, каково установленное законом максимальное ограничение скорости по умолчанию во Флориде там, где не установлено иное ограничение?","options":["55 миль/ч","70 миль/ч","65 миль/ч","45 миль/ч"],"explanation":"Fla. Stat. 316.183/316.187 устанавливают законный максимум 55 миль/ч в местах за пределами деловых или жилых районов, если не установлено иное ограничение; 30 миль/ч применяется в деловых или жилых районах."},"75":{"q":"На межштатной автомагистрали Флориды как минимум с четырьмя полосами и ограничением 70 миль/ч, каково установленное законом минимальное ограничение скорости?","options":["40 миль/ч","55 миль/ч","45 миль/ч","50 миль/ч"],"explanation":"Fla. Stat. 316.183 устанавливает минимальную скорость 50 миль/ч на разделённых межштатных автомагистралях как минимум с четырьмя полосами, где максимальное установленное ограничение составляет 70 миль/ч."},"76":{"q":"Согласно закону Флориды об отвлечённом вождении (Fla. Stat. 316.305), что запрещено во время управления движущимся механическим транспортным средством?","options":["Любое использование Bluetooth-громкоговорителя hands-free для телефонного звонка","Ручной набор или чтение данных для неголосовой связи, например текстовых сообщений, электронной почты или мгновенных сообщений","Прослушивание голосовых указаний навигации","Наличие закреплённого телефона на виду в кабине"],"explanation":"Fla. Stat. 316.305 запрещает ручной набор или ввод символов и отправку или чтение данных на беспроводном устройстве для неголосовой межличностной связи (текстовые сообщения, электронная почта, мгновенные сообщения) во время вождения."},"77":{"q":"Какое утверждение о применении закона Флориды о запрете текстовых сообщений за рулём (Fla. Stat. 316.305) является верным?","options":["Это вторичное правонарушение, требующее сначала другого нарушения","Это первичное правонарушение, поэтому офицер может остановить и оштрафовать водителя только за текстовые сообщения","Это применяется только к водителям младше 18 лет","Это применяется только в период с заката до рассвета"],"explanation":"С 2019 года Fla. Stat. 316.305 делает отправку текстовых сообщений за рулём первичным правонарушением, позволяя офицерам останавливать и штрафовать водителя только за это нарушение."},"78":{"q":"Когда Флорида активирует Emergency Shoulder Use (ESU) на эвакуационном маршруте во время урагана, каким транспортным средствам НЕ разрешено использовать открытую полосу обочины?","options":["Легковым автомобилям и пикапам","Большим грузовикам, автобусам и прицепам","Мотоциклам и внедорожникам","Все транспортные средства могут использовать обочину одинаково"],"explanation":"Согласно плану Emergency Shoulder Use FDOT Флориды (который заменил встречное движение, contraflow), все автомобилисты, КРОМЕ больших грузовиков, автобусов и прицепов, могут использовать мощёную обочину как временную полосу движения во время эвакуации при урагане."},"79":{"q":"Что касается длительной работы двигателя на холостом ходу у большегрузных коммерческих транспортных средств, какое утверждение отражает действующий закон Флориды?","options":["Флорида запрещает любую работу грузовиков на холостом ходу более 3 минут на всей территории штата","Флорида ограничивает работу на холостом ходу 5 минутами на всей территории штата в любое время","Флорида требует выключать двигатели всякий раз, когда грузовик припаркован где-либо в штате","Во Флориде нет общегосударственного ограничения по сокращению холостого хода большегрузных транспортных средств; прежнее правило о холостом ходе было отменено"],"explanation":"Правило Флориды о сокращении холостого хода большегрузных транспортных средств (Fla. Admin. Code 62-285.420) было отменено, поэтому общегосударственного ограничения по времени холостого хода нет; водителям всё же следует проверять местные постановления. Это отличается от штатов с общегосударственными законами против холостого хода."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) во Флориде?","options":["Департамент транспорта Флориды (FDOT)","Департамент безопасности дорожного движения и автотранспортных средств Флориды (FLHSMV)","Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент автотранспортных средств США"],"explanation":"Во Флориде CDL выдаются и администрируются Департаментом безопасности дорожного движения и автотранспортных средств Флориды (FLHSMV). FMCSA устанавливает федеральные стандарты, но фактический документ выдаёт ведомство штата. Источник: FLHSMV, страница Commercial Driver License."},"81":{"q":"При подаче заявления на первичный CDL Флориды или коммерческое ученическое разрешение какой набор документов должен предъявить заявитель в FLHSMV?","options":["Только действующее водительское удостоверение Флориды класса E и фотографию","Паспорт и один счёт за коммунальные услуги, без документации о номере социального страхования","Только медицинскую справку DOT и дактилоскопическую карту","Подтверждение личности, подтверждение номера социального страхования и два подтверждения жилого адреса во Флориде"],"explanation":"Согласно федеральному закону REAL ID Act, реализованному FLHSMV, заявители на первичный CDL/CLP должны предъявить оригиналы документов, подтверждающих личность, их номер социального страхования и два подтверждения жилого адреса во Флориде. Источник: FLHSMV, страницы What to Bring / Commercial Driver License."},"82":{"q":"Документы CDL и CLP Флориды соответствуют REAL ID. Что закон REAL ID Act требует от заявителей?","options":["Подачу нотариально заверенного аффидевита вместо любых документов, удостоверяющих личность","Предъявление оригиналов документов, подтверждающих личность, номер социального страхования и жилой адрес","Предоставление федеральной паспортной карты как единственного приемлемого подтверждения всех требований","Прохождение онлайн-теста на установление личности вместо личной проверки документов"],"explanation":"REAL ID требует, чтобы заявители предъявляли оригиналы документов, подтверждающих личность, номер социального страхования и жилой адрес при первой выдаче в офисе. После предоставления их обычно нужно показывать снова только при изменении информации. Источник: FLHSMV, страница REAL ID."},"83":{"q":"Сколько подтверждений жилого адреса во Флориде должен предъявить заявитель на CDL или CLP в FLHSMV?","options":["Подтверждение жилого адреса для CDL не требуется","Четыре подтверждения жилого адреса, все — счета за коммунальные услуги","Одно подтверждение, но это должен быть паспорт","Два подтверждения жилого адреса на имя заявителя"],"explanation":"FLHSMV требует, чтобы заявители на CLP и CDL предъявляли два подтверждения жилого адреса во Флориде на своё имя (два из списка A или одно из списка A и одно из списка B). Источник: FLHSMV, страница What to Bring."},"84":{"q":"Федеральные правила безопасности автоперевозчиков требуют, чтобы каждый водитель, получающий или продлевающий CDL, самостоятельно сертифицировался в FLHSMV в скольких категориях деятельности?","options":["Двух категориях","Четырёх категориях","Шести категориях","Трёх категориях"],"explanation":"Водители должны самостоятельно сертифицироваться в одну из четырёх категорий: межштатная без исключений (non-excepted interstate), межштатная с исключениями (excepted interstate), внутриштатная без исключений (non-excepted intrastate) и внутриштатная с исключениями (excepted intrastate). Источник: FLHSMV, страница CDL Medical Certification."},"85":{"q":"Какая из следующих является одной из четырёх категорий самосертификации CDL, используемых FLHSMV?","options":["Межштатная без исключений (non-excepted interstate)","Федеральная hazmat с исключениями","Ограниченная внутриштатная только для сельского хозяйства","Временная межштатная торговля"],"explanation":"Четыре действительные категории самосертификации — это межштатная без исключений (non-excepted interstate), межштатная с исключениями (excepted interstate), внутриштатная без исключений (non-excepted intrastate) и внутриштатная с исключениями (excepted intrastate). «Non-excepted interstate» — это категория для водителей, которые должны иметь федеральную медицинскую справку. Источник: FLHSMV, страница CDL Medical Certification."},"86":{"q":"Водитель CDL Флориды самостоятельно сертифицируется как «non-excepted interstate». Какое постоянное медицинское обязательство это создаёт?","options":["Он навсегда освобождён от любой медицинской сертификации","Ему нужно проходить медицинский осмотр только раз в пятнадцать лет","Он должен получить и хранить действующую медицинскую справку DOT в FLHSMV","Он должен самостоятельно сертифицироваться, но ему никогда не нужна медицинская справка"],"explanation":"Водители, сертифицирующиеся как non-excepted interstate (или non-excepted intrastate), должны иметь действующую медицинскую справку DOT и поддерживать её актуальной в FLHSMV. Источник: FLHSMV, страница CDL Medical Certification."},"87":{"q":"Для чего используется медицинская справка DOT (часто называемая «Med Card») в процессе получения CDL во Флориде?","options":["Для подтверждения того, что водитель прошёл начальное обучение водителей (ELDT)","Чтобы служить подтверждением проживания водителя во Флориде","Чтобы заменить тесты на знания и навыки для опытных водителей","Для подтверждения того, что водитель соответствует стандартам физической пригодности для управления коммерческим механическим транспортным средством"],"explanation":"Медицинская справка DOT подтверждает, что сертифицированный медицинский эксперт признал водителя физически пригодным для управления коммерческим механическим транспортным средством. Она отделена от подтверждения проживания и от тестов на знания/навыки. Источник: FLHSMV, страница CDL Medical Certification."},"88":{"q":"Обладателю CDL Флориды категории non-excepted interstate необходимо поддерживать актуальность своей самосертификации и медицинской информации. Какой способ управления этим предоставляет FLHSMV?","options":["Отправка справки факсом только в национальный офис FMCSA","Онлайн-сервис самосертификации медицинских данных CDL через портал MyDMV","Размещение справки в аккаунте социальной сети","Способа обновить это нет; после выдачи изменить нельзя"],"explanation":"FLHSMV предлагает сервис медицинской самосертификации CDL через портал MyDMV, где водители могут подать свою категорию самосертификации и медицинскую информацию. Медицинские эксперты также теперь обязаны передавать результаты осмотра DOT в электронном виде. Источник: FLHSMV, CDL Medical Self-Certification (портал MyDMV)."},"89":{"q":"Что происходит, если водитель CDL категории non-excepted не поддерживает актуальную медицинскую сертификацию в FLHSMV?","options":["Привилегия CDL может быть понижена или дисквалифицирована до восстановления действительной медицинской сертификации","Ничего не происходит; медицинская справка является чисто необязательной","Водитель автоматически получает разрешение hazmat","Срок удержания CLP водителя отменяется"],"explanation":"Если медицинская сертификация водителя категории non-excepted истекает, FLHSMV может понизить CDL до некоммерческого удостоверения или дисквалифицировать коммерческую привилегию до предоставления актуальной медицинской документации. Источник: FLHSMV, страница CDL Medical Certification."},"90":{"q":"Перед сдачей экзамена на первичный CDL класса A или класса B какое федеральное требование к обучению должен выполнить заявитель во Флориде?","options":["Пройти четырёхлетнее ученичество, зарегистрированное в штате","Пройти отдельную проверку биографических данных ФБР","Пройти начальное обучение водителей (ELDT) у провайдера, указанного в реестре провайдеров обучения FMCSA (Training Provider Registry)","Иметь неограниченное удостоверение класса E в течение десяти лет"],"explanation":"Для коммерческих ученических разрешений, полученных 7 февраля 2022 года или позже, заявители на первичный CDL класса A/B должны пройти ELDT у провайдера, указанного в реестре провайдеров обучения FMCSA (Training Provider Registry), перед сдачей экзамена на навыки CDL. Источник: FMCSA Entry-Level Driver Training; FLHSMV, страница Commercial Driver License."},"91":{"q":"Какое из этих заявлений на получение разрешения (endorsement) также влечёт за собой требование ELDT (начальное обучение водителей) перед сдачей экзамена?","options":["Первичное разрешение на опасные материалы (H), пассажирское (P) или школьный автобус (S)","Продление существующей привилегии на составное транспортное средство","Добавление разрешения на мотоцикл к удостоверению класса E","Замена утерянного CDL с теми же разрешениями"],"explanation":"ELDT требуется для первичных заявителей, желающих получить разрешение на опасные материалы (H), пассажирское (P) или школьный автобус (S), в дополнение к первичным заявителям на CDL класса A/B и переход с класса B на класс A. Источник: FMCSA Entry-Level Driver Training; FLHSMV."},"92":{"q":"После того как заявитель проходит ELDT, как FLHSMV узнаёт, что обучение завершено?","options":["Заявитель отправляет бумажный диплом напрямую в офис губернатора","FLHSMV физически осматривает грузовик, на котором обучался водитель","Провайдер обучения подаёт сертификацию в реестр провайдеров обучения FMCSA (Training Provider Registry), который штат проверяет перед экзаменом","Проверка не проводится; заявитель просто заявляет, что обучение завершено"],"explanation":"Провайдер обучения в электронном виде подаёт информацию о завершении ELDT водителем в реестр провайдеров обучения FMCSA (Training Provider Registry), и штат проверяет запись перед допуском к экзамену на навыки (или, для H, на знания). Источник: FMCSA Training Provider Registry."},"93":{"q":"Какой документ человек обычно получает первым на пути к CDL Флориды, позволяющий ему практиковаться в вождении коммерческого транспортного средства?","options":["Полный неограниченный CDL, выдаваемый немедленно","Карту разрешения на опасные материалы","Медицинскую справку DOT","Коммерческое ученическое разрешение (CLP)"],"explanation":"Заявители сначала получают коммерческое ученическое разрешение (CLP), сдав необходимые тесты на знания; CLP позволяет им практиковаться на дорогах общего пользования с квалифицированным обладателем CDL перед сдачей экзамена на навыки. Источник: FLHSMV, страница Commercial Driver License."},"94":{"q":"Согласно федеральным правилам, которым следует Флорида, каково минимальное время, в течение которого водитель должен владеть CLP, прежде чем сдавать экзамен на навыки CDL?","options":["Не менее 90 дней","Минимального периода ожидания нет","Не менее 14 дней","Не менее одного полного года"],"explanation":"Федеральное правило требует, чтобы обладатель CLP подождал минимум 14 дней после выдачи CLP, прежде чем сдавать экзамен на навыки CDL. Источник: FMCSA 49 CFR 383.25; процесс CDL FLHSMV."},"95":{"q":"Как долго коммерческое ученическое разрешение может оставаться действительным до того, как потребуется новое заявление?","options":["До одного года с даты выдачи, с возможностью продления в течение этого года","До десяти лет, как паспорт","Только 48 часов с момента выдачи","Оно никогда не истекает после выдачи"],"explanation":"Федеральные правила позволяют CLP быть действительным до одного года с момента первоначальной выдачи; CLP, выданный на срок менее года, может быть продлён при условии, что в общей сложности он действителен не более одного года. Источник: FMCSA 49 CFR 383.25; FLHSMV."},"96":{"q":"Из каких трёх частей состоит экзамен на навыки CDL Флориды?","options":["Письменное эссе, устное собеседование и тест на печатание","Предрейсовый осмотр транспортного средства, базовое управление транспортным средством и вождение по дороге","Проверка зрения, проверка слуха и тест на скорость реакции","Замена шины, замена масла и капитальный ремонт двигателя"],"explanation":"Экзамен на навыки CDL состоит из трёх частей: предрейсовый осмотр транспортного средства, тест базового управления транспортным средством и тест вождения по дороге. Источник: FLHSMV, страница Commercial Driver License."},"97":{"q":"На каком языке должен проводиться экзамен на навыки CDL Флориды?","options":["На любом языке по выбору заявителя","Только на испанском","На английском","Он не проводится ни на каком разговорном языке"],"explanation":"FLHSMV требует, чтобы экзамен на навыки CDL проводился на английском языке, в соответствии с федеральными требованиями о том, что коммерческие водители должны уметь понимать дорожные знаки и общаться на английском. Источник: FLHSMV, страница Commercial Driver License."},"98":{"q":"Каков минимальный возраст для получения CDL Флориды и какое ограничение применяется к водителям младше 21 года?","options":["Не менее 18 лет, но водители младше 21 года, как правило, ограничены внутриштатной деятельностью","Не менее 16 лет, без операционных ограничений","Не менее 25 лет для любого класса CDL","Не менее 21 года, без каких-либо исключений"],"explanation":"Заявители на CDL Флориды должны быть не моложе 18 лет; лица младше 21 года, как правило, ограничены внутриштатной (в пределах Флориды) торговлей, пока им не исполнится 21 год. Источник: FLHSMV, страница Commercial Driver License."},"99":{"q":"Как часто обладатель CDL Флориды должен продлевать своё коммерческое водительское удостоверение?","options":["Каждые шесть месяцев","Каждые двадцать лет","Только один раз, поскольку CDL никогда не истекает","Каждые восемь лет"],"explanation":"Водительские удостоверения Флориды, включая CDL, должны продлеваться каждые восемь лет; CDL необходимо продлевать, и его нельзя продлить на дополнительный срок (extend). Точные сборы могут меняться, поэтому проверяйте актуальные суммы в FLHSMV. Источник: FLHSMV, страница Renew or Replace Your Florida Driver License."}},"tr":{"0":{"q":"Florida karayollarında, bir taşıt veya yükü için (gerekli güvenlik aygıtları hariç) aşırı boyut izni olmadan izin verilen azami toplam dış genişlik nedir?","options":["96 inç (8 fit)","102 inç (8 fit 6 inç)","108 inç (9 fit)","114 inç (9 fit 6 inç)"],"explanation":"Florida Yasası 316.515, herhangi bir taşıtın veya yükünün azami toplam dış genişliğini, güvenlik aygıtları hariç olmak üzere 102 inç (8 fit 6 inç) olarak belirler. Bunu aşmak için FDOT aşırı boyut izni gerekir."},"1":{"q":"Florida karayollarında, bir taşıtın yük dahil izin olmadan ulaşabileceği azami yükseklik nedir?","options":["13 fit","14 fit","14 fit 6 inç","13 fit 6 inç"],"explanation":"Florida Yasası 316.515 uyarınca hiçbir taşıt, yük dahil 13 fit 6 inç yüksekliği aşamaz. (Otomobil taşıyıcılarına 14 fite kadar izin verilir.) Florida yasası, üstten geçen yapıların altından geçişi güvenli şekilde sağlama sorumluluğunu sürücüye yükler."},"2":{"q":"Florida'da, Eyalet Karayolu Sistemi'nde çekici-yarı römork kombinasyonunda çalışan bir yarı römorkun azami uzunluğu (özel uzunluk muafiyetleri uygulanmadan önce) nedir?","options":["48 fit","45 fit","53 fit","57 fit"],"explanation":"Florida Yasası 316.515, çekici-yarı römork kombinasyonundaki bir yarı römorkun azami genel uzunluğunu 48 fit ile sınırlar; 48 fitten fazla ancak 57 fiti aşmayan yarı römorklar yalnızca FDOT veya yerel makamlarca kısıtlanmamış yollarda çalışabilir."},"3":{"q":"Florida yasasına göre tek bir düz kamyonun azami genel uzunluğu nedir?","options":["35 fit","45 fit","40 fit","48 fit"],"explanation":"Florida Yasası 316.515, bir düz kamyonu (tek taşıt) azami genel uzunluk olarak 40 fit ile sınırlar."},"4":{"q":"Florida'da çekici-yarı römork-römork (ikili/çift römork) kombinasyonunda, her bir römorkun azami uzunluğu nedir?","options":["24 fit","28 fit","33 fit","40 fit"],"explanation":"Florida Yasası 316.515, çekici-yarı römork-römork kombinasyonunda çalışan hiçbir yarı römorkun veya römorkun, çift römorklar için federal standartla aynı olan 28 fit uzunluğu aşamayacağını öngörür."},"5":{"q":"Bir taşıtın herhangi bir tek dingilinin tekerlekleri tarafından Florida karayoluna uygulanan azami brüt ağırlık nedir?","options":["18.000 pound","22.400 pound","24.000 pound","20.000 pound"],"explanation":"Florida Yasası 316.535, herhangi bir tek dingilin tekerlekleri tarafından uygulanan brüt ağırlığı 20.000 pound ile sınırlar."},"6":{"q":"Florida karayollarında herhangi bir taşıt veya taşıt kombinasyonu için tüm denetim toleransları dahil azami toplam brüt ağırlık nedir?","options":["73.280 pound","76.000 pound","80.000 pound","88.000 pound"],"explanation":"Florida Yasası 316.535, herhangi bir taşıtın veya taşıt kombinasyonunun toplam brüt ağırlığını, tüm denetim toleransları dahil 80.000 pound ile sınırlandırır. Bu, Interstate sistemi için federal sınırla aynıdır."},"7":{"q":"Florida ve Interstate karayollarında, bir tandem dingil grubu (40 inçten fazla ancak 96 inçten fazla olmayan aralıkta birbirini izleyen iki dingil) için izin verilen azami ağırlık genel olarak şudur:","options":["34.000 pound","30.000 pound","40.000 pound","44.000 pound"],"explanation":"Florida'da uygulanan federal ağırlık standardı uyarınca, bir tandem dingil grubu 34.000 pound ile sınırlıdır. Florida, Interstate sisteminde Federal Köprü Formülü'nü ve 316.535 sayılı Yasanın 80.000 poundluk brüt üst sınırını uygular."},"8":{"q":"Florida, dingil aralığına bağlı olarak ağırlığı sınırlamak için Federal Köprü Formülü'nü kullanır. W = 500[LN/(N-1) + 12N + 36] formülünde 'L' harfi neyi temsil eder?","options":["Pound cinsinden yasal yük ağırlığını","Bir dingil grubunun uçları arasındaki fit cinsinden mesafeyi","Römorkun inç cinsinden uzunluğunu","Taşıtın ruhsatlı brüt ağırlığını"],"explanation":"Florida Yasası 316.535'te benimsenen Federal Köprü Formülü'nde L, birbirini izleyen iki veya daha fazla dingilden oluşan herhangi bir grubun uçları arasındaki fit cinsinden mesafedir; N, gruptaki dingil sayısıdır ve W, izin verilen brüt ağırlıktır."},"9":{"q":"Florida'da kullanılan Federal Köprü Formülü öncelikle neyi korumak için tasarlanmıştır?","options":["Taşıtın lastiklerini aşırı yükten","Sürücüyü yorgunluktan","Yükün kaymasını önlemek için","Köprüleri ve yol kaplamasını yoğunlaşmış ağırlıktan"],"explanation":"Florida Yasası 316.535'teki Federal Köprü Formülü, ağırlığı daha büyük bir mesafeye (daha fazla dingil, daha uzun aralık) yayarak köprüleri ve kaplamayı korur; sık aralıklı dingiller yükü yoğunlaştırır ve daha az ağırlık taşımalıdır."},"10":{"q":"Yasal boyut veya ağırlık sınırlarını aşan yükler için aşırı boyut ve aşırı ağırlık izinlerini hangi Florida kurumu verir?","options":["Florida Karayolu Güvenliği ve Motorlu Taşıtlar Departmanı (DHSMV)","Florida Karayolu Devriyesi (FHP)","Florida Ulaştırma Departmanı (FDOT)","ABD Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Florida Ulaştırma Departmanı (FDOT), Florida Yasaları 316.515 ve 316.535'teki sınırları aşan yükler için İzin Ofisi ve çevrimiçi İzin Başvuru Sistemi aracılığıyla aşırı boyut/aşırı ağırlık izinleri verir."},"11":{"q":"Bir yük 110 inç genişliğindedir. Bunu bir Florida karayolunda taşımadan önce sürücü şunu yapmalıdır:","options":["Bir FDOT aşırı boyut izni almalı","Hiçbir şey yapmamalı; 110 inç yasaldır","Yalnızca hızı 10 mil/saat azaltmalı","Yalnızca yerel polisten onay almalı"],"explanation":"110 inç, Florida Yasası 316.515'teki 102 inçlik (8'6\") yasal genişlik sınırını aştığından, bu taşıma bir FDOT aşırı boyut izni gerektirir. Yükler izin olmadan yasal genişliği aşamaz."},"12":{"q":"Hangi tür FDOT izni, tek bir kaynaktan tek bir varış noktasına tek bir aşırı boyut/aşırı ağırlık taşımasına yetki verir?","options":["Yıllık genel izin","Sefer (tek sefer) izni","Güzergaha özel genel izin","Taşıta özel genel izin"],"explanation":"FDOT, tek bir taşıma için sefer (tek sefer) izni verir; genel izinler (yıllık, güzergaha özel veya taşıta özel) daha uzun bir süre boyunca tekrarlanan taşımaları kapsar. Sefer izinleri genellikle taşımayı tamamlamak için sınırlı sayıda gün için geçerlidir."},"13":{"q":"Florida/FDOT izin kurallarına göre, bir aşırı boyutlu yük genellikle hangi genişlikte en az bir refakat (kılavuz) aracı gerektirmeye başlar?","options":["8 fit 6 inçten fazla","10 fitten fazla","12 fitten fazla","16 fitten fazla"],"explanation":"FDOT aşırı boyutlu yük kurallarına göre, 12 fitten geniş yükler genellikle en az bir refakat aracı gerektirir; 14 fitten geniş yükler tipik olarak iki refakat aracı gerektirir ve en geniş yükler kolluk kuvveti refakati gerektirebilir."},"14":{"q":"Florida'da bir FDOT izni kapsamında taşınan aşırı boyutlu bir yükün genellikle şunu göstermesi gerekir:","options":["Yalnızca gündüz açık farlar","Yalnızca yeşil bir izin levhası","12 fitten dar ise özel işaret yok","Köşelerde/uç noktalarda 'OVERSIZE LOAD' tabelaları ve uyarı bayrakları"],"explanation":"FDOT izin koşulları, aşırı boyutlu yüklerin, diğer trafiğin boyut dışı yükü görebilmesi için yükün köşelerinde ve en geniş noktalarında 'OVERSIZE LOAD' uyarı tabelaları ve renkli (kırmızı/turuncu) bayraklar göstermesini gerektirir."},"15":{"q":"Florida'da uygulanan federal yük emniyete alma kurallarına göre, bağlama elemanlarının toplam çalışma yük sınırı (WLL), emniyete alınan yükün ağırlığının en az hangi oranı kadar olmalıdır?","options":["Yarısı (%50)","Dörtte biri (%25)","Üçte ikisi (%67)","Tam ağırlığı (%100)"],"explanation":"Florida'nın uyguladığı federal yük emniyete alma kuralları (49 CFR 393.106), tüm bağlama elemanlarının toplam çalışma yük sınırının, emniyete alınan eşyanın veya yükün ağırlığının en az yarısı (%50) kadar olmasını gerektirir."},"16":{"q":"Florida'da uygulanan yük emniyete alma kurallarına göre, 5 fit veya daha kısa uzunlukta ve 1.100 pound veya daha az ağırlıkta bir yük eşyası en az kaç bağlama elemanı gerektirir?","options":["İki bağlama elemanı","Bir bağlama elemanı","Üç bağlama elemanı","Takozlanmışsa bağlama elemanı gerekmez"],"explanation":"49 CFR 393.110 uyarınca (Florida'da uygulanır), 5 fit veya daha kısa ve 1.100 pound veya daha az bir eşya en az bir bağlama elemanı gerektirir; daha uzun veya daha ağır eşyalar iki veya daha fazla gerektirir."},"17":{"q":"Yükleme yapıp bir sefere başladıktan sonra, bir Florida CDL sürücüsü yükü ve emniyete alma aygıtlarını ilk olarak ne zaman denetlemelidir?","options":["İlk 25 mil içinde","İlk 100 mil içinde","İlk 50 mil içinde","Yalnızca varış noktasında"],"explanation":"Florida'da uygulanan federal kurallar (49 CFR 392.9), sürücünün sefere başladıktan sonraki ilk 50 mil içinde yükü ve emniyete alma aygıtlarını denetlemesini ve daha sonra bunları periyodik olarak yeniden incelemesini gerektirir."},"18":{"q":"Florida yasası, ağırlık sınırlarında belirli düşük cezalı veya tolerans hükümlerini öncelikle hangi tür yük taşıyıcıları için sağlar?","options":["Kuru kasalarda genel yük","Tehlikeli maddeler","Ev eşyaları","Doğal, işlenmemiş tarım ürünleri"],"explanation":"Florida'nın trafik ve ağırlık yasaları (Bölüm 316), bu yüklerin mevsimsel, çiftlikle ilgili niteliğini göz önünde bulundurarak doğal, işlenmemiş tarım ürünlerinin taşınması için özel tolerans/ceza hükümleri sağlar."},"19":{"q":"Florida'da 14 fit genişliğinde ve 120.000 pound ağırlığında bölünemez bir yük taşıyan bir sürücü, taşımadan önce ne yapmalıdır?","options":["Bir FDOT aşırı boyut VE aşırı ağırlık izni almalı","Hiçbir şey; bölünemez yükler muaftır","Yalnızca gece seyahat etmeli","Bölünemese bile yükü yasal sınırlara indirmeli"],"explanation":"Hem 102 inçlik genişlik sınırını (316.515) hem de 80.000 poundluk brüt ağırlık sınırını (316.535) aşan bölünemez bir yük, güzergah, refakat ve seyahat zamanı koşullarını da belirleyen bir FDOT aşırı boyut/aşırı ağırlık izni gerektirir."},"20":{"q":"Florida'da, çekilen birimin 10.000 lb'yi aştığı, 26.001 lb veya daha fazla brüt kombinasyon ağırlık derecesine sahip bir taşıt kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["A Sınıfı","B Sınıfı","C Sınıfı","D Sınıfı"],"explanation":"26.001 lb veya daha fazla dereceli ve 10.000 lb'yi aşan bir birim çeken kamyon/römork kombinasyonlarını (örneğin çekici-römork) kullanmak için Florida A Sınıfı CDL gereklidir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası; FL CDL El Kitabı."},"21":{"q":"Bir Florida sürücüsü, 10.000 lb'yi aşan bir römork çekmeyen, 26.001 lb veya daha fazla dereceli tek bir düz kamyon veya otobüs kullanmak istiyor. Hangi CDL sınıfı uygundur?","options":["A Sınıfı","B Sınıfı","C Sınıfı","E Sınıfı"],"explanation":"Florida B Sınıfı CDL, 10.000 lb'yi aşan bir birim çekmeyen, 26.001 lb veya daha fazla dereceli tek (düz) kamyonları ve otobüsleri kapsar. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"22":{"q":"16 veya daha fazla kişi taşımak için tasarlanmış veya levhalı tehlikeli madde taşıyan, daha küçük bir taşıt (A veya B Sınıfı ağırlığını karşılamayan) için hangi Florida CDL sınıfı gereklidir?","options":["A Sınıfı","B Sınıfı","C Sınıfı","M Sınıfı"],"explanation":"Florida C Sınıfı CDL, A veya B Sınıfı ağırlık standartlarını karşılamayan ancak 16+ kişi taşımak için tasarlanmış veya levhalı tehlikeli madde taşıyan taşıtlar için geçerlidir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"23":{"q":"Yalnızca eyalet içi (Florida içi) çalışmayla sınırlı bir Florida CDL almak için asgari yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Florida 18 yaşında CDL'ye izin verir, ancak 21 yaşın altındaki sürücüler eyalet içi (eyalet sınırları içinde) çalışmayla sınırlıdır. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası; Florida Yasaları Bölüm 322."},"24":{"q":"19 yaşındaki bir Florida CDL sahibi, eyalet sınırlarını aşarak (eyaletler arası) araç kullanmak veya tehlikeli madde taşımak istiyor. Bunu neden yapamaz?","options":["Eyaletler arası çalışma ve tehlikeli madde taşıma için asgari 21 yaş gerekir","Eyaletler arası çalışma için asgari 23 yaş gerekir","Önce beş yıl boyunca eyalet içi bir CDL'ye sahip olmaları gerekir","25 yaşın altındaki sürücüler hiçbir yük taşıyamaz"],"explanation":"21 yaşın altındaki Florida CDL sahipleri eyalet içi sürüşle sınırlıdır; eyaletler arası çalışma ve tehlikeli madde taşıma, sürücünün en az 21 yaşında olmasını gerektirir. Kaynak: FLHSMV; federal 49 CFR 391.11."},"25":{"q":"Bir Florida CDL sahibinin levhalı miktarlarda tehlikeli madde taşıması için hangi onaya ihtiyacı vardır?","options":["N onayı","T onayı","P onayı","H onayı"],"explanation":"H (Tehlikeli Madde) onayı, levhalı tehlikeli maddelerin taşınmasına yetki verir ve tehlikeli madde bilgi testini geçmeyi gerektirir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"26":{"q":"Florida'da bir tanker taşıt kullanmak için hangi onay gereklidir?","options":["N (Tanker Taşıtlar)","T (Çift/Üçlü Römorklar)","H (Tehlikeli Madde)","S (Okul Otobüsü)"],"explanation":"N onayı, gerekli tanker taşıt bilgi testini geçen ve tanker taşıt kullanacak sürücülere verilir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"27":{"q":"Bir Florida sürücüsü, çift veya üçlü çekici-römork kombinasyonları çekmeyi planlıyor. Hangi onay gereklidir?","options":["P (Yolcular)","T (Çift/Üçlü Römorklar)","N (Tanker Taşıtlar)","H (Tehlikeli Madde)"],"explanation":"Gerekli bilgi testini geçerek kazanılan T onayı, çift ve üçlü römork kombinasyonlarının kullanılmasına izin verir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"28":{"q":"Florida, 16 veya daha fazla kişi (sürücü dahil 15'ten fazla yolcu) taşımak için tasarlanmış bir taşıtı kullanmak için hangi onayı gerektirir?","options":["S (Okul Otobüsü)","P (Yolcular)","N (Tanker Taşıtlar)","T (Çift/Üçlü Römorklar)"],"explanation":"P (Yolcu) onayı hem bilgi hem de beceri testlerini geçmeyi gerektirir ve sürücü dahil 15'ten fazla kişi için tasarlanmış yolcu taşıtları için gereklidir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"29":{"q":"Bir Florida Okul Otobüsü (S) onayı almak için sürücünün ayrıca hangi ek onaya sahip olması gerekir?","options":["H (Tehlikeli Madde) onayı","N (Tanker) onayı","P (Yolcu) onayı","T (Çift/Üçlü) onayı"],"explanation":"Florida, S (Okul Otobüsü) onayına ek olarak P (Yolcu) onayını gerektirir; S onayı kendi bilgi ve beceri testlerini geçmeyi gerektirir. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası."},"30":{"q":"Hangi Florida CDL onayı, verilmeden önce parmak izi alımı ve ulusal geçmiş kontrolü dahil bir federal TSA güvenlik tehdidi değerlendirmesi gerektirir?","options":["P (Yolcular)","T (Çift/Üçlü Römorklar)","N (Tanker Taşıtlar)","H (Tehlikeli Madde)"],"explanation":"USA PATRIOT Yasası uyarınca, H (Tehlikeli Madde) onayı, başvuru sahiplerinin verilmeden önce parmak izi alınmasını ve bir TSA geçmiş kontrolünü geçmesini gerektirir; ek bir ücret uygulanır. Kaynak: FLHSMV Ticari Sürücü Belgesi sayfası; TSA."},"31":{"q":"Bir sürücünün CDL beceri (sürüş) testine girmesine izin verilmeden önce bir Florida Ticari Öğrenci Belgesi'ni (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Florida tarafından benimsenen federal kurallar, CDL beceri testine girmeden önce CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: FLHSMV; 49 CFR 383.25."},"32":{"q":"Bir Florida CLP ile alıştırma yaparken, ticari taşıtta belge sahibine kim eşlik etmelidir?","options":["21 yaş veya üzeri herhangi bir ehliyetli sürücü","Sürücünün yanında veya yakınında oturan, uygun sınıf ve onaylara sahip geçerli bir CDL sahibi","Yalnızca kapalı bir pistte sertifikalı bir CDL eğitmeni","Bilgi testi geçildikten sonra gözetmen gerekmez"],"explanation":"Bir CLP sahibine, uygun grup ve onaylara sahip, doğrudan gözetim altında sürücünün yanında (veya otobüsler için hemen arkasında) fiziksel olarak bulunan geçerli bir CDL sahibi eşlik etmelidir. Kaynak: FLHSMV; 49 CFR 383.25."},"33":{"q":"Ticari taşıt kullanan bir Florida CLP sahibine hangi yolcu kısıtlaması uygulanır?","options":["Eğitim amacıyla 8 yolcuya kadar taşıyabilirler","Yalnızca gündüz saatlerinde yolcu taşıyabilirler","Eşlik eden CDL sahibi dışında yolcu taşıyamazlar","Hepsi emniyet kemeri takarsa yolcu taşıyabilirler"],"explanation":"Bir CLP sahibi, eşlik eden geçerli CDL sahibi/rehber dışında yolcuların bulunduğu bir otobüsü veya taşıtı kullanamaz. Kaynak: FLHSMV; 49 CFR 383.25."},"34":{"q":"Bir Florida CDL başvuru sahibi hava frenleri bilgi testine girmez ve geçemezse, ehliyetlerine ne olur?","options":["Hava frenli taşıtları yasaklayan bir 'L' kısıtlaması eklenir","Onları eyalet içi sürüşle sınırlayan bir 'K' kısıtlaması eklenir","CDL otomatik olarak C Sınıfına düşürülür","Hava frenleri geçilene kadar CDL verilemez"],"explanation":"Hava frenleri testini geçememek veya atlamak, sürücünün hava frenleriyle donatılmış ticari taşıtları kullanmasını yasaklayan bir 'L' kısıtlamasıyla sonuçlanır. Kaynak: FLHSMV; FL CDL El Kitabı."},"35":{"q":"Florida'da benimsenen federal Giriş Düzeyi Sürücü Eğitimi (ELDT) kuralları uyarınca, hangi başvuru sahipleri test öncesinde ELDT'yi tamamlamalıdır?","options":["Yalnızca halihazırda eyalet dışı bir CDL sahibi olan sürücüler","İlk kez CDL başvuru sahipleri, B Sınıfından A Sınıfına yükseltmeler ve ilk kez H, P veya S onayı arayanlar","Yalnızca N veya T onayı arayan sürücüler","Yalnızca 21 yaşın üzerindeki sürücüler"],"explanation":"ELDT, ilk kez CDL başvuru sahipleri, B Sınıfından A Sınıfına yükseltmeler ve ilk kez Tehlikeli Madde, Yolcu veya Okul Otobüsü onayları için gereklidir (7 Şubat 2022 tarihinde veya sonrasında alınan CLP'ler için). Kaynak: FMCSA ELDT kuralı; FLHSMV."},"36":{"q":"Bir sürücünün eğitiminin CDL uygunluğuna sayılması için bir Florida ELDT eğitim sağlayıcısı nerede listelenmelidir?","options":["FMCSA Eğitim Sağlayıcı Sicili'nde","Yalnızca FLHSMV onaylı okul listesinde","TSA tedarikçi sicilinde","Herhangi bir eyalet topluluk koleji listesinde"],"explanation":"ELDT teori ve direksiyon başında eğitimi, tamamlanmayı elektronik olarak gönderen FMCSA Eğitim Sağlayıcı Sicili'nde (TPR) listelenen bir sağlayıcı tarafından verilmelidir. Kaynak: FMCSA Eğitim Sağlayıcı Sicili; FLHSMV."},"37":{"q":"Özellikle Tehlikeli Madde (H) onayı için, bir Florida başvuru sahibi hangi ELDT adımını tamamlamalıdır?","options":["Yol testinden önce direksiyon başında piste eğitimi","Tehlikeli Madde bilgi testine girmeden önce ELDT teori (bilgi) bölümünü","Bir tanker taşıtta tam bir beceri testi","Tehlikeli Madde için asla ELDT gerekmez"],"explanation":"Tehlikeli Madde başvuru sahipleri, Tehlikeli Madde bilgi sınavına girmeden önce kayıtlı bir sağlayıcı aracılığıyla ELDT teori bölümünü tamamlamalıdır. Kaynak: FMCSA ELDT kuralı; FLHSMV."},"38":{"q":"Eyalet sınırlarını aşarak çalışan ve federal bir tıbbi sertifika bulundurması gereken bir Florida CDL sürücüsü hangi kategori altında kendini sertifikalandırır?","options":["İstisnai Eyaletler Arası (EI)","İstisnai Eyalet İçi (EA)","İstisnai Olmayan Eyalet İçi (NA)","İstisnai Olmayan Eyaletler Arası (NI)"],"explanation":"İstisnai Olmayan Eyaletler Arası (NI), bir FMCSA Ulusal Sicil muayenecisinden geçerli bir tıbbi muayeneci sertifikası bulundurması gereken eyaletler arası ticaretteki sürücüler için geçerlidir. Kaynak: FLHSMV kendini sertifikalandırma; FMCSA 49 CFR 383.71."},"39":{"q":"REAL ID uyumlu bir CDL başvurusu için Florida hangi belgeyi birincil kimlik kanıtı olarak kabul eder?","options":["Onaylı bir ABD doğum belgesi veya geçerli bir ABD pasaportu","Başvuru sahibinin adına düzenlenmiş güncel bir kamu hizmeti faturası","Bir Florida seçmen kayıt kartı","İşveren tarafından verilmiş bir fotoğraflı kimlik kartı"],"explanation":"REAL ID uyumlu bir CDL için Florida, onaylı bir ABD doğum belgesi veya geçerli bir ABD pasaportu/pasaport kartı gibi birincil bir kimlik belgesinin yanı sıra Sosyal Güvenlik numarası kanıtı ve iki adet ikamet adresi kanıtı gerektirir. Kaynak: FLHSMV Yanınızda Getirilecekler / REAL ID."},"40":{"q":"Florida'da, bir CDL sahibinin yasal olarak ticari motorlu taşıt (CMV) kullanabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["yüzde 0,08","yüzde 0,02","yüzde 0,10","yüzde 0,04"],"explanation":"Florida'da BAC'niz yüzde 0,04 veya daha fazlaysa bir CMV kullanmak yasa dışıdır; bu, ticari olmayan sürücülere uygulanan yüzde 0,08 sınırının yarısıdır. Kaynak: Florida CDL El Kitabı (FLHSMV), Sürücü Diskalifiyeleri; 49 CFR 383.51."},"41":{"q":"Florida'nın zımni rıza yasası uyarınca, bir kişi eyalette bir ticari motorlu taşıt kullandığı anda ne olur?","options":["Her zaman ayrı bir nefes testi izni taşımaları gerekir","Alkol testine rıza göstermiş sayılırlar","CDL duruşması hakkından tamamen feragat ederler","Bir kaza olmadıkça testten muaftırlar"],"explanation":"Florida'da bir CMV kullanarak, bir sürücü alkol testine rıza göstermiş sayılır. Testi reddetmek, bir DUI mahkumiyetiyle aynı diskalifiyeyi taşır. Kaynak: Florida CDL El Kitabı (FLHSMV); Florida Yasaları Bölüm 322 (zımni rıza)."},"42":{"q":"Bir CDL sahibi, tehlikeli madde taşımazken DUI gibi ilk büyük bir suçtan mahkum olur. Florida'da asgari CDL diskalifiye süresi nedir?","options":["60 gün","3 yıl","1 yıl","Ömür boyu"],"explanation":"İlk büyük suç (DUI, bir CMV'de 0,04 veya daha yüksek BAC, testi reddetme, kaza yerinden ayrılma veya bir suç işlemek için taşıt kullanma) en az 1 yıllık CDL diskalifiyesiyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"43":{"q":"İlk büyük suç, bir CDL sürücüsü tehlikeli madde için levhalı bir CMV kullanırken işlenirse, Florida'da asgari diskalifiye süresi nedir?","options":["3 yıl","1 yıl","120 gün","Ömür boyu"],"explanation":"Tehlikeli madde için levhalı bir CMV kullanırken işlenen ilk büyük suç, asgari diskalifiyeyi 1 yıldan en az 3 yıla yükseltir. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"44":{"q":"Sürüş kariyeri boyunca herhangi bir zamanda İKİNCİ bir büyük suçtan mahkum olan bir CDL sahibi için Florida'daki sonuç nedir?","options":["3 yıllık diskalifiye","CDL'nin ömür boyu kaybı","1 yıllık diskalifiye","120 günlük diskalifiye"],"explanation":"İkinci bir büyük suç, ömür boyu CDL diskalifiyesiyle sonuçlanır. Florida, sınırlı koşullar altında asgari bir süreden sonra yeniden alma değerlendirmesine izin verebilir, ancak kural ömür boyu yasaktır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"45":{"q":"Florida'daki bir CDL sürücüsünden yasal olarak kandaki alkol testine tabi olması istenir ve reddeder. Bu, CDL diskalifiyesi açısından nasıl ele alınır?","options":["Yalnızca ciddi bir ihlaldir, 60 gün diskalifiye eder","Büyük bir suçtur, en az 1 yıl diskalifiye eder","Sürücü görev dışıysa hiçbir CDL cezası taşımaz","Yalnızca 24 saatlik bir hizmet dışı emriyle sonuçlanır"],"explanation":"Alkol testine tabi olmayı reddetmek büyük bir suç olarak ele alınır ve bir DUI mahkumiyetiyle aynı asgari 1 yıllık diskalifiyeyi (Tehlikeli Madde için levhalıysa 3 yıl) taşır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"46":{"q":"Aşağıdakilerden hangisi bir Florida CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Bir CMV'de yüzde 0,04 BAC ile araç kullanmak","Yasal bir alkol testini reddetmek","Hizmet dışı emri altında bir CMV kullanmak","Aşırı hız, belirtilen sınırın 15 mil/saat veya daha fazla üzerinde"],"explanation":"Aşırı hız (sınırın 15 mil/saat veya daha fazla üzerinde) ciddi bir trafik ihlalidir. Diğer seçenekler, farklı ve daha ağır cezalar taşıyan büyük suçlar veya hizmet dışı ihlalleridir. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"47":{"q":"Florida'da 3 yıllık bir süre içinde kaç ciddi trafik ihlali bir CDL diskalifiyesini tetikler ve ikincisi için ne kadar süreyle?","options":["2 ihlal en az 120 günlük diskalifiyeyle sonuçlanır","3 ihlal en az 60 günlük diskalifiyeyle sonuçlanır","2 ihlal en az 60 günlük diskalifiyeyle sonuçlanır","2 ihlal en az 1 yıllık diskalifiyeyle sonuçlanır"],"explanation":"3 yıllık bir süre içinde ikinci bir ciddi trafik ihlali, en az 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"48":{"q":"3 yıllık bir süre içinde işlenen ÜÇÜNCÜ bir ciddi trafik ihlali için Florida'daki asgari CDL diskalifiyesi nedir?","options":["60 gün","1 yıl","120 gün","30 gün"],"explanation":"3 yıllık bir süre içinde üçüncü bir ciddi trafik ihlali, en az 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"49":{"q":"Aşağıdakilerden hangisi bir Florida CDL sahibi için büyük bir suç değil de ciddi bir trafik ihlalidir?","options":["Uygunsuz veya düzensiz şerit değiştirmeler","Kaza yerinden ayrılmak","Bir suç işlemek için taşıt kullanmak","Kontrollü bir maddenin etkisi altında araç kullanmak"],"explanation":"Uygunsuz veya düzensiz şerit değiştirmeler ciddi bir trafik ihlalidir. Diğer üçü, asgari 1 yıllık (veya ömür boyu) diskalifiye taşıyan büyük suçlardır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"50":{"q":"Florida ve federal CDL kurallarına göre, bir CMV kullanırken mesajlaşmak, diskalifiye amaçları bakımından nasıl sınıflandırılır?","options":["1 yıllık diskalifiye gerektiren büyük bir suç olarak","Ciddi bir trafik ihlali olarak","Bir hizmet dışı bırakma emri ihlali olarak","Diskalifiye etkisi olmayan, CDL dışı bir kabahat olarak"],"explanation":"Bir CMV kullanırken mesajlaşmayı yasaklayan kanunu ihlal etmek, ciddi bir trafik ihlalidir. 3 yıl içinde diğer ciddi ihlallerle birleştiğinde, 60 veya 120 günlük bir diskalifiyeye yol açabilir. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51 ve 392.80."},"51":{"q":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmak, Florida'daki CDL sürücüleri için yasaktır. Diskalifiye amaçları bakımından bu suç şu şekilde değerlendirilir:","options":["Ömür boyu diskalifiye gerektiren büyük bir suç","Bir demir yolu geçidi ihlali","Ciddi bir trafik ihlali","Bir hizmet dışı bırakma emri ihlali"],"explanation":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanımını yasaklayan kanunu ihlal etmek, ciddi bir trafik ihlalidir; 3 yıl içindeki tekrarlanan ciddi ihlaller, 60 veya 120 günlük diskalifiyelere yol açar. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51 ve 392.82."},"52":{"q":"Florida'da bir demir yolu-karayolu hemzemin geçit ihlalinin İLK mahkumiyeti için asgari CDL diskalifiyesi nedir?","options":["120 gün","60 gün","1 yıl","30 gün"],"explanation":"İlk demir yolu-karayolu hemzemin geçit ihlali, en az 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"53":{"q":"Bir Florida CDL sahibi, 3 yıllık bir süre içinde İKİNCİ bir demir yolu-karayolu hemzemin geçit ihlali işliyor. Asgari diskalifiye nedir?","options":["60 gün","1 yıl","180 gün","120 gün"],"explanation":"3 yıl içinde ikinci bir demir yolu-karayolu hemzemin geçit ihlali, en az 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"54":{"q":"Florida'da 3 yıllık bir süre içinde ÜÇÜNCÜ bir demir yolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifiyesi nedir?","options":["120 gün","60 gün","1 yıl","Ömür boyu"],"explanation":"3 yıllık bir süre içinde üçüncü bir demir yolu-karayolu hemzemin geçit ihlali, en az 1 yıllık bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"55":{"q":"Bir Florida CDL sürücüsü, tehlikeli madde veya yolcu taşımazken İLK kez bir hizmet dışı bırakma emrini ihlal ediyor. Asgari diskalifiye nedir?","options":["180 gün","60 gün","90 gün","120 gün"],"explanation":"İlk hizmet dışı bırakma emri ihlali, en az 180 günlük bir diskalifiyeyle sonuçlanır (HazMat veya yolcu taşınıyorsa daha uzun). Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"56":{"q":"Florida'da 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı bırakma emri ihlali için asgari CDL diskalifiyesi nedir?","options":["180 gün","1 yıl","3 yıl","2 yıl"],"explanation":"10 yıllık bir süre içinde ikinci bir hizmet dışı bırakma emri ihlali, en az 2 yıllık bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"57":{"q":"Bir Florida CDL sürücüsü, 10 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir hizmet dışı bırakma emri ihlali işliyor. Asgari diskalifiye nedir?","options":["3 yıl","2 yıl","1 yıl","180 gün"],"explanation":"10 yıllık bir süre içinde üçüncü veya sonraki bir hizmet dışı bırakma emri ihlali, en az 3 yıllık bir diskalifiyeyle sonuçlanır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"58":{"q":"Florida'da bir CDL sürücüsünün görev başındayken HERHANGİ bir tespit edilebilir miktarda alkol (0.04 BAC altında) bulundurduğu tespit edilirse, ani sonucu nedir?","options":["24 saatliğine hizmet dışı bırakılır","CDL'nin kalıcı olarak kaybı","60 günlük bir diskalifiye","Zorunlu 1 yıllık bir diskalifiye"],"explanation":"0.04'ün altında herhangi bir tespit edilebilir miktarda alkol bulunan bir sürücü, 24 saatliğine hizmet dışı bırakılır. 0.04 veya daha yüksek bir BAC, sürücüyü en az 1 yıl diskalifiye eden büyük bir suçtur. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 392.5 ve 383.51."},"59":{"q":"Florida'da hangi suç, yeniden alma imkanı olmaksızın ZORUNLU ömür boyu CDL diskalifiyesiyle sonuçlanır?","options":["Bir CMV'de ilk DUI mahkumiyeti","3 yıl içinde iki ciddi trafik ihlali","İlk demir yolu geçidi ihlali","Kontrollü bir maddenin üretilmesi, dağıtılması veya temin edilmesi için bir CMV kullanmak"],"explanation":"Kontrollü bir maddenin üretilmesi, dağıtılması veya temin edilmesini içeren bir suçun işlenmesinde bir CMV kullanmak, yeniden alma imkanı olmaksızın zorunlu ömür boyu diskalifiye taşır. Kaynak: Florida CDL El Kitabı (FLHSMV); 49 CFR 383.51."},"60":{"q":"Florida'nın Şerit Değiştirme Yasası (Move Over Act) kapsamında, çok şeritli bir otoyolda bir çekici-römork kullanıyorsunuz ve acil durum ışıkları yanan, duran bir devriye arabasına yaklaşıyorsunuz. Yasa önce ne yapmanızı gerektirir?","options":["Acil durum aracı ayrılana kadar mevcut şeritinizde tamamen durun","Güvenli olduğu anda acil durum aracına en yakın şeridi boşaltın","Yaklaşımınız konusunda memuru uyarmak için kornanızı çalın","Hızınızı koruyun ama dörtlü flaşörlerinizi açın"],"explanation":"Florida'nın Şerit Değiştirme Yasası (Fla. Stat. 316.126), çok şeritli bir yoldaki sürücülerin, güvenli olduğu anda durmuş acil durum veya hizmet aracına en yakın şeridi boşaltmasını gerektirir; yalnızca şerit değiştirmek mümkün değilse yavaşlamanız gerekir."},"61":{"q":"55 mph olarak işaretlenmiş iki şeritli bir Florida yolunda, sarı ışıklar gösteren duran bir çekici (wrecker) aracına yaklaşıyorsunuz ve güvenli bir şekilde şerit değiştiremiyorsunuz. Hızınızı saatte kaç mil'e düşürmeniz gerekir?","options":["45 mph","25 mph","35 mph","55 mph; iki şeritli bir yolda hız düşürmek gerekmez"],"explanation":"Fla. Stat. 316.126 kapsamında, şerit değiştiremediğinizde, işaretli hız 25 mph veya daha yüksek olduğunda işaretli sınırın 20 mph altına yavaşlamanız gerekir. 55 mph'lik bir yolda bu, 35 mph anlamına gelir."},"62":{"q":"Florida'nın Şerit Değiştirme Yasası, şerit değiştiremediğinizde hız düşürmeyi gerektirir. İşaretli hız sınırının 20 mph veya daha az olduğu bir yolda, nitelikli bir duran aracın yanından geçerken hangi hıza yavaşlamanız gerekir?","options":["5 mph","10 mph","0 mph (tam duruş)","15 mph"],"explanation":"Fla. Stat. 316.126, işaretli hız sınırı 20 mph veya daha az olduğunda, şerit değiştiremeyen bir sürücünün duran aracın yanından geçerken 5 mph'e yavaşlaması gerektiğini öngörür."},"63":{"q":"Acil durum araçlarına ek olarak, Florida'nın Şerit Değiştirme yasası (Fla. Stat. 316.126), uygun sinyalleri gösteren aşağıdaki duran araçlardan hangisini de korur?","options":["Temizlik, kamu hizmeti ve yol veya köprü bakım araçları ile dörtlü flaşörleri yanan arızalı araçlar","Yalnızca işaretli kolluk kuvveti ve itfaiye araçları","Yalnızca ambulanslar ve çekiciler","Banketteki herhangi bir özel mülkiyet binek otomobili"],"explanation":"Fla. Stat. 316.126, Şerit Değiştirme korumalarını, acil durum araçlarına ek olarak temizlik araçlarına, kamu hizmeti araçlarına, çekicilere, yol ve köprü bakım/inşaat araçlarına ve dörtlü flaşörleri yanan arızalı motorlu araçlara genişletir."},"64":{"q":"Florida'da yolcu taşıyan bir otobüs kullanıyorsunuz ve bir demir yolu hemzemin geçidine yaklaşıyorsunuz. En yakın raydan ne kadar mesafede durmanız gerekir?","options":["5 ile 15 fit arasında","50 ile 100 fit arasında","15 ile 50 fit arasında","Tam 25 fit, ne daha yakın ne daha uzak"],"explanation":"Yolcu taşıyan otobüsler ve plakalı tehlikeli madde araçları, en yakın raya 15 fitten daha yakın ve 50 fitten daha uzak olmayacak şekilde durmalı, ardından geçmeden önce bakıp dinlemelidir (Florida CDL El Kitabı; FMCSR 392.10)."},"65":{"q":"Florida'da bir istisna geçerli olmadıkça her demir yolu geçidinde zorunlu olarak durması gereken ticari araç hangisidir?","options":["Yükü olmayan boş bir düz römork kamyon","Plakalı miktarlarda tehlikeli madde taşıyan bir araç","Genel yük taşıyan bir teslimat kamyoneti","Kum taşıyan bir damperli kamyon"],"explanation":"Florida CDL El Kitabı'nda benimsenen federal kurallara göre (FMCSR 392.10), tehlikeli maddeler için plakalı olması gereken araçlar ve yolcu taşıyan otobüsler demir yolu geçitlerinde durmalıdır; sıradan yük araçlarının durması gerekmez."},"66":{"q":"Plakalı tehlikeli madde sürücüsünün veya otobüs sürücüsünün hangi demir yolu geçidinde durması GEREKMEZ?","options":["Çalışan bir trafik sinyalinin yeşil gösterdiği veya resmi bir Muaf (Exempt) tabelasıyla işaretlenmiş bir geçit","Kırsal iki şeritli bir yoldaki herhangi bir geçit","Çapraz işaretleri olan ama yanıp sönen ışıkları olmayan bir geçit","Gün batımından hemen sonraki bir geçit"],"explanation":"Florida CDL El Kitabı (FMCSR 392.10), zorunlu duruşa istisnaları listeler: yeşil bir trafik kontrol sinyali, resmi bir Muaf (Exempt) tabelasıyla işaretlenmiş bir geçit, bir polis memuru veya işaretçi tarafından yönlendirilen bir geçit ve yalnızca tramvaylar veya endüstriyel manevra için kullanılan raylar."},"67":{"q":"Manuel şanzımanlı bir ticari araçla demir yolu raylarını geçerken ne yapmalısınız?","options":["Rayları daha hızlı geçmek için karşıya geçerken ortada daha yüksek bir vitese geçin","Devam etmeden önce aynalarınızı kontrol etmek için rayların üzerinde durun","Vitesi boşa alın ve raylar boyunca yuvarlanarak geçin","Düşük bir viteste geçin ve raylar üzerindeyken vites değiştirmeyin"],"explanation":"Florida CDL El Kitabı, sürücülere aracı raylardan tamamen geçirecek bir vites seçmelerini ve rayların üzerinde stop etmeyi önlemek için geçerken asla vites değiştirmemelerini söyler."},"68":{"q":"Refüj veya bariyeri olmayan iki yönlü bir Florida caddesinde, bir okul otobüsü kırmızı ışıkları yanıp sönerek ve dur kolu açık olarak duruyor. Karşı yönden yaklaşan trafik ne yapmalıdır?","options":["10 mph'e yavaşlayın ama otobüsün yanından geçmeye devam edebilirsiniz","Karşı yön trafiğinin asla durması gerekmediği için normal şekilde devam edin","Durun ve ışıklar yanıp sönmeyi bırakıp dur kolu geri çekilene kadar durmaya devam edin","Yalnızca çocuklar yolu geçerken görünüyorsa durun"],"explanation":"Fla. Stat. 316.172, bölünmemiş iki yönlü bir yolda karşı yön trafiği dahil tüm trafiğin, yanıp sönen kırmızı ışıkları olan duran bir okul otobüsü için durmasını ve ışıklar durup dur kolu geri çekilene kadar durmaya devam etmesini gerektirir."},"69":{"q":"Florida yasalarına göre, karşı yönde seyreden sürücülerin, yol aşağıdakilerden hangisiyle bölündüğünde duran bir okul otobüsü için durmaları GEREKMEZ?","options":["Tek düz sarı orta çizgi","Boyalı iki yönlü sola dönüş şeridi","Yükseltilmiş bir refüj, fiziksel bir bariyer veya en az 5 fitlik kaplamasız bir alan","Bir sıra yansıtıcı şerit işaretleyici"],"explanation":"Fla. Stat. 316.172(2), karşı yön trafiğini durmaktan yalnızca bölünmüş otoyolun trafiği yükseltilmiş bir refüj, fiziksel bir bariyer veya en az 5 fitlik kaplamasız bir alanla ayırdığında muaf tutar. Yalnızca boya çizgileri uygun değildir."},"70":{"q":"Ticari motorlu aracınızı tek yönlü veya bölünmüş bir Florida otoyolunun banketinde durdurmanız gerekirse, üç acil durum uyarı cihazınızı nereye yerleştirmelisiniz?","options":["Yaklaşan trafiğe doğru 5 fit, 50 fit ve 150 fit","Üçünü de aracın arkasının 10 fit içinde","Aracın 25 fit, 75 fit ve 125 fit önünde","Yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit"],"explanation":"Florida CDL El Kitabı (FMCSR 392.22), tek yönlü veya bölünmüş bir otoyolda uyarı cihazlarının yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit'e yerleştirilmesini gerektirir."},"71":{"q":"Ticari aracınızı bir Florida otoyolunun seyir kısmında veya banketinde durdurduktan sonra, dörtlü flaşör (four-way flasher) uyarı ışıklarınızı kaç saniye içinde etkinleştirmeniz gerekir?","options":["30 dakika içinde, yalnızca geceleri","Yalnızca uyarı üçgenleri zaten yerleştirildikten sonra","Hemen ve uyarı cihazlarını 10 dakika içinde yerleştirin","Dörtlü flaşörler için bir süre gerekliliği yoktur"],"explanation":"Florida CDL El Kitabı'nda benimsenen FMCSR 392.22 kapsamında, durmuş bir CMV, dörtlü flaşörlerini hemen açmalı ve uyarı cihazlarını (üçgenler/fişekler) 10 dakika içinde yerleştirmelidir."},"72":{"q":"Her iki yönde de trafik taşıyan iki şeritli bir Florida yolunda, CMV'niz durduğunda uyarı üçgenleri nereye yerleştirilmelidir?","options":["Aracın 10 fit içinde ve arkasında ve önünde 100 fit","Yalnızca aracın 200 fit arkasında","Yalnızca aracın ön tamponunda","Yalnızca 50 fit arkada ve 50 fit önde"],"explanation":"Florida CDL El Kitabı (FMCSR 392.22), iki şeritli veya bölünmemiş bir yolda bir uyarı cihazını aracın 10 fit içine, bir tanesini durmuş aracın 100 fit arkasına ve bir tanesini de 100 fit önüne yerleştirmenizi yönlendirir."},"73":{"q":"Kendi yönünüzde üç veya daha fazla şeridi olan bir Florida yolunda, genel sağ şerit kuralı, kamyonlar dahil yavaş hareket eden araçların ne yapmasını gerektirir?","options":["Hıza bakılmaksızın her zaman orta şeritte seyredin","Sağ şerit trafiğini açık tutmak için en sol şeridi kullanın","Hiçbir kısıtlama olmaksızın herhangi bir şeridi serbestçe seçin","Geçiş, sollama veya sola dönüşe hazırlanma dışında sağ taraftaki şeritte kalın"],"explanation":"Fla. Stat. 316.081, normal trafik hızından daha yavaş seyreden herhangi bir aracın, sollama/geçiş veya sola dönüşe hazırlanma dışında sağ taraftaki şeridi (veya mümkün olduğunca sağ kenara yakın) kullanmasını gerektirir."},"74":{"q":"İş veya konut bölgeleri dışında, başka bir sınır işaretlenmemişse Florida'nın yasal varsayılan azami hız sınırı nedir?","options":["55 mph","70 mph","65 mph","45 mph"],"explanation":"Fla. Stat. 316.183/316.187, farklı bir sınır işaretlenmedikçe iş veya konut bölgeleri dışındaki yerlerde yasal azamiyi 55 mph olarak belirler; iş veya konut bölgelerinde 30 mph geçerlidir."},"75":{"q":"70 mph olarak işaretlenmiş en az dört şeritli bir Florida eyaletler arası otoyolunda, yasal asgari hız sınırı nedir?","options":["40 mph","55 mph","45 mph","50 mph"],"explanation":"Fla. Stat. 316.183, azami işaretli sınırın 70 mph olduğu en az dört şeritli bölünmüş eyaletler arası otoyollarda 50 mph'lik bir asgari hız belirler."},"76":{"q":"Florida'nın dikkat dağınık sürüş yasası (Fla. Stat. 316.305) kapsamında, hareket eden bir motorlu aracı kullanırken ne yasaktır?","options":["Bir telefon görüşmesi için eller serbest Bluetooth hoparlörünün herhangi bir kullanımı","Mesajlaşma, e-posta veya anlık mesajlaşma gibi sesli olmayan iletişim için manuel olarak veri yazmak veya okumak","Navigasyon sesli yönergelerini dinlemek","Kabinde görünür şekilde monteli bir telefon bulundurmak"],"explanation":"Fla. Stat. 316.305, sürüş sırasında kablosuz bir cihazda sesli olmayan kişilerarası iletişim için (mesajlaşma, e-posta, anlık mesajlaşma) manuel olarak karakter yazmayı veya girmeyi ve veri göndermeyi veya okumayı yasaklar."},"77":{"q":"Florida'nın sürüş sırasında mesajlaşma yasasının (Fla. Stat. 316.305) uygulanması hakkında hangi ifade doğrudur?","options":["Önce başka bir ihlal gerektiren ikincil bir suçtur","Birincil bir suçtur, bu yüzden bir memur yalnızca mesajlaşma nedeniyle bir sürücüyü durdurup ceza yazabilir","Yalnızca 18 yaşının altındaki sürücüler için geçerlidir","Yalnızca gün batımı ile gün doğumu arasında geçerlidir"],"explanation":"2019'dan beri, Fla. Stat. 316.305, sürüş sırasında mesajlaşmayı birincil bir suç haline getirerek memurların yalnızca bu ihlal nedeniyle bir sürücüyü durdurup ceza yazmasına izin verir."},"78":{"q":"Florida, bir kasırga sırasında bir tahliye rotasında Acil Durum Banket Kullanımını (Emergency Shoulder Use, ESU) etkinleştirdiğinde, hangi araçların açılan banket şeridini kullanmasına İZİN VERİLMEZ?","options":["Binek otomobiller ve kamyonetler","Büyük kamyonlar, otobüsler ve römorklar","Motosikletler ve SUV'lar","Tüm araçların banketi eşit olarak kullanmasına izin verilir"],"explanation":"Florida'nın FDOT Acil Durum Banket Kullanımı planı (kontraflow'un yerini alan) kapsamında, büyük kamyonlar, otobüsler ve römorklar HARİÇ tüm sürücüler, bir kasırga tahliyesi sırasında kaplamalı banketi geçici bir seyir şeridi olarak kullanabilir."},"79":{"q":"Ağır hizmet ticari araçların uzun süreli rölantide çalışması ile ilgili olarak, hangi ifade mevcut Florida yasasını yansıtır?","options":["Florida, eyalet genelinde 3 dakikadan fazla tüm kamyon rölantisini yasaklar","Florida, eyalet genelinde her zaman rölantiyi 5 dakika ile sınırlar","Florida, eyaletin herhangi bir yerinde bir kamyon park edildiğinde motorların kapatılmasını gerektirir","Florida'nın eyalet genelinde ağır hizmet aracı rölanti azaltma sınırı yoktur; önceki rölanti kuralı yürürlükten kaldırıldı"],"explanation":"Florida'nın ağır hizmet aracı rölanti azaltma kuralı (Fla. Admin. Code 62-285.420) yürürlükten kaldırıldı, bu yüzden eyalet genelinde bir rölanti süresi sınırı yok; sürücüler yine de yerel düzenlemeleri kontrol etmelidir. Bu, eyalet genelinde rölanti karşıtı yasaları olan eyaletlerden farklıdır."},"80":{"q":"Florida'da ticari sürücü ehliyetlerini (CDL'leri) hangi kurum verir?","options":["Florida Ulaştırma Bakanlığı (FDOT)","Florida Karayolu Güvenliği ve Motorlu Taşıtlar Bakanlığı (FLHSMV)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","ABD Motorlu Taşıtlar Dairesi"],"explanation":"Florida'da CDL'ler, Florida Karayolu Güvenliği ve Motorlu Taşıtlar Bakanlığı (FLHSMV) tarafından verilir ve yönetilir. FMCSA federal standartları belirler, ancak gerçek belgeyi eyalet kurumu verir. Kaynak: FLHSMV, Ticari Sürücü Ehliyeti sayfası."},"81":{"q":"Orijinal bir Florida CDL veya ticari öğrenci belgesi (CLP) için başvururken, başvuru sahibinin FLHSMV'ye hangi belge setini sunması gerekir?","options":["Yalnızca güncel bir Florida Class E sürücü ehliyeti ve bir fotoğraf","Bir pasaport ve tek bir fatura, Sosyal Güvenlik belgesi olmadan","Yalnızca bir DOT tıbbi muayene memuru sertifikası ve bir parmak izi kartı","Kimlik kanıtı, Sosyal Güvenlik numarası kanıtı ve iki Florida konut adresi kanıtı"],"explanation":"FLHSMV tarafından uygulanan federal REAL ID Yasası kapsamında, orijinal CDL/CLP başvuru sahipleri kimliklerini, Sosyal Güvenlik numaralarını ve iki Florida konut adresini kanıtlayan orijinal belgeler sunmalıdır. Kaynak: FLHSMV, Ne Getirmeli / Ticari Sürücü Ehliyeti sayfaları."},"82":{"q":"Florida CDL ve CLP belgeleri REAL ID uyumludur. REAL ID Yasası başvuru sahiplerinden ne gerektirir?","options":["Herhangi bir kimlik belgesi yerine noter onaylı bir beyanname sunmak","Kimliği, Sosyal Güvenlik numarasını ve konut adresini doğrulayan orijinal belgeler sunmak","Tüm gereksinimlerin tek kabul edilebilir kanıtı olarak federal bir pasaport kartı sağlamak","Yüz yüze belge incelemesi yerine çevrimiçi bir kimlik sınavı tamamlamak"],"explanation":"REAL ID, başvuru sahiplerinin ilk ofis içi belge düzenlemede kimliği, Sosyal Güvenlik numarasını ve konut adresini doğrulayan orijinal belgeler sunmasını gerektirir. Bir kez sağlandıktan sonra, genellikle yalnızca bilgiler değişirse tekrar gösterilmeleri gerekir. Kaynak: FLHSMV, REAL ID sayfası."},"83":{"q":"Bir CDL veya CLP başvuru sahibinin FLHSMV'ye kaç Florida konut adresi kanıtı sunması gerekir?","options":["Bir CDL için konut adresi kanıtı gerekmez","Hepsi fatura olan, dört konut adresi kanıtı","Bir kanıt, ancak bir pasaport olmalıdır","Başvuru sahibinin adına iki konut adresi kanıtı"],"explanation":"FLHSMV, CLP ve CDL başvuru sahiplerinin kendi adlarına iki Florida konut adresi kanıtı sunmalarını gerektirir (Liste A'dan ikisi veya Liste A'dan biri ve Liste B'den biri). Kaynak: FLHSMV, Ne Getirmeli sayfası."},"84":{"q":"Federal Motorlu Taşıyıcı Güvenliği Yönetmelikleri, bir CDL alan veya yenileyen her sürücünün FLHSMV'ye kaç operasyon kategorisinde kendi beyanını (self-certify) yapmasını gerektirir?","options":["İki kategori","Dört kategori","Altı kategori","Üç kategori"],"explanation":"Sürücüler dört kategoriden birinde kendi beyanlarını yapmalıdır: istisnasız eyaletler arası, istisnalı eyaletler arası, istisnasız eyalet içi ve istisnalı eyalet içi. Kaynak: FLHSMV, CDL Tıbbi Sertifikasyon sayfası."},"85":{"q":"Aşağıdakilerden hangisi FLHSMV tarafından kullanılan dört CDL kendi beyan (self-certification) kategorisinden biridir?","options":["İstisnasız eyaletler arası","İstisnalı federal hazmat","Kısıtlı yalnızca eyalet içi tarımsal","Geçici eyaletler arası ticaret"],"explanation":"Dört geçerli kendi beyan kategorisi şunlardır: istisnasız eyaletler arası, istisnalı eyaletler arası, istisnasız eyalet içi ve istisnalı eyalet içi. 'İstisnasız eyaletler arası', federal bir tıbbi sertifikayı sürdürmesi gereken sürücüler için olan kategoridir. Kaynak: FLHSMV, CDL Tıbbi Sertifikasyon sayfası."},"86":{"q":"Bir Florida CDL sürücüsü 'istisnasız eyaletler arası' olarak kendi beyanını yapıyor. Bu, ne tür sürekli bir tıbbi yükümlülük oluşturur?","options":["Herhangi bir tıbbi sertifikasyondan kalıcı olarak muaftırlar","Yalnızca on beş yılda bir tıbbi muayene yaptırmaları gerekir","Geçerli bir DOT tıbbi muayene memuru sertifikası edinmeleri ve FLHSMV'de dosyada güncel tutmaları gerekir","Kendi beyanlarını yapmaları gerekir ama asla bir tıbbi muayene memuru sertifikasına ihtiyaç duymazlar"],"explanation":"İstisnasız eyaletler arası (veya istisnasız eyalet içi) olarak beyan veren sürücüler, geçerli bir DOT tıbbi muayene memuru sertifikası sürdürmeli ve FLHSMV'de dosyada güncel tutmalıdır. Kaynak: FLHSMV, CDL Tıbbi Sertifikasyon sayfası."},"87":{"q":"DOT tıbbi muayene memuru sertifikası (sıklıkla 'Med Card' olarak adlandırılır) Florida CDL sürecinde ne için kullanılır?","options":["Sürücünün giriş seviyesi sürücü eğitimini tamamladığını kanıtlamak için","Sürücünün Florida ikamet kanıtı olarak hizmet etmek için","Deneyimli sürücüler için bilgi ve beceri testlerinin yerini almak için","Bir sürücünün ticari bir motorlu aracı kullanmak için fiziksel yeterlilik standartlarını karşıladığını belgelemek için"],"explanation":"DOT tıbbi muayene memuru sertifikası, sertifikalı bir tıbbi muayene memurunun sürücüyü ticari bir motorlu aracı kullanmak için fiziksel olarak yeterli bulduğunu belgeler. İkamet kanıtından ve bilgi/beceri testlerinden ayrıdır. Kaynak: FLHSMV, CDL Tıbbi Sertifikasyon sayfası."},"88":{"q":"Bir Florida istisnasız eyaletler arası CDL sahibinin kendi beyanını ve tıbbi bilgilerini güncel tutması gerekir. FLHSMV tarafından sağlanan bunu yönetmenin bir yolu nedir?","options":["Sertifikayı yalnızca FMCSA ulusal ofisine fakslamak","Çevrimiçi MyDMV Portalı CDL tıbbi kendi beyan hizmeti","Sertifikayı bir sosyal medya hesabına göndermek","Bunu güncellemenin bir yolu yoktur; düzenlendikten sonra değiştirilemez"],"explanation":"FLHSMV, sürücülerin kendi beyan kategorisini ve tıbbi bilgilerini gönderebileceği MyDMV Portalı aracılığıyla bir CDL Tıbbi Kendi Beyan hizmeti sunar. Tıbbi muayene memurlarının artık DOT muayene sonuçlarını elektronik olarak iletmeleri de gerekmektedir. Kaynak: FLHSMV, CDL Tıbbi Kendi Beyan (MyDMV Portalı)."},"89":{"q":"İstisnasız bir CDL sürücüsü FLHSMV'de dosyada güncel bir tıbbi sertifikasyon tutmazsa ne olur?","options":["Geçerli tıbbi sertifikasyon restore edilene kadar CDL ayrıcalığı düşürülebilir veya diskalifiye edilebilir","Hiçbir şey olmaz; tıbbi sertifika tamamen isteğe bağlıdır","Sürücü otomatik olarak bir hazmat onayı (endorsement) alır","Sürücünün CLP tutma süresi muaf tutulur"],"explanation":"İstisnasız bir sürücünün tıbbi sertifikasyonu sona ererse, FLHSMV CDL'yi ticari olmayan bir ehliyete düşürebilir veya güncel tıbbi belge sağlanana kadar ticari ayrıcalığı diskalifiye edebilir. Kaynak: FLHSMV, CDL Tıbbi Sertifikasyon sayfası."},"90":{"q":"İlk kez bir Class A veya Class B CDL için test edilmeden önce, bir Florida başvuru sahibinin hangi federal eğitim gerekliliğini karşılaması gerekir?","options":["Eyaletle kayıtlı dört yıllık bir çıraklık tamamlamak","Ayrı bir FBI geçmiş soruşturmasını geçmek","CDL beceri testinden önce FMCSA Eğitim Sağlayıcı Kayıt Defterinde (Training Provider Registry) listelenen bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimini (ELDT) tamamlamak","On yıl boyunca kısıtlamasız bir Class E ehliyeti tutmak"],"explanation":"7 Şubat 2022'de veya sonrasında alınan ticari öğrenci belgeleri (CLP) için, ilk kez Class A/B CDL başvuru sahipleri, CDL beceri testini almadan önce FMCSA Eğitim Sağlayıcı Kayıt Defterinde listelenen bir sağlayıcıdan ELDT'yi tamamlamalıdır. Kaynak: FMCSA Giriş Seviyesi Sürücü Eğitimi; FLHSMV Ticari Sürücü Ehliyeti sayfası."},"91":{"q":"Bu onay (endorsement) başvurularından hangisi, test edilmeden önce ELDT (Giriş Seviyesi Sürücü Eğitimi) gerekliliğini de tetikler?","options":["İlk kez tehlikeli madde (H), yolcu (P) veya okul otobüsü (S) onayı","Mevcut bir kombinasyon araç ayrıcalığını yenilemek","Bir Class E ehliyetine motosiklet onayı eklemek","Kaybolmuş bir CDL'yi aynı onaylarla değiştirmek"],"explanation":"ELDT, ilk kez Class A/B CDL başvuru sahiplerine ve Class B'den Class A'ya yükseltmelere ek olarak, ilk kez tehlikeli madde (H), yolcu (P) veya okul otobüsü (S) onayı isteyen başvuru sahipleri için gereklidir. Kaynak: FMCSA Giriş Seviyesi Sürücü Eğitimi; FLHSMV."},"92":{"q":"Bir başvuru sahibi ELDT'yi tamamladıktan sonra, FLHSMV eğitimin bittiğini nasıl öğrenir?","options":["Başvuru sahibi doğrudan Valilik ofisine bir kağıt diploma postalar","FLHSMV, sürücünün eğitim aldığı kamyonu fiziksel olarak denetler","Eğitim sağlayıcı, sertifikasyonu, eyaletin test öncesi kontrol ettiği FMCSA Eğitim Sağlayıcı Kayıt Defterine sunar","Hiçbir doğrulama yapılmaz; başvuru sahibi yalnızca tamamlandığını beyan eder"],"explanation":"Eğitim sağlayıcı, sürücünün ELDT tamamlamasını elektronik olarak FMCSA Eğitim Sağlayıcı Kayıt Defterine sunar ve eyalet, beceri (veya H için bilgi) testine izin vermeden önce kaydı doğrular. Kaynak: FMCSA Eğitim Sağlayıcı Kayıt Defteri."},"93":{"q":"Bir kişinin Florida CDL yolunda tipik olarak edindiği, ticari bir araç kullanma pratiği yapmasına olanak tanıyan ilk belge nedir?","options":["Hemen verilen tam kısıtlamasız bir CDL","Bir tehlikeli madde onay kartı","Bir DOT tıbbi muayene memuru sertifikası","Bir Ticari Öğrenci Belgesi (CLP)"],"explanation":"Başvuru sahipleri önce gerekli bilgi testlerini geçerek bir Ticari Öğrenci Belgesi (CLP) edinir; CLP, beceri testini almadan önce nitelikli bir CDL sahibiyle birlikte kamu yollarında pratik yapmalarına olanak tanır. Kaynak: FLHSMV, Ticari Sürücü Ehliyeti sayfası."},"94":{"q":"Florida'nın izlediği federal kurallara göre, bir sürücünün CDL beceri testini almadan önce bir CLP tutması gereken asgari süre nedir?","options":["En az 90 gün","Asgari bir bekleme süresi yoktur","En az 14 gün","En az tam bir yıl"],"explanation":"Federal düzenleme, bir CLP sahibinin CDL beceri testini almadan önce CLP verildikten sonra asgari 14 gün beklemesini gerektirir. Kaynak: FMCSA 49 CFR 383.25; FLHSMV CDL süreci."},"95":{"q":"Bir Ticari Öğrenci Belgesi, yeni bir başvuru gerekmeden önce ne kadar süre geçerli kalabilir?","options":["Düzenleme tarihinden itibaren bir yıla kadar, o yıl içinde yenilemeye izin verilir","Bir pasaport gibi on yıla kadar","Düzenlemeden itibaren yalnızca 48 saat","Bir kez düzenlendikten sonra asla sona ermez"],"explanation":"Federal kurallar, bir CLP'nin ilk düzenlemeden itibaren bir yıla kadar geçerli olmasına izin verir; bir yıldan az süreyle düzenlenen bir CLP, toplamda bir yıldan fazla geçerli olmaması şartıyla yenilenebilir. Kaynak: FMCSA 49 CFR 383.25; FLHSMV."},"96":{"q":"Florida CDL beceri testi hangi üç bölümden oluşur?","options":["Yazılı kompozisyon, sözlü mülakat ve bir daktilo testi","Sefer öncesi araç muayenesi, temel araç kontrolü ve yolda sürüş","Görme taraması, işitme testi ve tepki süresi testi","Lastik değişimi, yağ değişimi ve motor yenileme"],"explanation":"CDL beceri testi üç bölümden oluşur: bir sefer öncesi araç muayenesi, bir temel araç kontrol testi ve bir yolda sürüş testi. Kaynak: FLHSMV, Ticari Sürücü Ehliyeti sayfası."},"97":{"q":"Florida CDL beceri testi hangi dilde yapılmalıdır?","options":["Başvuru sahibinin seçtiği herhangi bir dilde","Yalnızca İspanyolca","İngilizce","Herhangi bir konuşulan dilde yapılmaz"],"explanation":"FLHSMV, ticari sürücülerin trafik işaretlerini anlayabilmesi ve İngilizce iletişim kurabilmesi gerektiğine dair federal gerekliliklerle tutarlı olarak, CDL beceri testinin İngilizce yapılmasını gerektirir. Kaynak: FLHSMV, Ticari Sürücü Ehliyeti sayfası."},"98":{"q":"Bir Florida CDL edinmek için asgari yaş nedir ve 21 yaşının altındaki sürücülere hangi kısıtlama uygulanır?","options":["En az 18 yaşında, ancak 21 yaşının altındaki sürücüler genellikle eyalet içi operasyonla kısıtlıdır","En az 16 yaşında, operasyonel kısıtlama olmadan","Herhangi bir CDL sınıfı için en az 25 yaşında","En az 21 yaşında, hiçbir istisnaya izin verilmez"],"explanation":"Florida CDL başvuru sahipleri en az 18 yaşında olmalıdır; 21 yaşının altındakiler 21 yaşına gelene kadar genellikle eyalet içi (Florida içi) ticaretle sınırlıdır. Kaynak: FLHSMV, Ticari Sürücü Ehliyeti sayfası."},"99":{"q":"Bir Florida CDL sahibi ticari sürücü ehliyetini ne sıklıkla yenilemelidir?","options":["Her altı ayda bir","Her yirmi yılda bir","Yalnızca bir kez, çünkü bir CDL asla sona ermez","Her sekiz yılda bir"],"explanation":"CDL'ler dahil Florida sürücü ehliyetleri her sekiz yılda bir yenilenmelidir; CDL'ler yenilenmelidir ve uzatılamaz. Kesin ücretler değişebilir, bu yüzden güncel tutarlar için FLHSMV'yi kontrol edin. Kaynak: FLHSMV, Florida Sürücü Ehliyetinizi Yenileyin veya Değiştirin sayfası."}},"es":{"0":{"q":"En las carreteras de Florida, ¿cuál es el ancho exterior total máximo permitido para un vehículo o su carga (excluyendo los dispositivos de seguridad requeridos) sin un permiso de sobredimensión?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","114 pulgadas (9 pies 6 pulgadas)"],"explanation":"El Estatuto de Florida 316.515 establece el ancho exterior total máximo de cualquier vehículo o su carga en 102 pulgadas (8 pies 6 pulgadas), excluyendo los dispositivos de seguridad. Exceder esto requiere un permiso de sobredimensión del FDOT."},"1":{"q":"¿Cuál es la altura máxima, incluida la carga, para un vehículo en las carreteras de Florida sin un permiso?","options":["13 pies","14 pies","14 pies 6 pulgadas","13 pies 6 pulgadas"],"explanation":"Conforme al Estatuto de Florida 316.515, ningún vehículo puede exceder una altura de 13 pies 6 pulgadas, incluida la carga. (Los transportadores de automóviles tienen permitido hasta 14 pies). La ley de Florida coloca sobre el conductor la responsabilidad de librar las estructuras elevadas."},"2":{"q":"En Florida, ¿cuál es la longitud máxima de un semirremolque que opera en una combinación de tractocamión-semirremolque en el Sistema de Carreteras Estatales (antes de que apliquen las asignaciones especiales de longitud)?","options":["48 pies","45 pies","53 pies","57 pies"],"explanation":"El Estatuto de Florida 316.515 limita un semirremolque en una combinación de tractocamión-semirremolque a 48 pies en dimensión total extrema; los semirremolques de más de 48 pero no más de 57 pies solo pueden operar en vías no restringidas por el FDOT o las autoridades locales."},"3":{"q":"¿Cuál es la longitud máxima de un solo camión rígido en dimensión total extrema conforme a la ley de Florida?","options":["35 pies","45 pies","40 pies","48 pies"],"explanation":"El Estatuto de Florida 316.515 limita un camión rígido (vehículo único) a una longitud de 40 pies en dimensión total extrema."},"4":{"q":"En una combinación de tractocamión-semirremolque-remolque (remolque doble/gemelo) de Florida, ¿cuál es la longitud máxima de cada remolque individual?","options":["24 pies","28 pies","33 pies","40 pies"],"explanation":"El Estatuto de Florida 316.515 dispone que ningún semirremolque o remolque que opere en una combinación de tractocamión-semirremolque-remolque puede exceder una longitud de 28 pies, coincidiendo con el estándar federal para remolques gemelos."},"5":{"q":"¿Cuál es el peso bruto máximo impuesto sobre una carretera de Florida por las ruedas de cualquier eje simple de un vehículo?","options":["18,000 libras","22,400 libras","24,000 libras","20,000 libras"],"explanation":"El Estatuto de Florida 316.535 limita el peso bruto impuesto por las ruedas de cualquier eje simple a 20,000 libras."},"6":{"q":"¿Cuál es el peso bruto total máximo, incluidas todas las tolerancias de aplicación de la ley, para cualquier vehículo o combinación de vehículos en las carreteras de Florida?","options":["73,280 libras","76,000 libras","80,000 libras","88,000 libras"],"explanation":"El Estatuto de Florida 316.535 limita el peso bruto total de cualquier vehículo o combinación de vehículos a 80,000 libras, incluidas todas las tolerancias de aplicación de la ley. Esto coincide con el límite federal para el sistema interestatal."},"7":{"q":"En las carreteras de Florida e interestatales, el peso máximo permitido en un grupo de ejes en tándem (dos ejes consecutivos separados más de 40 pulgadas pero no más de 96 pulgadas) generalmente es:","options":["34,000 libras","30,000 libras","40,000 libras","44,000 libras"],"explanation":"Conforme al estándar federal de peso aplicado en Florida, un grupo de ejes en tándem se limita a 34,000 libras. Florida aplica la Fórmula Federal de Puentes y el límite bruto de 80,000 libras del Estatuto 316.535 en el sistema interestatal."},"8":{"q":"Florida usa la Fórmula Federal de Puentes para limitar el peso según el espaciamiento de los ejes. En la fórmula W = 500[LN/(N-1) + 12N + 36], ¿qué representa la letra 'L'?","options":["El peso legal de la carga en libras","La distancia en pies entre los extremos de un grupo de ejes","La longitud del remolque en pulgadas","El peso bruto autorizado del vehículo"],"explanation":"En la Fórmula Federal de Puentes adoptada en el Estatuto de Florida 316.535, L es la distancia en pies entre los extremos de cualquier grupo de dos o más ejes consecutivos, N es el número de ejes en el grupo y W es el peso bruto permitido."},"9":{"q":"La Fórmula Federal de Puentes utilizada en Florida está diseñada principalmente para proteger ¿qué?","options":["Las llantas del vehículo contra la sobrecarga","Al conductor contra la fatiga","La carga contra el desplazamiento","Los puentes y el pavimento de la calzada contra el peso concentrado"],"explanation":"La Fórmula Federal de Puentes en el Estatuto de Florida 316.535 distribuye el peso sobre una mayor distancia (más ejes, mayor espaciamiento) para proteger los puentes y el pavimento; los ejes muy próximos concentran la carga y deben pesar menos."},"10":{"q":"¿Qué agencia de Florida emite los permisos de sobredimensión y sobrepeso para cargas que exceden los límites legales de tamaño o peso?","options":["Departamento de Seguridad Vial y Vehículos Motorizados de Florida (DHSMV)","Patrulla de Caminos de Florida (FHP)","Departamento de Transporte de Florida (FDOT)","Administración Federal de Seguridad de Autotransportes de EE. UU. (FMCSA)"],"explanation":"El Departamento de Transporte de Florida (FDOT) emite los permisos de sobredimensión/sobrepeso a través de su Oficina de Permisos y su Sistema de Solicitud de Permisos en línea para cargas que exceden los límites de los Estatutos de Florida 316.515 y 316.535."},"11":{"q":"Una carga mide 110 pulgadas de ancho. Antes de transportarla en una carretera de Florida, el conductor debe:","options":["Obtener un permiso de sobredimensión del FDOT","No hacer nada; 110 pulgadas es legal","Solo reducir la velocidad en 10 mph","Obtener aprobación únicamente de la policía local"],"explanation":"Dado que 110 pulgadas excede el límite legal de ancho de 102 pulgadas (8'6\") del Estatuto de Florida 316.515, el traslado requiere un permiso de sobredimensión del FDOT. Las cargas no pueden exceder el ancho legal sin un permiso."},"12":{"q":"¿Qué tipo de permiso del FDOT autoriza un solo traslado de sobredimensión/sobrepeso desde un origen hasta un destino?","options":["Permiso general anual","Permiso de viaje (un solo viaje)","Permiso general específico por ruta","Permiso general específico por vehículo"],"explanation":"El FDOT emite un permiso de viaje (un solo viaje) para un solo traslado; los permisos generales (anuales, específicos por ruta o específicos por vehículo) cubren traslados repetidos durante un período más largo. Los permisos de viaje suelen ser válidos por un número limitado de días para completar el traslado."},"13":{"q":"Conforme a las normas de permisos de Florida/FDOT, ¿a partir de qué ancho una carga sobredimensionada generalmente comienza a requerir al menos un vehículo escolta (piloto)?","options":["Más de 8 pies 6 pulgadas","Más de 10 pies","Más de 12 pies","Más de 16 pies"],"explanation":"Según las normas del FDOT sobre cargas sobredimensionadas, las cargas de más de 12 pies de ancho generalmente requieren al menos un vehículo escolta; las cargas de más de 14 pies normalmente requieren dos escoltas, y las cargas más anchas pueden requerir escolta de las fuerzas del orden."},"14":{"q":"Una carga sobredimensionada que se traslada bajo un permiso del FDOT en Florida generalmente debe exhibir:","options":["Solo los faros encendidos durante el día","Únicamente una placa de permiso verde","Ninguna señalización especial si tiene menos de 12 pies de ancho","Letreros de 'OVERSIZE LOAD' y banderas de advertencia en las esquinas/extremidades"],"explanation":"Las condiciones del permiso del FDOT exigen que las cargas sobredimensionadas exhiban letreros de advertencia 'OVERSIZE LOAD' y banderas de color (rojo/naranja) en las esquinas y los puntos más anchos de la carga para que el resto del tránsito pueda ver la carga de dimensiones excesivas."},"15":{"q":"Según las normas federales de aseguramiento de carga seguidas en Florida, el límite de carga de trabajo (WLL) agregado de los amarres debe ser al menos qué fracción del peso de la carga asegurada?","options":["La mitad (50%)","Una cuarta parte (25%)","Dos tercios (67%)","El peso total (100%)"],"explanation":"Las normas federales de aseguramiento de carga (49 CFR 393.106), que Florida hace cumplir, exigen que el límite de carga de trabajo agregado de todos los amarres sea al menos la mitad (50%) del peso del artículo o carga que se asegura."},"16":{"q":"Conforme a las normas de aseguramiento de carga aplicadas en Florida, un artículo de carga de 5 pies o menos de longitud y que pesa 1,100 libras o menos requiere al menos cuántos amarres?","options":["Dos amarres","Un amarre","Tres amarres","Ningún amarre si está bloqueado"],"explanation":"Conforme al 49 CFR 393.110 (aplicado en Florida), un artículo de 5 pies o menos de longitud y de 1,100 libras o menos requiere un mínimo de un amarre; los artículos más largos o pesados requieren dos o más."},"17":{"q":"Después de cargar y comenzar un viaje, ¿cuándo debe un conductor con CDL de Florida inspeccionar por primera vez la carga y los dispositivos de aseguramiento?","options":["Dentro de las primeras 25 millas","Dentro de las primeras 100 millas","Dentro de las primeras 50 millas","Solo en el destino"],"explanation":"Las normas federales seguidas en Florida (49 CFR 392.9) exigen que el conductor inspeccione la carga y los dispositivos de aseguramiento dentro de las primeras 50 millas después de comenzar un viaje, y que los reexamine periódicamente a partir de entonces."},"18":{"q":"La ley de Florida establece ciertas disposiciones de penalización reducida o de tolerancia sobre los límites de peso principalmente para los transportistas de qué tipo de carga?","options":["Carga general en cajas secas","Materiales peligrosos","Artículos para el hogar","Productos agrícolas naturales y no procesados"],"explanation":"Los estatutos de tránsito y peso de Florida (Capítulo 316) establecen disposiciones especiales de tolerancia/penalización para el transporte de productos agrícolas naturales y no procesados, reconociendo la naturaleza estacional y agrícola de estas cargas."},"19":{"q":"Un conductor que transporta una carga indivisible que mide 14 pies de ancho y pesa 120,000 libras en Florida debe hacer qué antes del traslado?","options":["Obtener un permiso de sobredimensión Y sobrepeso del FDOT","Nada; las cargas indivisibles están exentas","Solo viajar de noche","Reducir la carga a los límites legales aunque no pueda dividirse"],"explanation":"Una carga indivisible que excede tanto el límite de ancho de 102 pulgadas (316.515) como el límite de peso bruto de 80,000 libras (316.535) requiere un permiso de sobredimensión/sobrepeso del FDOT, que también establece las condiciones de ruta, escolta y horario de viaje."},"20":{"q":"En Florida, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una calificación de peso bruto combinado de 26,001 lbs o más, donde la unidad remolcada excede las 10,000 lbs?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Se requiere un CDL Clase A de Florida para operar combinaciones de camión/remolque calificadas en 26,001 lbs o más que remolquen una unidad de más de 10,000 lbs (por ejemplo, tractocamiones). Fuente: página de Licencia de Conducir Comercial del FLHSMV; Manual del CDL de FL."},"21":{"q":"Un conductor de Florida desea operar un solo camión rígido o autobús calificado en 26,001 lbs o más que no remolca un remolque de más de 10,000 lbs. ¿Qué clase de CDL corresponde?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"Un CDL Clase B de Florida cubre camiones rígidos (únicos) y autobuses calificados en 26,001 lbs o más que no remolcan una unidad de más de 10,000 lbs. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"22":{"q":"¿Qué clase de CDL de Florida se requiere para un vehículo más pequeño (que no cumple con el peso de Clase A o B) diseñado para transportar 16 o más personas o que transporta materiales peligrosos con placas (placarded)?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Un CDL Clase C de Florida aplica a vehículos que no cumplen con los estándares de peso de Clase A o B pero que están diseñados para transportar 16 o más personas o que transportan materiales peligrosos con placas. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"23":{"q":"¿Cuál es la edad mínima para obtener un CDL de Florida restringido únicamente a operación intraestatal (dentro de Florida)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Florida permite un CDL a los 18 años, pero los conductores menores de 21 están restringidos a operación intraestatal (dentro del estado). Fuente: página de Licencia de Conducir Comercial del FLHSMV; Estatutos de Florida Cap. 322."},"24":{"q":"Un titular de CDL de Florida de 19 años desea conducir cruzando las líneas estatales (interestatal) o transportar materiales peligrosos. ¿Por qué no puede?","options":["La operación interestatal y el transporte de materiales peligrosos requieren una edad mínima de 21 años","La operación interestatal requiere una edad mínima de 23 años","Primero debe tener un CDL intraestatal durante cinco años","Los conductores menores de 25 años nunca pueden transportar ninguna carga"],"explanation":"Los titulares de CDL de Florida menores de 21 años están limitados a la conducción intraestatal; la operación interestatal y el transporte de materiales peligrosos requieren que el conductor tenga al menos 21 años. Fuente: FLHSMV; federal 49 CFR 391.11."},"25":{"q":"¿Qué endoso necesita un titular de CDL de Florida para transportar cantidades con placas (placarded) de materiales peligrosos?","options":["Endoso N","Endoso T","Endoso P","Endoso H"],"explanation":"El endoso H (HazMat) autoriza el transporte de materiales peligrosos con placas y requiere aprobar el examen de conocimientos de materiales peligrosos. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"26":{"q":"¿Qué endoso se requiere para conducir un vehículo cisterna en Florida?","options":["N (Vehículos Cisterna)","T (Remolques Dobles/Triples)","H (HazMat)","S (Autobús Escolar)"],"explanation":"El endoso N se emite a los conductores que aprueban el examen de conocimientos requerido sobre vehículos cisterna y que operarán vehículos cisterna. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"27":{"q":"Un conductor de Florida planea remolcar combinaciones de tractocamión dobles o triples. ¿Qué endoso se requiere?","options":["P (Pasajeros)","T (Remolques Dobles/Triples)","N (Vehículos Cisterna)","H (HazMat)"],"explanation":"El endoso T, obtenido al aprobar el examen de conocimientos requerido, permite la operación de combinaciones de remolques dobles y triples. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"28":{"q":"¿Qué endoso requiere Florida para conducir un vehículo diseñado para transportar 16 o más personas (más de 15 pasajeros incluido el conductor)?","options":["S (Autobús Escolar)","P (Pasajeros)","N (Vehículos Cisterna)","T (Remolques Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) requiere aprobar los exámenes de conocimientos y de habilidades, y es necesario para vehículos de pasajeros diseñados para más de 15 personas incluido el conductor. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"29":{"q":"Para obtener el endoso de Autobús Escolar (S) de Florida, ¿qué endoso adicional debe tener también el conductor?","options":["El endoso H (HazMat)","El endoso N (Cisterna)","El endoso P (Pasajeros)","El endoso T (Dobles/Triples)"],"explanation":"Florida requiere el endoso P (Pasajeros) además del endoso S (Autobús Escolar); el endoso S requiere aprobar sus propios exámenes de conocimientos y de habilidades. Fuente: página de Licencia de Conducir Comercial del FLHSMV."},"30":{"q":"¿Qué endoso de CDL de Florida requiere una evaluación federal de amenaza a la seguridad de la TSA, que incluye toma de huellas dactilares y una verificación nacional de antecedentes, antes de poder emitirse?","options":["P (Pasajeros)","T (Remolques Dobles/Triples)","N (Vehículos Cisterna)","H (HazMat)"],"explanation":"Conforme a la Ley USA PATRIOT, el endoso H (HazMat) requiere que los solicitantes se tomen las huellas dactilares y aprueben una verificación de antecedentes de la TSA antes de su emisión; aplica una tarifa adicional. Fuente: página de Licencia de Conducir Comercial del FLHSMV; TSA."},"31":{"q":"¿Cuánto tiempo debe un conductor mantener un Permiso de Aprendizaje Comercial (CLP) de Florida antes de que se le permita tomar el examen de habilidades (de conducción) del CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Las normas federales adoptadas por Florida requieren mantener el CLP durante un mínimo de 14 días antes de tomar el examen de habilidades del CDL. Fuente: FLHSMV; 49 CFR 383.25."},"32":{"q":"Mientras practica con un CLP de Florida, ¿quién debe acompañar al titular del permiso en el vehículo comercial?","options":["Cualquier conductor con licencia de 21 años o más","Un titular de un CDL válido con la clase y los endosos apropiados, sentado junto a o cerca del conductor","Únicamente un instructor de CDL certificado, en una pista cerrada","No se requiere supervisor una vez aprobado el examen de conocimientos"],"explanation":"Un titular de CLP debe ir acompañado por un titular de CDL válido con el grupo y los endosos apropiados, físicamente presente al lado (o, para autobuses, justo detrás) del conductor bajo supervisión directa. Fuente: FLHSMV; 49 CFR 383.25."},"33":{"q":"¿Qué restricción de pasajeros aplica a un titular de CLP de Florida que opera un vehículo comercial?","options":["Pueden llevar hasta 8 pasajeros con fines de capacitación","Pueden llevar pasajeros solo durante las horas de luz del día","No pueden llevar pasajeros que no sean el titular de CDL supervisor","Pueden llevar pasajeros si todos usan cinturón de seguridad"],"explanation":"Un titular de CLP no puede operar un autobús o vehículo ocupado por pasajeros que no sean el titular de CDL/mentor acompañante válido. Fuente: FLHSMV; 49 CFR 383.25."},"34":{"q":"Si un solicitante de CDL de Florida no toma y aprueba el examen de conocimientos de frenos de aire, ¿qué sucede con su licencia?","options":["Se agrega una restricción 'L' que prohíbe vehículos con frenos de aire","Se agrega una restricción 'K' que los limita a la conducción intraestatal","El CDL se degrada automáticamente a una Clase C","No se puede emitir ningún CDL hasta que se apruebe el examen de frenos de aire"],"explanation":"No aprobar u omitir el examen de frenos de aire resulta en una restricción 'L', que prohíbe al conductor operar vehículos comerciales equipados con frenos de aire. Fuente: FLHSMV; Manual del CDL de FL."},"35":{"q":"Conforme a las normas federales de Capacitación de Conductores de Nivel Inicial (ELDT) adoptadas en Florida, ¿qué solicitantes deben completar la ELDT antes de presentar el examen?","options":["Solo los conductores que ya tienen un CDL de otro estado","Solicitantes de CDL por primera vez, actualizaciones de Clase B a A y quienes buscan por primera vez un endoso H, P o S","Solo los conductores que buscan el endoso N o T","Solo los conductores mayores de 21 años"],"explanation":"La ELDT es requerida para solicitantes de CDL por primera vez, actualizaciones de Clase B a Clase A y endosos de HazMat, Pasajeros o Autobús Escolar por primera vez (para CLP obtenidos en o después del 7 de febrero de 2022). Fuente: norma ELDT de la FMCSA; FLHSMV."},"36":{"q":"¿Dónde debe estar registrado un proveedor de capacitación ELDT de Florida para que la capacitación de un conductor cuente para la elegibilidad del CDL?","options":["En el Registro de Proveedores de Capacitación de la FMCSA","Únicamente en la lista de escuelas aprobadas del FLHSMV","En el registro de proveedores de la TSA","En cualquier lista de colegios comunitarios estatales"],"explanation":"La capacitación teórica y práctica (detrás del volante) de la ELDT debe ser impartida por un proveedor registrado en el Registro de Proveedores de Capacitación (TPR) de la FMCSA, que envía la finalización electrónicamente. Fuente: Registro de Proveedores de Capacitación de la FMCSA; FLHSMV."},"37":{"q":"Para el endoso de HazMat (H) específicamente, ¿qué paso de la ELDT debe completar un solicitante de Florida?","options":["Capacitación práctica en pista (detrás del volante) antes del examen de manejo","La parte teórica (de conocimientos) de la ELDT antes de tomar el examen de conocimientos de HazMat","Un examen completo de habilidades en un vehículo cisterna","Nunca se requiere ELDT para HazMat"],"explanation":"Los solicitantes de HazMat deben completar la parte teórica de la ELDT a través de un proveedor registrado antes de tomar el examen de conocimientos de HazMat. Fuente: norma ELDT de la FMCSA; FLHSMV."},"38":{"q":"Un conductor con CDL de Florida que opera cruzando las líneas estatales y que está obligado a mantener un certificado médico federal se autocertificaría bajo qué categoría?","options":["Interestatal Exceptuado (EI)","Intraestatal Exceptuado (EA)","Intraestatal No Exceptuado (NA)","Interestatal No Exceptuado (NI)"],"explanation":"Interestatal No Exceptuado (NI) aplica a conductores en el comercio interestatal que deben tener un certificado de examinador médico válido de un examinador del Registro Nacional de la FMCSA. Fuente: autocertificación del FLHSMV; FMCSA 49 CFR 383.71."},"39":{"q":"¿Qué documento acepta Florida como prueba primaria de identidad para una solicitud de CDL conforme con REAL ID?","options":["Un acta de nacimiento certificada de EE. UU. o un pasaporte de EE. UU. válido","Una factura de servicios públicos vigente a nombre del solicitante","Una tarjeta de registro de votante de Florida","Una credencial con foto emitida por el empleador"],"explanation":"Para un CDL conforme con REAL ID, Florida requiere un documento primario de identidad como un acta de nacimiento certificada de EE. UU. o un pasaporte/tarjeta de pasaporte de EE. UU. válido, además de la prueba del número de Seguro Social y dos pruebas del domicilio residencial. Fuente: Qué Traer / REAL ID del FLHSMV."},"40":{"q":"En Florida, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que un titular de CDL puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.08 por ciento","0.02 por ciento","0.10 por ciento","0.04 por ciento"],"explanation":"Es ilegal operar un CMV en Florida si su BAC es de 0.04 por ciento o más, que es la mitad del límite de 0.08 que aplica a los conductores no comerciales. Fuente: Manual del CDL de Florida (FLHSMV), Descalificaciones del Conductor; 49 CFR 383.51."},"41":{"q":"Conforme a la ley de consentimiento implícito de Florida, ¿qué sucede en el momento en que una persona opera un vehículo motorizado comercial en el estado?","options":["Debe portar un permiso separado de prueba de aliento en todo momento","Se considera que ha dado su consentimiento para la prueba de alcohol","Renuncia por completo al derecho a una audiencia de CDL","Está exenta de pruebas a menos que ocurra un accidente"],"explanation":"Al operar un CMV en Florida, se considera que un conductor ha dado su consentimiento para la prueba de alcohol. Negarse a la prueba conlleva la misma descalificación que una condena por DUI. Fuente: Manual del CDL de Florida (FLHSMV); Estatutos de Florida Cap. 322 (consentimiento implícito)."},"42":{"q":"Un titular de CDL es condenado por una primera ofensa mayor, como un DUI, mientras NO transporta materiales peligrosos. ¿Cuál es el período mínimo de descalificación del CDL en Florida?","options":["60 días","3 años","1 año","De por vida"],"explanation":"Una primera ofensa mayor (DUI, BAC de 0.04 o más en un CMV, negarse a una prueba, abandonar el lugar de un accidente o usar un vehículo para cometer un delito grave) resulta en una descalificación del CDL de al menos 1 año. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"43":{"q":"Si una primera ofensa mayor ocurre mientras un conductor con CDL opera un CMV con placas (placarded) de materiales peligrosos, ¿cuál es el período mínimo de descalificación en Florida?","options":["3 años","1 año","120 días","De por vida"],"explanation":"Una primera ofensa mayor cometida mientras se opera un CMV con placas de materiales peligrosos eleva la descalificación mínima de 1 año a al menos 3 años. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"44":{"q":"¿Cuál es la consecuencia en Florida para un titular de CDL que es condenado por una SEGUNDA ofensa mayor en cualquier momento durante su carrera como conductor?","options":["Una descalificación de 3 años","Pérdida del CDL de por vida","Una descalificación de 1 año","Una descalificación de 120 días"],"explanation":"Una segunda ofensa mayor resulta en una descalificación del CDL de por vida. Florida puede permitir la consideración de la reinstauración después de un período mínimo bajo circunstancias limitadas, pero la regla es una prohibición de por vida. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"45":{"q":"A un conductor con CDL en Florida se le solicita legalmente que se someta a una prueba de alcohol en sangre y se niega. ¿Cómo se trata esto a efectos de descalificación del CDL?","options":["Es solo una infracción grave, descalifica por 60 días","Es una ofensa mayor, descalifica por al menos 1 año","No conlleva ninguna penalización al CDL si el conductor estaba fuera de servicio","Resulta solo en una orden de fuera de servicio de 24 horas"],"explanation":"Negarse a someterse a la prueba de alcohol se trata como una ofensa mayor, conllevando la misma descalificación mínima de 1 año (3 años si lleva placas de HazMat) que una condena por DUI. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"46":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Florida?","options":["Conducir con un BAC de 0.04 por ciento en un CMV","Negarse a una prueba de alcohol legal","Operar un CMV bajo una orden de fuera de servicio","Exceso de velocidad, 15 mph o más por encima del límite señalizado"],"explanation":"El exceso de velocidad (15 mph o más por encima del límite) es una infracción de tránsito grave. Las demás opciones son ofensas mayores o infracciones de fuera de servicio, que conllevan penalizaciones diferentes y más severas. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"47":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años activarán una descalificación del CDL en Florida, y por cuánto tiempo para la segunda?","options":["2 infracciones resultan en una descalificación de al menos 120 días","3 infracciones resultan en una descalificación de al menos 60 días","2 infracciones resultan en una descalificación de al menos 60 días","2 infracciones resultan en una descalificación de al menos 1 año"],"explanation":"Una segunda infracción de tránsito grave dentro de un período de 3 años resulta en una descalificación de al menos 60 días. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"48":{"q":"¿Cuál es la descalificación mínima del CDL en Florida por una TERCERA infracción de tránsito grave cometida dentro de un período de 3 años?","options":["60 días","1 año","120 días","30 días"],"explanation":"Una tercera infracción de tránsito grave dentro de un período de 3 años resulta en una descalificación de al menos 120 días. Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"49":{"q":"¿Cuál de las siguientes es una infracción de tránsito grave en lugar de una ofensa mayor para un titular de CDL de Florida?","options":["Cambios de carril indebidos o erráticos","Abandonar el lugar de un accidente","Usar un vehículo para cometer un delito grave","Conducir bajo la influencia de una sustancia controlada"],"explanation":"Los cambios de carril indebidos o erráticos son una infracción de tránsito grave. Las otras tres son ofensas mayores que conllevan una descalificación mínima de 1 año (o de por vida). Fuente: Manual del CDL de Florida (FLHSMV); 49 CFR 383.51."},"50":{"q":"Según las normas CDL de Florida y federales, ¿cómo se clasifica el enviar mensajes de texto mientras se conduce un CMV para efectos de descalificación?","options":["Como una infracción mayor con una descalificación de 1 año","Como una infracción de tránsito grave","Como una violación de una orden de fuera de servicio","Como una infracción no relacionada con el CDL sin efecto de descalificación"],"explanation":"Violar la ley que prohíbe enviar mensajes de texto mientras se conduce un CMV es una infracción de tránsito grave. Combinada con otras infracciones graves dentro de un período de 3 años, puede dar lugar a una descalificación de 60 o 120 días. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51 y 392.80."},"51":{"q":"El uso de un teléfono móvil de mano mientras se conduce un CMV está prohibido para los conductores con CDL en Florida. Para efectos de descalificación, esta infracción se trata como:","options":["Una infracción mayor que requiere descalificación de por vida","Una violación de cruce de ferrocarril","Una infracción de tránsito grave","Una violación de una orden de fuera de servicio"],"explanation":"Violar la ley que prohíbe el uso de un teléfono móvil de mano mientras se conduce un CMV es una infracción de tránsito grave; las infracciones graves repetidas dentro de un período de 3 años dan lugar a descalificaciones de 60 o 120 días. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51 y 392.82."},"52":{"q":"¿Cuál es la descalificación mínima del CDL por una PRIMERA condena por una violación en un cruce a nivel entre ferrocarril y carretera en Florida?","options":["120 días","60 días","1 año","30 días"],"explanation":"Una primera violación en un cruce a nivel entre ferrocarril y carretera resulta en una descalificación de al menos 60 días. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"53":{"q":"Un titular de un CDL de Florida comete una SEGUNDA violación en un cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años. ¿Cuál es la descalificación mínima?","options":["60 días","1 año","180 días","120 días"],"explanation":"Una segunda violación en un cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de al menos 120 días. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"54":{"q":"¿Cuál es la descalificación mínima del CDL por una TERCERA violación en un cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años en Florida?","options":["120 días","60 días","1 año","De por vida"],"explanation":"Una tercera violación en un cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de al menos 1 año. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"55":{"q":"Un conductor con CDL de Florida viola una orden de fuera de servicio por PRIMERA vez sin transportar materiales peligrosos ni pasajeros. ¿Cuál es la descalificación mínima?","options":["180 días","60 días","90 días","120 días"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de al menos 180 días (más prolongada si se transportan HazMat o pasajeros). Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"56":{"q":"¿Cuál es la descalificación mínima del CDL por una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 años en Florida?","options":["180 días","1 año","3 años","2 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de al menos 2 años. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"57":{"q":"Un conductor con CDL de Florida comete una TERCERA violación, o una posterior, de una orden de fuera de servicio dentro de un período de 10 años. ¿Cuál es la descalificación mínima?","options":["3 años","2 años","1 año","180 días"],"explanation":"Una tercera violación, o una posterior, de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de al menos 3 años. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"58":{"q":"Si se determina que un conductor con CDL en Florida tiene CUALQUIER cantidad detectable de alcohol mientras está en servicio (por debajo de 0.04 BAC), ¿cuál es la consecuencia inmediata?","options":["Puesto fuera de servicio por 24 horas","Pérdida permanente del CDL","Una descalificación de 60 días","Una descalificación obligatoria de 1 año"],"explanation":"Un conductor con cualquier cantidad detectable de alcohol por debajo de 0.04 es puesto fuera de servicio por 24 horas. Un BAC de 0.04 o superior es una infracción mayor que descalifica al conductor por al menos 1 año. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 392.5 y 383.51."},"59":{"q":"¿Qué infracción resulta en una descalificación OBLIGATORIA del CDL de por vida sin posibilidad de reinstalación en Florida?","options":["Una primera condena por DUI en un CMV","Dos infracciones de tránsito graves dentro de un período de 3 años","Una primera violación de cruce de ferrocarril","Usar un CMV para fabricar, distribuir o dispensar una sustancia controlada"],"explanation":"Usar un CMV en la comisión de un delito grave que implique la fabricación, distribución o dispensación de una sustancia controlada conlleva una descalificación obligatoria de por vida sin reinstalación. Fuente: Manual CDL de Florida (FLHSMV); 49 CFR 383.51."},"60":{"q":"Según la Ley Move Over de Florida, usted conduce un tractocamión con remolque en una carretera de varios carriles y se aproxima a una patrulla detenida con las luces de emergencia encendidas. ¿Qué le exige hacer primero la ley?","options":["Detenerse por completo en su carril actual hasta que el vehículo de emergencia se retire","Desocupar el carril más cercano al vehículo de emergencia tan pronto como sea seguro hacerlo","Tocar la bocina para advertir al oficial de su aproximación","Mantener su velocidad pero encender las luces intermitentes de emergencia"],"explanation":"La Ley Move Over de Florida (Fla. Stat. 316.126) exige que los conductores en una vía de varios carriles desocupen el carril más cercano al vehículo de emergencia o de servicio detenido tan pronto como sea seguro; solo si no es posible cambiarse de carril debe disminuir la velocidad."},"61":{"q":"En una vía de dos carriles de Florida con un límite señalizado de 55 mph, usted se aproxima a una grúa detenida que muestra luces ámbar y no puede cambiar de carril con seguridad. ¿A cuántas millas por hora debe reducir su velocidad?","options":["45 mph","25 mph","35 mph","55 mph; no se requiere reducción en una vía de dos carriles"],"explanation":"Según Fla. Stat. 316.126, cuando no puede cambiarse de carril, debe reducir la velocidad a 20 mph por debajo del límite señalizado cuando la velocidad señalizada es de 25 mph o superior. En una vía de 55 mph eso significa 35 mph."},"62":{"q":"La Ley Move Over de Florida exige reducir la velocidad cuando no puede cambiar de carril. En una vía donde el límite de velocidad señalizado es de 20 mph o menos, ¿a qué velocidad debe reducir al pasar junto a un vehículo detenido que califica?","options":["5 mph","10 mph","0 mph (alto total)","15 mph"],"explanation":"Fla. Stat. 316.126 establece que cuando el límite de velocidad señalizado es de 20 mph o menos, el conductor que no puede cambiarse de carril debe reducir la velocidad a 5 mph al pasar junto al vehículo detenido."},"63":{"q":"Además de los vehículos de emergencia, la ley Move Over de Florida (Fla. Stat. 316.126) también protege a ¿cuál de los siguientes vehículos detenidos que muestren las señales apropiadas?","options":["Vehículos de saneamiento, de servicios públicos y de mantenimiento de carreteras o puentes, y vehículos averiados con luces intermitentes de emergencia","Solo vehículos rotulados de las fuerzas del orden y de bomberos","Solo ambulancias y grúas","Cualquier automóvil de pasajeros de propiedad privada estacionado en el acotamiento"],"explanation":"Fla. Stat. 316.126 extiende las protecciones de Move Over a los vehículos de saneamiento, vehículos de servicios públicos, grúas, vehículos de mantenimiento/construcción de carreteras y puentes, y vehículos automotores averiados que muestren luces intermitentes de emergencia, además de los vehículos de emergencia."},"64":{"q":"Usted conduce un autobús que transporta pasajeros y se aproxima a un cruce a nivel de ferrocarril en Florida. ¿A qué distancia del riel más cercano debe detenerse?","options":["Entre 5 y 15 pies","Entre 50 y 100 pies","Entre 15 y 50 pies","Exactamente a 25 pies, ni más cerca ni más lejos"],"explanation":"Los autobuses que transportan pasajeros y los vehículos con materiales peligrosos que requieren letreros (placards) deben detenerse a no menos de 15 pies y a no más de 50 pies del riel más cercano, y luego mirar y escuchar antes de cruzar (Manual CDL de Florida; FMCSR 392.10)."},"65":{"q":"¿Qué vehículo comercial está obligado a hacer un alto obligatorio en cada cruce de ferrocarril en Florida, a menos que aplique una excepción?","options":["Un camión de plataforma vacío sin carga","Un vehículo que transporta cantidades de materiales peligrosos que requieren letreros (placards)","Una camioneta de reparto que transporta carga general","Un camión volquete que transporta arena"],"explanation":"Según las normas federales adoptadas en el Manual CDL de Florida (FMCSR 392.10), los vehículos que deben llevar letreros (placards) por materiales peligrosos, y los autobuses que transportan pasajeros, deben detenerse en los cruces de ferrocarril; los vehículos de carga ordinarios no están obligados a detenerse."},"66":{"q":"¿En cuál cruce de ferrocarril NO está obligado a detenerse un conductor de materiales peligrosos con letreros (placards) o un conductor de autobús?","options":["Un cruce donde una señal de tránsito en funcionamiento muestra verde, o que está marcado con un letrero oficial de Exento (Exempt)","Cualquier cruce en una carretera rural de dos carriles","Un cruce con cruces de San Andrés (crossbucks) pero sin luces intermitentes","Un cruce inmediatamente después del atardecer"],"explanation":"El Manual CDL de Florida (FMCSR 392.10) enumera las excepciones al alto obligatorio: una señal de control de tránsito en verde, un cruce marcado con un letrero oficial de Exento (Exempt), un cruce dirigido por un policía u oficial con banderola, y vías usadas únicamente por tranvías o para maniobras industriales."},"67":{"q":"Al cruzar vías de ferrocarril en un vehículo comercial con transmisión manual, ¿qué debe hacer?","options":["Cambiar a una marcha más alta a mitad del cruce para librar las vías más rápido","Detenerse sobre las vías para revisar los espejos antes de continuar","Poner en neutro y cruzar las vías por inercia","Cruzar en una marcha baja y no cambiar de marcha mientras esté sobre las vías"],"explanation":"El Manual CDL de Florida indica a los conductores que elijan una marcha que permita que el vehículo cruce completamente las vías y que nunca cambien de marcha mientras cruzan, para evitar quedarse parados sobre las vías."},"68":{"q":"En una calle de doble sentido de Florida sin mediana ni barrera, un autobús escolar se detiene con sus luces rojas intermitentes encendidas y el brazo de alto extendido. ¿Qué debe hacer el tránsito que se aproxima desde la dirección opuesta?","options":["Reducir a 10 mph pero puede continuar pasando junto al autobús","Continuar normalmente porque el tránsito en sentido opuesto nunca tiene que detenerse","Detenerse y permanecer detenido hasta que las luces dejen de parpadear y el brazo de alto se retraiga","Detenerse solo si hay niños cruzando la vía de manera visible"],"explanation":"Fla. Stat. 316.172 exige que todo el tránsito, incluido el de sentido opuesto en una vía de doble sentido sin separación, se detenga ante un autobús escolar detenido con luces rojas intermitentes, y permanezca detenido hasta que las luces dejen de parpadear y el brazo de alto se retraiga."},"69":{"q":"Según la ley de Florida, los conductores que viajan en sentido opuesto NO están obligados a detenerse ante un autobús escolar detenido cuando la vía está dividida por ¿cuál de los siguientes elementos?","options":["Una sola línea central amarilla continua","Un carril central pintado de giro a la izquierda en ambos sentidos","Una mediana elevada, una barrera física o un espacio sin pavimentar de al menos 5 pies","Una hilera de marcadores reflectantes de carril"],"explanation":"Fla. Stat. 316.172(2) exime al tránsito de sentido opuesto de detenerse únicamente cuando la carretera dividida separa el tránsito mediante una mediana elevada, una barrera física o un espacio sin pavimentar de al menos 5 pies. Las líneas pintadas por sí solas no califican."},"70":{"q":"Si debe detener su vehículo automotor comercial en el acotamiento de una carretera de un solo sentido o dividida de Florida, ¿dónde debe colocar sus tres dispositivos de advertencia de emergencia?","options":["A 5 pies, 50 pies y 150 pies en dirección al tránsito que se aproxima","Los tres dentro de 10 pies de la parte trasera del vehículo","A 25 pies, 75 pies y 125 pies delante del vehículo","A 10 pies, 100 pies y 200 pies en dirección al tránsito que se aproxima"],"explanation":"El Manual CDL de Florida (FMCSR 392.22) exige colocar los dispositivos de advertencia a 10 pies, 100 pies y 200 pies en dirección al tránsito que se aproxima en una carretera de un solo sentido o dividida."},"71":{"q":"Después de detener su vehículo comercial sobre la parte transitada o el acotamiento de una carretera de Florida, ¿dentro de cuántos segundos debe activar las luces de advertencia de emergencia (intermitentes de cuatro vías)?","options":["Dentro de 30 minutos, solo de noche","Solo después de que ya se hayan colocado los triángulos de advertencia","De inmediato, y colocar los dispositivos de advertencia dentro de 10 minutos","No hay requisito de tiempo para las luces intermitentes de emergencia"],"explanation":"Según FMCSR 392.22, adoptado en el Manual CDL de Florida, un CMV detenido debe encender de inmediato sus luces intermitentes de advertencia de emergencia y colocar los dispositivos de advertencia (triángulos/bengalas) dentro de 10 minutos."},"72":{"q":"En una carretera de Florida de dos carriles que lleva tránsito en ambos sentidos, ¿dónde deben colocarse los triángulos de advertencia cuando su CMV está detenido?","options":["Dentro de 10 pies del vehículo y a 100 pies detrás y delante de él","Solo a 200 pies detrás del vehículo","Solo en el parachoques delantero del vehículo","Solo a 50 pies detrás y 50 pies delante"],"explanation":"El Manual CDL de Florida (FMCSR 392.22) indica que en una vía de dos carriles o sin división debe colocar un dispositivo de advertencia dentro de 10 pies del vehículo y uno a 100 pies detrás y uno a 100 pies delante del vehículo detenido."},"73":{"q":"En una vía de Florida con tres o más carriles en su sentido, la regla general del carril derecho exige que los vehículos que se mueven más lento, incluidos los camiones, hagan qué?","options":["Viajar siempre en el carril central sin importar la velocidad","Usar el carril del extremo izquierdo para mantener despejado el tránsito del carril derecho","Elegir cualquier carril libremente sin restricción","Mantenerse en el carril derecho excepto al rebasar, adelantar o prepararse para un giro a la izquierda"],"explanation":"Fla. Stat. 316.081 exige que todo vehículo que viaje más lento que la velocidad normal del tránsito use el carril derecho (o lo más cerca posible del borde derecho que sea práctico) excepto al rebasar/adelantar o prepararse para un giro a la izquierda."},"74":{"q":"Fuera de los distritos comerciales o residenciales, ¿cuál es el límite de velocidad máximo predeterminado por ley en Florida donde no haya otro límite señalizado?","options":["55 mph","70 mph","65 mph","45 mph"],"explanation":"Fla. Stat. 316.183/316.187 establecen el máximo legal en 55 mph en lugares fuera de distritos comerciales o residenciales a menos que se señalice un límite distinto; 30 mph aplica en distritos comerciales o residenciales."},"75":{"q":"En una autopista interestatal de Florida de al menos cuatro carriles señalizada a 70 mph, ¿cuál es el límite de velocidad mínimo establecido por ley?","options":["40 mph","55 mph","45 mph","50 mph"],"explanation":"Fla. Stat. 316.183 establece una velocidad mínima de 50 mph en autopistas interestatales divididas de al menos cuatro carriles donde el límite máximo señalizado es de 70 mph."},"76":{"q":"Según la ley de conducción distraída de Florida (Fla. Stat. 316.305), ¿qué está prohibido mientras se opera un vehículo automotor en movimiento?","options":["Cualquier uso de un altavoz Bluetooth de manos libres para una llamada telefónica","Escribir manualmente o leer datos para comunicación no verbal, como enviar mensajes de texto, correos electrónicos o mensajería instantánea","Escuchar indicaciones de voz de navegación","Tener un teléfono montado visible en la cabina"],"explanation":"Fla. Stat. 316.305 prohíbe escribir o introducir caracteres manualmente y enviar o leer datos en un dispositivo inalámbrico para comunicación interpersonal no verbal (mensajes de texto, correo electrónico, mensajería instantánea) mientras se conduce."},"77":{"q":"¿Cuál afirmación sobre la aplicación de la ley de mensajes de texto al conducir de Florida (Fla. Stat. 316.305) es correcta?","options":["Es una infracción secundaria que requiere primero otra infracción","Es una infracción primaria, por lo que un oficial puede detener y multar a un conductor únicamente por enviar mensajes de texto","Solo aplica a conductores menores de 18 años","Solo aplica entre el atardecer y el amanecer"],"explanation":"Desde 2019, Fla. Stat. 316.305 convierte el envío de mensajes de texto al conducir en una infracción primaria, lo que autoriza a los oficiales a detener y multar a un conductor solo por esa infracción."},"78":{"q":"Cuando Florida activa el Uso de Acotamiento de Emergencia (Emergency Shoulder Use, ESU) en una ruta de evacuación durante un huracán, ¿qué vehículos NO están autorizados a usar el carril del acotamiento abierto?","options":["Automóviles de pasajeros y camionetas pickup","Camiones grandes, autobuses y remolques","Motocicletas y SUV","Todos los vehículos pueden usar el acotamiento por igual"],"explanation":"Según el plan de Uso de Acotamiento de Emergencia del FDOT de Florida (que reemplazó al contraflujo), todos los automovilistas EXCEPTO los camiones grandes, autobuses y remolques pueden usar el acotamiento pavimentado como carril de circulación temporal durante una evacuación por huracán."},"79":{"q":"En cuanto al ralentí prolongado de vehículos comerciales de servicio pesado, ¿qué afirmación refleja la ley actual de Florida?","options":["Florida prohíbe todo ralentí de camiones de más de 3 minutos en todo el estado","Florida limita el ralentí a 5 minutos en todo el estado en todo momento","Florida exige apagar los motores cada vez que un camión esté estacionado en cualquier lugar del estado","Florida no tiene un límite estatal de reducción de ralentí para vehículos de servicio pesado; su norma de ralentí anterior fue derogada"],"explanation":"La norma de reducción de ralentí para vehículos de servicio pesado de Florida (Fla. Admin. Code 62-285.420) fue derogada, por lo que no existe un límite de tiempo de ralentí en todo el estado; aun así, los conductores deben verificar las ordenanzas locales. Esto difiere de los estados con leyes estatales contra el ralentí."},"80":{"q":"¿Qué agencia emite las licencias de conducir comercial (CDL) en Florida?","options":["El Departamento de Transporte de Florida (FDOT)","El Departamento de Seguridad Vial y Vehículos Automotores de Florida (FLHSMV)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Vehículos Automotores de los Estados Unidos"],"explanation":"En Florida, las CDL son emitidas y administradas por el Departamento de Seguridad Vial y Vehículos Automotores de Florida (FLHSMV). La FMCSA establece los estándares federales, pero la agencia estatal emite la credencial en sí. Fuente: FLHSMV, página de Licencia de Conducir Comercial."},"81":{"q":"Al solicitar una CDL original de Florida o un permiso de aprendiz comercial, ¿qué conjunto de documentos debe presentar el solicitante ante el FLHSMV?","options":["Solo una licencia de conducir Clase E vigente de Florida y una foto","Un pasaporte y una sola factura de servicios públicos, sin documentación del Seguro Social","Solo un certificado de examinador médico del DOT y una tarjeta de huellas dactilares","Comprobante de identidad, comprobante del número de Seguro Social y dos comprobantes de domicilio residencial de Florida"],"explanation":"Según la Ley federal REAL ID, tal como la implementa el FLHSMV, los solicitantes de CDL/CLP originales deben presentar documentos originales que prueben su identidad, su número de Seguro Social y dos comprobantes de domicilio residencial de Florida. Fuente: FLHSMV, páginas What to Bring / Licencia de Conducir Comercial."},"82":{"q":"Las credenciales de CDL y CLP de Florida cumplen con REAL ID. ¿Qué exige la Ley REAL ID a los solicitantes?","options":["Presentar una declaración jurada notarizada en lugar de cualquier documento de identidad","Presentar documentos originales que verifiquen la identidad, el número de Seguro Social y el domicilio residencial","Proporcionar una tarjeta de pasaporte federal como único comprobante aceptable de todos los requisitos","Completar un cuestionario de identidad en línea en lugar de la revisión presencial de documentos"],"explanation":"REAL ID exige que los solicitantes presenten documentos originales que validen la identidad, el número de Seguro Social y el domicilio residencial en la primera emisión en la oficina. Una vez proporcionados, por lo general solo deben mostrarse de nuevo si la información cambia. Fuente: FLHSMV, página REAL ID."},"83":{"q":"¿Cuántos comprobantes de domicilio residencial de Florida debe presentar al FLHSMV un solicitante de CDL o CLP?","options":["No se requiere comprobante de domicilio residencial para una CDL","Cuatro comprobantes de domicilio residencial, todos facturas de servicios públicos","Uno, pero debe ser un pasaporte","Dos comprobantes de domicilio residencial a nombre del solicitante"],"explanation":"El FLHSMV exige que los solicitantes de CLP y CDL presenten dos comprobantes de domicilio residencial de Florida a su nombre (dos de la Lista A, o uno de la Lista A y uno de la Lista B). Fuente: FLHSMV, página What to Bring."},"84":{"q":"Las Normas Federales de Seguridad de Autotransportes exigen que todo conductor que obtenga o renueve una CDL se autocertifique ante el FLHSMV en ¿cuántas categorías de operación?","options":["Dos categorías","Cuatro categorías","Seis categorías","Tres categorías"],"explanation":"Los conductores deben autocertificarse en una de cuatro categorías: interestatal no exenta, interestatal exenta, intraestatal no exenta e intraestatal exenta. Fuente: FLHSMV, página de Certificación Médica de CDL."},"85":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación de CDL utilizadas por el FLHSMV?","options":["Interestatal no exenta","Hazmat federal exenta","Agrícola intraestatal restringida únicamente","Comercio interestatal provisional"],"explanation":"Las cuatro categorías válidas de autocertificación son interestatal no exenta, interestatal exenta, intraestatal no exenta e intraestatal exenta. 'Interestatal no exenta' es la categoría para conductores que deben mantener un certificado médico federal. Fuente: FLHSMV, página de Certificación Médica de CDL."},"86":{"q":"Un conductor con CDL de Florida se autocertifica como 'interestatal no exento'. ¿Qué obligación médica continua crea esto?","options":["Está permanentemente exento de cualquier certificación médica","Solo necesita un examen médico una vez cada quince años","Debe obtener y mantener un certificado de examinador médico del DOT vigente en el expediente del FLHSMV","Debe autocertificarse pero nunca necesita un certificado de examinador médico"],"explanation":"Los conductores que se certifican como interestatales no exentos (o intraestatales no exentos) deben mantener un certificado de examinador médico del DOT vigente y conservarlo actualizado en el expediente del FLHSMV. Fuente: FLHSMV, página de Certificación Médica de CDL."},"87":{"q":"¿Para qué se utiliza el certificado de examinador médico del DOT (a menudo llamado 'tarjeta médica' o 'Med Card') en el proceso de CDL de Florida?","options":["Para probar que el conductor completó la capacitación de conductor de nivel inicial","Para servir como comprobante de residencia en Florida del conductor","Para reemplazar los exámenes de conocimientos y habilidades de los conductores con experiencia","Para documentar que un conductor cumple con los estándares de calificación física para operar un vehículo automotor comercial"],"explanation":"El certificado de examinador médico del DOT documenta que un examinador médico certificado determinó que el conductor está físicamente calificado para operar un vehículo automotor comercial. Es independiente del comprobante de residencia y de los exámenes de conocimientos/habilidades. Fuente: FLHSMV, página de Certificación Médica de CDL."},"88":{"q":"Un titular de CDL interestatal no exento de Florida necesita mantener actualizada su autocertificación e información médica. ¿Cuál es una forma proporcionada por el FLHSMV para administrar esto?","options":["Enviar por fax el certificado únicamente a la oficina nacional de la FMCSA","El servicio en línea de autocertificación médica de CDL del MyDMV Portal","Publicar el certificado en una cuenta de redes sociales","No hay forma de actualizarlo; no se puede cambiar después de la emisión"],"explanation":"El FLHSMV ofrece un servicio de Autocertificación Médica de CDL a través del MyDMV Portal donde los conductores pueden enviar su categoría de autocertificación e información médica. Los examinadores médicos también ahora están obligados a transmitir los resultados de los exámenes del DOT electrónicamente. Fuente: FLHSMV, Autocertificación Médica de CDL (MyDMV Portal)."},"89":{"q":"¿Qué sucede si un conductor con CDL no exento no mantiene una certificación médica vigente en el expediente del FLHSMV?","options":["El privilegio de CDL puede ser degradado o descalificado hasta que se restablezca una certificación médica válida","No pasa nada; el certificado médico es totalmente opcional","El conductor recibe automáticamente un endoso de hazmat","Se exime al conductor del período de tenencia del CLP"],"explanation":"Si la certificación médica de un conductor no exento caduca, el FLHSMV puede degradar la CDL a una licencia no comercial o descalificar el privilegio comercial hasta que se proporcione documentación médica vigente. Fuente: FLHSMV, página de Certificación Médica de CDL."},"90":{"q":"Antes de realizar el examen para una CDL Clase A o Clase B por primera vez, ¿qué requisito federal de capacitación debe cumplir un solicitante de Florida?","options":["Completar un aprendizaje de cuatro años registrado ante el estado","Aprobar una investigación de antecedentes del FBI por separado","Completar la Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor listado en el Registro de Proveedores de Capacitación de la FMCSA","Tener una licencia Clase E sin restricciones durante diez años"],"explanation":"Para los permisos de aprendiz comercial obtenidos a partir del 7 de febrero de 2022, los solicitantes de CDL Clase A/B por primera vez deben completar la ELDT de un proveedor listado en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar el examen de habilidades de CDL. Fuente: Capacitación de Conductor de Nivel Inicial de la FMCSA; página de Licencia de Conducir Comercial del FLHSMV."},"91":{"q":"¿Cuál de estas solicitudes de endoso también activa el requisito de ELDT (Capacitación de Conductor de Nivel Inicial) antes del examen?","options":["Endoso de materiales peligrosos (H), de pasajeros (P) o de autobús escolar (S) por primera vez","Renovar un privilegio existente de vehículo combinado","Agregar un endoso de motocicleta a una licencia Clase E","Reemplazar una CDL perdida con los mismos endosos"],"explanation":"La ELDT es requerida para los solicitantes por primera vez que buscan un endoso de materiales peligrosos (H), de pasajeros (P) o de autobús escolar (S), además de los solicitantes de CDL Clase A/B por primera vez y los ascensos de Clase B a Clase A. Fuente: Capacitación de Conductor de Nivel Inicial de la FMCSA; FLHSMV."},"92":{"q":"Después de que un solicitante completa la ELDT, ¿cómo se entera el FLHSMV de que la capacitación se finalizó?","options":["El solicitante envía por correo un diploma en papel directamente a la oficina del Gobernador","El FLHSMV inspecciona físicamente el camión en el que se capacitó el conductor","El proveedor de capacitación envía la certificación al Registro de Proveedores de Capacitación de la FMCSA, que el estado verifica antes del examen","No ocurre ninguna verificación; el solicitante simplemente declara que la completó"],"explanation":"El proveedor de capacitación envía electrónicamente la finalización de la ELDT del conductor al Registro de Proveedores de Capacitación de la FMCSA, y el estado verifica el registro antes de permitir el examen de habilidades (o, para H, el examen de conocimientos). Fuente: Registro de Proveedores de Capacitación de la FMCSA."},"93":{"q":"¿Cuál es la primera credencial que una persona obtiene normalmente en el camino hacia una CDL de Florida, que le permite practicar la conducción de un vehículo comercial?","options":["Una CDL completa sin restricciones emitida de inmediato","Una tarjeta de endoso de materiales peligrosos","Un certificado de examinador médico del DOT","Un Permiso de Aprendiz Comercial (CLP)"],"explanation":"Los solicitantes primero obtienen un Permiso de Aprendiz Comercial (CLP) aprobando los exámenes de conocimientos requeridos; el CLP les permite practicar en vías públicas con un titular de CDL calificado antes de presentar el examen de habilidades. Fuente: FLHSMV, página de Licencia de Conducir Comercial."},"94":{"q":"Según las normas federales que sigue Florida, ¿cuál es el tiempo mínimo que un conductor debe tener un CLP antes de presentar el examen de habilidades de CDL?","options":["Al menos 90 días","No hay período mínimo de espera","Al menos 14 días","Al menos un año completo"],"explanation":"La regulación federal exige que un titular de CLP espere un mínimo de 14 días después de la emisión del CLP antes de presentar el examen de habilidades de CDL. Fuente: FMCSA 49 CFR 383.25; proceso de CDL del FLHSMV."},"95":{"q":"¿Por cuánto tiempo puede permanecer válido un Permiso de Aprendiz Comercial antes de que se requiera una nueva solicitud?","options":["Hasta un año desde la fecha de emisión, con renovación permitida dentro de ese año","Hasta diez años, como un pasaporte","Solo 48 horas desde la emisión","Nunca caduca una vez emitido"],"explanation":"Las normas federales permiten que un CLP sea válido hasta un año desde su emisión inicial; un CLP emitido por menos de un año puede renovarse siempre que no sea válido por más de un año en total. Fuente: FMCSA 49 CFR 383.25; FLHSMV."},"96":{"q":"¿De qué tres partes se compone el examen de habilidades de CDL de Florida?","options":["Ensayo escrito, entrevista oral y un examen de mecanografía","Inspección del vehículo previa al viaje, control básico del vehículo y conducción en carretera","Examen de la vista, examen de audición y examen de tiempo de reacción","Cambio de llanta, cambio de aceite y reconstrucción del motor"],"explanation":"El examen de habilidades de CDL consta de tres partes: una inspección del vehículo previa al viaje, un examen de control básico del vehículo y un examen de conducción en carretera. Fuente: FLHSMV, página de Licencia de Conducir Comercial."},"97":{"q":"¿En qué idioma debe realizarse el examen de habilidades de CDL de Florida?","options":["Cualquier idioma que el solicitante elija","Solo español","Inglés","No se realiza en ningún idioma hablado"],"explanation":"El FLHSMV exige que el examen de habilidades de CDL se realice en inglés, en consonancia con los requisitos federales de que los conductores comerciales puedan entender las señales de tránsito y comunicarse en inglés. Fuente: FLHSMV, página de Licencia de Conducir Comercial."},"98":{"q":"¿Cuál es la edad mínima para obtener una CDL de Florida, y qué restricción aplica a los conductores menores de 21 años?","options":["Al menos 18 años, pero los conductores menores de 21 años generalmente están restringidos a la operación intraestatal","Al menos 16 años, sin restricciones operativas","Al menos 25 años para cualquier clase de CDL","Al menos 21 años, sin excepciones permitidas"],"explanation":"Los solicitantes de CDL de Florida deben tener al menos 18 años; quienes son menores de 21 años generalmente están limitados al comercio intraestatal (dentro de Florida) hasta que cumplan 21 años. Fuente: FLHSMV, página de Licencia de Conducir Comercial."},"99":{"q":"¿Con qué frecuencia debe un titular de CDL de Florida renovar su licencia de conducir comercial?","options":["Cada seis meses","Cada veinte años","Solo una vez, porque una CDL nunca caduca","Cada ocho años"],"explanation":"Las licencias de conducir de Florida, incluidas las CDL, deben renovarse cada ocho años; las CDL deben renovarse y no pueden extenderse. Las tarifas exactas pueden cambiar, así que consulte el FLHSMV para los montos vigentes. Fuente: FLHSMV, página Renew or Replace Your Florida Driver License."}},"hi":{"0":{"q":"फ्लोरिडा के राजमार्गों पर, ओवरसाइज़ परमिट के बिना किसी वाहन या उसके लोड (आवश्यक सुरक्षा उपकरणों को छोड़कर) की अधिकतम कुल बाहरी चौड़ाई कितनी अनुमत है?","options":["96 इंच (8 फ़ुट)","102 इंच (8 फ़ुट 6 इंच)","108 इंच (9 फ़ुट)","114 इंच (9 फ़ुट 6 इंच)"],"explanation":"फ्लोरिडा क़ानून 316.515 किसी भी वाहन या उसके लोड की अधिकतम कुल बाहरी चौड़ाई 102 इंच (8 फ़ुट 6 इंच) निर्धारित करता है, सुरक्षा उपकरणों को छोड़कर। इससे अधिक होने पर FDOT ओवरसाइज़ परमिट की आवश्यकता होती है।"},"1":{"q":"फ्लोरिडा के राजमार्गों पर परमिट के बिना किसी वाहन की अधिकतम ऊँचाई, लोड सहित, कितनी होती है?","options":["13 फ़ुट","14 फ़ुट","14 फ़ुट 6 इंच","13 फ़ुट 6 इंच"],"explanation":"फ्लोरिडा क़ानून 316.515 के अंतर्गत, कोई भी वाहन 13 फ़ुट 6 इंच की ऊँचाई से अधिक नहीं हो सकता, लोड सहित। (ऑटोमोबाइल ट्रांसपोर्टर को 14 फ़ुट तक की अनुमति है।) फ्लोरिडा क़ानून ऊपरी संरचनाओं को साफ़ रखने की ज़िम्मेदारी चालक पर रखता है।"},"2":{"q":"फ्लोरिडा में, स्टेट हाईवे सिस्टम पर ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में संचालित होने वाले सेमीट्रेलर की अधिकतम लंबाई कितनी होती है (विशेष लंबाई भत्ते लागू होने से पहले)?","options":["48 फ़ुट","45 फ़ुट","53 फ़ुट","57 फ़ुट"],"explanation":"फ्लोरिडा क़ानून 316.515 ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर को अत्यधिक कुल आयाम में 48 फ़ुट तक सीमित करता है; 48 फ़ुट से अधिक लेकिन 57 फ़ुट से अधिक नहीं वाले सेमीट्रेलर केवल उन सड़कों पर संचालित हो सकते हैं जो FDOT या स्थानीय प्राधिकरणों द्वारा प्रतिबंधित नहीं हैं।"},"3":{"q":"फ्लोरिडा क़ानून के अंतर्गत किसी एकल सीधे ट्रक की अत्यधिक कुल आयाम में अधिकतम लंबाई कितनी होती है?","options":["35 फ़ुट","45 फ़ुट","40 फ़ुट","48 फ़ुट"],"explanation":"फ्लोरिडा क़ानून 316.515 एक सीधे ट्रक (एकल वाहन) को अत्यधिक कुल आयाम में 40 फ़ुट की लंबाई तक सीमित करता है।"},"4":{"q":"फ्लोरिडा ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर (डबल/ट्विन ट्रेलर) संयोजन में, प्रत्येक व्यक्तिगत ट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["24 फ़ुट","28 फ़ुट","33 फ़ुट","40 फ़ुट"],"explanation":"फ्लोरिडा क़ानून 316.515 यह प्रावधान करता है कि ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर संयोजन में संचालित कोई भी सेमीट्रेलर या ट्रेलर 28 फ़ुट की लंबाई से अधिक नहीं हो सकता, जो ट्विन ट्रेलरों के लिए संघीय मानक से मेल खाता है।"},"5":{"q":"फ्लोरिडा के राजमार्ग पर किसी वाहन के किसी एक सिंगल एक्सल के पहियों द्वारा लगाया गया अधिकतम सकल भार कितना होता है?","options":["18,000 पाउंड","22,400 पाउंड","24,000 पाउंड","20,000 पाउंड"],"explanation":"फ्लोरिडा क़ानून 316.535 किसी एक सिंगल एक्सल के पहियों द्वारा लगाए गए सकल भार को 20,000 पाउंड तक सीमित करता है।"},"6":{"q":"फ्लोरिडा के राजमार्गों पर किसी भी वाहन या वाहनों के संयोजन के लिए, सभी प्रवर्तन सहनशीलताओं सहित, अधिकतम कुल सकल भार कितना होता है?","options":["73,280 पाउंड","76,000 पाउंड","80,000 पाउंड","88,000 पाउंड"],"explanation":"फ्लोरिडा क़ानून 316.535 किसी भी वाहन या वाहनों के संयोजन के कुल सकल भार को 80,000 पाउंड तक सीमित करता है, सभी प्रवर्तन सहनशीलताओं सहित। यह इंटरस्टेट सिस्टम के लिए संघीय सीमा से मेल खाता है।"},"7":{"q":"फ्लोरिडा और इंटरस्टेट राजमार्गों पर, एक टैंडम एक्सल समूह (दो लगातार एक्सल जो 40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं की दूरी पर हों) पर अनुमत अधिकतम भार आमतौर पर कितना होता है:","options":["34,000 पाउंड","30,000 पाउंड","40,000 पाउंड","44,000 पाउंड"],"explanation":"फ्लोरिडा में लागू संघीय भार मानक के अंतर्गत, एक टैंडम एक्सल समूह 34,000 पाउंड तक सीमित है। फ्लोरिडा इंटरस्टेट सिस्टम पर फ़ेडरल ब्रिज फ़ॉर्मूला और क़ानून 316.535 की 80,000 पाउंड सकल सीमा लागू करता है।"},"8":{"q":"फ्लोरिडा एक्सल दूरी के आधार पर भार सीमित करने के लिए फ़ेडरल ब्रिज फ़ॉर्मूला का उपयोग करता है। फ़ॉर्मूला W = 500[LN/(N-1) + 12N + 36] में, अक्षर 'L' क्या दर्शाता है?","options":["पाउंड में क़ानूनी लोड भार","एक्सल के समूह के सिरों के बीच फ़ुट में दूरी","ट्रेलर की लंबाई इंच में","वाहन का लाइसेंसीकृत सकल भार"],"explanation":"फ्लोरिडा क़ानून 316.535 में अपनाए गए फ़ेडरल ब्रिज फ़ॉर्मूला में, L दो या अधिक लगातार एक्सल के किसी समूह के सिरों के बीच फ़ुट में दूरी है, N समूह में एक्सल की संख्या है, और W अनुमत सकल भार है।"},"9":{"q":"फ्लोरिडा में उपयोग किया जाने वाला फ़ेडरल ब्रिज फ़ॉर्मूला मुख्य रूप से किसकी रक्षा के लिए डिज़ाइन किया गया है?","options":["वाहन के टायरों को ओवरलोड से","चालक को थकान से","माल को खिसकने से","पुलों और सड़क की सतह को केंद्रित भार से"],"explanation":"फ्लोरिडा क़ानून 316.535 में फ़ेडरल ब्रिज फ़ॉर्मूला भार को अधिक दूरी पर फैलाता है (अधिक एक्सल, अधिक दूरी) ताकि पुलों और सड़क की सतह की रक्षा हो सके; पास-पास लगे एक्सल भार को केंद्रित करते हैं और उनका वज़न कम होना चाहिए।"},"10":{"q":"कौन सी फ्लोरिडा एजेंसी उन लोडों के लिए ओवरसाइज़ और ओवरवेट परमिट जारी करती है जो क़ानूनी आकार या भार सीमा से अधिक हैं?","options":["फ्लोरिडा डिपार्टमेंट ऑफ़ हाईवे सेफ़्टी एंड मोटर व्हीकल्स (DHSMV)","फ्लोरिडा हाईवे पेट्रोल (FHP)","फ्लोरिडा डिपार्टमेंट ऑफ़ ट्रांसपोर्टेशन (FDOT)","यू.एस. फ़ेडरल मोटर कैरियर सेफ़्टी एडमिनिस्ट्रेशन (FMCSA)"],"explanation":"फ्लोरिडा डिपार्टमेंट ऑफ़ ट्रांसपोर्टेशन (FDOT) अपने परमिट कार्यालय और ऑनलाइन परमिट आवेदन प्रणाली के माध्यम से उन लोडों के लिए ओवरसाइज़/ओवरवेट परमिट जारी करता है जो फ्लोरिडा क़ानून 316.515 और 316.535 की सीमाओं से अधिक हैं।"},"11":{"q":"एक लोड 110 इंच चौड़ा है। फ्लोरिडा के राजमार्ग पर इसे ले जाने से पहले, चालक को अवश्य:","options":["FDOT ओवरसाइज़ परमिट प्राप्त करना चाहिए","कुछ न करें; 110 इंच क़ानूनी है","केवल गति 10 mph कम करें","केवल स्थानीय पुलिस से अनुमति लें"],"explanation":"चूँकि 110 इंच फ्लोरिडा क़ानून 316.515 में 102-इंच (8'6\") क़ानूनी चौड़ाई सीमा से अधिक है, इस आवाजाही के लिए FDOT ओवरसाइज़ परमिट की आवश्यकता है। लोड परमिट के बिना क़ानूनी चौड़ाई से अधिक नहीं हो सकते।"},"12":{"q":"किस प्रकार का FDOT परमिट एक मूल स्थान से एक गंतव्य तक एकल ओवरसाइज़/ओवरवेट आवाजाही को अधिकृत करता है?","options":["वार्षिक ब्लैंकेट परमिट","ट्रिप (सिंगल-ट्रिप) परमिट","रूट-विशिष्ट ब्लैंकेट परमिट","वाहन-विशिष्ट ब्लैंकेट परमिट"],"explanation":"FDOT एकल आवाजाही के लिए एक ट्रिप (सिंगल-ट्रिप) परमिट जारी करता है; ब्लैंकेट परमिट (वार्षिक, रूट-विशिष्ट, या वाहन-विशिष्ट) लंबी अवधि में बार-बार होने वाली आवाजाही को कवर करते हैं। ट्रिप परमिट आमतौर पर आवाजाही पूरी करने के लिए सीमित दिनों की संख्या के लिए वैध होते हैं।"},"13":{"q":"फ्लोरिडा/FDOT परमिट नियमों के अंतर्गत, किस चौड़ाई पर एक ओवरसाइज़ लोड के लिए आमतौर पर कम से कम एक एस्कॉर्ट (पायलट) वाहन की आवश्यकता होने लगती है?","options":["8 फ़ुट 6 इंच से अधिक","10 फ़ुट से अधिक","12 फ़ुट से अधिक","16 फ़ुट से अधिक"],"explanation":"FDOT ओवरसाइज़-लोड नियमों के अनुसार, 12 फ़ुट से अधिक चौड़े लोडों के लिए आमतौर पर कम से कम एक एस्कॉर्ट वाहन की आवश्यकता होती है; 14 फ़ुट से अधिक के लोडों के लिए आमतौर पर दो एस्कॉर्ट की आवश्यकता होती है, और सबसे चौड़े लोडों के लिए क़ानून-प्रवर्तन एस्कॉर्ट की आवश्यकता हो सकती है।"},"14":{"q":"फ्लोरिडा में FDOT परमिट के तहत संचालित होने वाले एक ओवरसाइज़ लोड को आमतौर पर प्रदर्शित करना आवश्यक होता है:","options":["केवल दिन के उजाले में हेडलाइट चालू रखना","केवल एक हरा परमिट प्लेकार्ड","12 फ़ुट से कम चौड़ा होने पर कोई विशेष चिह्न नहीं","'OVERSIZE LOAD' संकेत और कोनों/सिरों पर चेतावनी झंडे"],"explanation":"FDOT परमिट शर्तों के अनुसार ओवरसाइज़ लोडों को 'OVERSIZE LOAD' चेतावनी संकेत और लोड के कोनों और सबसे चौड़े बिंदुओं पर रंगीन (लाल/नारंगी) झंडे प्रदर्शित करने की आवश्यकता होती है ताकि अन्य यातायात अति-आयामी लोड को देख सके।"},"15":{"q":"फ्लोरिडा में पालन किए जाने वाले संघीय माल सुरक्षा नियमों के अनुसार, टाईडाउन की कुल वर्किंग लोड लिमिट (WLL) सुरक्षित किए गए माल के भार के कम से कम किस अंश के बराबर होनी चाहिए?","options":["आधा (50%)","एक-चौथाई (25%)","दो-तिहाई (67%)","पूरा भार (100%)"],"explanation":"संघीय माल सुरक्षा नियम (49 CFR 393.106), जिन्हें फ्लोरिडा लागू करता है, सभी टाईडाउन की कुल वर्किंग लोड लिमिट को सुरक्षित की जा रही वस्तु या माल के भार के कम से कम आधा (50%) होने की आवश्यकता रखते हैं।"},"16":{"q":"फ्लोरिडा में लागू माल सुरक्षा नियमों के अंतर्गत, 5 फ़ुट या उससे कम लंबाई और 1,100 पाउंड या उससे कम वज़न वाली माल की वस्तु को कम से कम कितने टाईडाउन की आवश्यकता होती है?","options":["दो टाईडाउन","एक टाईडाउन","तीन टाईडाउन","ब्लॉक किए जाने पर कोई टाईडाउन नहीं"],"explanation":"49 CFR 393.110 (फ्लोरिडा में लागू) के अंतर्गत, 5 फ़ुट या उससे कम लंबाई और 1,100 पाउंड या उससे कम वाली वस्तु को न्यूनतम एक टाईडाउन की आवश्यकता होती है; लंबी या भारी वस्तुओं को दो या अधिक की आवश्यकता होती है।"},"17":{"q":"लोडिंग और यात्रा शुरू करने के बाद, फ्लोरिडा CDL चालक को सबसे पहले माल और सुरक्षा उपकरणों का निरीक्षण कब करना चाहिए?","options":["पहले 25 मील के भीतर","पहले 100 मील के भीतर","पहले 50 मील के भीतर","केवल गंतव्य पर"],"explanation":"फ्लोरिडा में पालन किए जाने वाले संघीय नियम (49 CFR 392.9) चालक को यात्रा शुरू करने के बाद पहले 50 मील के भीतर माल और सुरक्षा उपकरणों का निरीक्षण करने और उसके बाद समय-समय पर उनकी पुनः जाँच करने की आवश्यकता रखते हैं।"},"18":{"q":"फ्लोरिडा क़ानून मुख्य रूप से किस प्रकार के लोड के वाहकों के लिए भार सीमाओं पर कुछ कम-दंड या सहनशीलता प्रावधान प्रदान करता है?","options":["ड्राई वैन में सामान्य माल","ख़तरनाक सामग्री","घरेलू सामान","प्राकृतिक, असंसाधित कृषि उत्पाद"],"explanation":"फ्लोरिडा के यातायात और भार क़ानून (अध्याय 316) प्राकृतिक, असंसाधित कृषि उत्पादों के परिवहन के लिए विशेष सहनशीलता/दंड प्रावधान प्रदान करते हैं, इन लोडों की मौसमी, खेत-संबंधी प्रकृति को मान्यता देते हुए।"},"19":{"q":"फ्लोरिडा में 14 फ़ुट चौड़े और 120,000 पाउंड वज़न वाले एक अविभाज्य लोड को ले जाने वाले चालक को आवाजाही से पहले क्या करना चाहिए?","options":["FDOT ओवरसाइज़ और ओवरवेट परमिट प्राप्त करें","कुछ नहीं; अविभाज्य लोड छूट प्राप्त हैं","केवल रात में यात्रा करें","लोड को क़ानूनी सीमाओं तक कम करें भले ही उसे विभाजित न किया जा सके"],"explanation":"एक अविभाज्य लोड जो 102-इंच चौड़ाई सीमा (316.515) और 80,000 पाउंड सकल भार सीमा (316.535) दोनों से अधिक है, उसके लिए FDOT ओवरसाइज़/ओवरवेट परमिट की आवश्यकता होती है, जो मार्ग, एस्कॉर्ट और यात्रा-समय की शर्तें भी निर्धारित करता है।"},"20":{"q":"फ्लोरिडा में, 26,001 lbs या उससे अधिक के सकल संयोजन भार रेटिंग वाले वाहनों के संयोजन को संचालित करने के लिए कौन सी CDL श्रेणी आवश्यक है, जहाँ खींची जाने वाली इकाई 10,000 lbs से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"26,001 lbs या उससे अधिक रेटेड और 10,000 lbs से अधिक की इकाई खींचने वाले ट्रक/ट्रेलर संयोजनों (जैसे ट्रैक्टर-ट्रेलर) को संचालित करने के लिए फ्लोरिडा Class A CDL आवश्यक है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज; FL CDL हैंडबुक।"},"21":{"q":"एक फ्लोरिडा चालक 26,001 lbs या उससे अधिक रेटेड एकल सीधे ट्रक या बस को संचालित करना चाहता है जो 10,000 lbs से अधिक का ट्रेलर नहीं खींच रहा है। कौन सी CDL श्रेणी उपयुक्त है?","options":["Class A","Class B","Class C","Class E"],"explanation":"फ्लोरिडा Class B CDL उन एकल (सीधे) ट्रकों और बसों को कवर करता है जो 26,001 lbs या उससे अधिक रेटेड हैं और 10,000 lbs से अधिक की इकाई नहीं खींचते। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"22":{"q":"एक छोटे वाहन (जो Class A या B भार को पूरा नहीं करता) के लिए कौन सी फ्लोरिडा CDL श्रेणी आवश्यक है जो 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया है या प्लेकार्डेड ख़तरनाक सामग्री ले जाता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"फ्लोरिडा Class C CDL उन वाहनों पर लागू होता है जो Class A या B भार मानकों को पूरा नहीं करते लेकिन 16+ व्यक्तियों को ले जाने के लिए डिज़ाइन किए गए हैं या प्लेकार्डेड ख़तरनाक सामग्री का परिवहन करते हैं। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"23":{"q":"केवल इंट्रास्टेट (फ्लोरिडा के भीतर) संचालन तक सीमित फ्लोरिडा CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"फ्लोरिडा 18 वर्ष की आयु में CDL की अनुमति देता है, लेकिन 21 वर्ष से कम आयु के चालक इंट्रास्टेट (राज्य के भीतर) संचालन तक सीमित हैं। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज; फ्लोरिडा क़ानून अध्याय 322।"},"24":{"q":"एक 19-वर्षीय फ्लोरिडा CDL धारक राज्य की सीमाओं के पार (इंटरस्टेट) ड्राइव करना या ख़तरनाक सामग्री ले जाना चाहता है। वे ऐसा क्यों नहीं कर सकते?","options":["इंटरस्टेट संचालन और हज़मैट के लिए न्यूनतम आयु 21 वर्ष आवश्यक है","इंटरस्टेट संचालन के लिए न्यूनतम आयु 23 वर्ष आवश्यक है","उन्हें पहले पाँच वर्ष तक एक इंट्रास्टेट CDL रखना होगा","25 वर्ष से कम आयु के चालक कभी भी कोई माल नहीं ले जा सकते"],"explanation":"21 वर्ष से कम आयु के फ्लोरिडा CDL धारक इंट्रास्टेट ड्राइविंग तक सीमित हैं; इंटरस्टेट संचालन और ख़तरनाक सामग्री के परिवहन के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: FLHSMV; संघीय 49 CFR 391.11।"},"25":{"q":"प्लेकार्डेड मात्रा में ख़तरनाक सामग्री का परिवहन करने के लिए फ्लोरिडा CDL धारक को कौन से एंडोर्समेंट की आवश्यकता होती है?","options":["N एंडोर्समेंट","T एंडोर्समेंट","P एंडोर्समेंट","H एंडोर्समेंट"],"explanation":"H (हज़मैट) एंडोर्समेंट प्लेकार्डेड ख़तरनाक सामग्री के परिवहन को अधिकृत करता है और इसके लिए हज़मैट ज्ञान परीक्षा उत्तीर्ण करना आवश्यक है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"26":{"q":"फ्लोरिडा में टैंक वाहन चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["N (टैंक वाहन)","T (डबल/ट्रिपल ट्रेलर)","H (हज़मैट)","S (स्कूल बस)"],"explanation":"N एंडोर्समेंट उन चालकों को जारी किया जाता है जो आवश्यक टैंक-वाहन ज्ञान परीक्षा उत्तीर्ण करते हैं और टैंक वाहन संचालित करेंगे। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"27":{"q":"एक फ्लोरिडा चालक डबल या ट्रिपल ट्रैक्टर-ट्रेलर संयोजन खींचने की योजना बनाता है। कौन सा एंडोर्समेंट आवश्यक है?","options":["P (यात्री)","T (डबल/ट्रिपल ट्रेलर)","N (टैंक वाहन)","H (हज़मैट)"],"explanation":"T एंडोर्समेंट, जो आवश्यक ज्ञान परीक्षा उत्तीर्ण करके अर्जित किया जाता है, डबल और ट्रिपल ट्रेलर संयोजनों के संचालन की अनुमति देता है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"28":{"q":"16 या अधिक लोगों (चालक सहित 15 से अधिक यात्री) को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए फ्लोरिडा को कौन से एंडोर्समेंट की आवश्यकता होती है?","options":["S (स्कूल बस)","P (यात्री)","N (टैंक वाहन)","T (डबल/ट्रिपल ट्रेलर)"],"explanation":"P (यात्री) एंडोर्समेंट के लिए ज्ञान और कौशल दोनों परीक्षाएँ उत्तीर्ण करना आवश्यक है और चालक सहित 15 से अधिक व्यक्तियों के लिए डिज़ाइन किए गए यात्री वाहनों के लिए आवश्यक है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"29":{"q":"फ्लोरिडा स्कूल बस (S) एंडोर्समेंट प्राप्त करने के लिए, चालक को कौन सा अतिरिक्त एंडोर्समेंट भी रखना चाहिए?","options":["H (हज़मैट) एंडोर्समेंट","N (टैंक) एंडोर्समेंट","P (यात्री) एंडोर्समेंट","T (डबल/ट्रिपल) एंडोर्समेंट"],"explanation":"फ्लोरिडा S (स्कूल बस) एंडोर्समेंट के अतिरिक्त P (यात्री) एंडोर्समेंट की आवश्यकता रखता है; S एंडोर्समेंट के लिए अपनी स्वयं की ज्ञान और कौशल परीक्षाएँ उत्तीर्ण करना आवश्यक है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"30":{"q":"किस फ्लोरिडा CDL एंडोर्समेंट के लिए जारी होने से पहले एक संघीय TSA सुरक्षा ख़तरा आकलन की आवश्यकता होती है, जिसमें फ़िंगरप्रिंटिंग और राष्ट्रीय पृष्ठभूमि जाँच शामिल है?","options":["P (यात्री)","T (डबल/ट्रिपल ट्रेलर)","N (टैंक वाहन)","H (हज़मैट)"],"explanation":"USA PATRIOT Act के अंतर्गत, H (हज़मैट) एंडोर्समेंट के लिए आवेदकों को जारी होने से पहले फ़िंगरप्रिंट लेना और TSA पृष्ठभूमि जाँच उत्तीर्ण करना आवश्यक है; एक अतिरिक्त शुल्क लागू होता है। स्रोत: FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज; TSA।"},"31":{"q":"CDL कौशल (ड्राइविंग) परीक्षा देने की अनुमति मिलने से पहले चालक को फ्लोरिडा कमर्शियल लर्नर परमिट (CLP) कितने समय तक रखना चाहिए?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"फ्लोरिडा द्वारा अपनाए गए संघीय नियम CDL कौशल परीक्षा देने से पहले CLP को न्यूनतम 14 दिनों तक रखने की आवश्यकता रखते हैं। स्रोत: FLHSMV; 49 CFR 383.25।"},"32":{"q":"फ्लोरिडा CLP के साथ अभ्यास करते समय, वाणिज्यिक वाहन में परमिट धारक के साथ किसे होना चाहिए?","options":["21 वर्ष या उससे अधिक आयु का कोई भी लाइसेंस प्राप्त चालक","उचित श्रेणी और एंडोर्समेंट वाले वैध CDL का धारक, जो चालक के बगल में या पास बैठा हो","केवल एक प्रमाणित CDL प्रशिक्षक, एक बंद कोर्स पर","ज्ञान परीक्षा उत्तीर्ण करने के बाद किसी पर्यवेक्षक की आवश्यकता नहीं है"],"explanation":"एक CLP धारक के साथ उपयुक्त समूह और एंडोर्समेंट वाला एक वैध CDL धारक होना चाहिए, जो प्रत्यक्ष पर्यवेक्षण में चालक के बगल में (या बसों के लिए, ठीक पीछे) शारीरिक रूप से मौजूद हो। स्रोत: FLHSMV; 49 CFR 383.25।"},"33":{"q":"वाणिज्यिक वाहन संचालित करने वाले फ्लोरिडा CLP धारक पर कौन सा यात्री प्रतिबंध लागू होता है?","options":["वे प्रशिक्षण उद्देश्यों के लिए 8 तक यात्री ले जा सकते हैं","वे केवल दिन के उजाले के घंटों में यात्री ले जा सकते हैं","वे पर्यवेक्षण करने वाले CDL धारक के अलावा यात्री नहीं ले जा सकते","वे यात्री ले जा सकते हैं यदि सभी सीट बेल्ट पहनें"],"explanation":"एक CLP धारक साथ आने वाले वैध CDL धारक/मेंटर के अलावा अन्य यात्रियों से भरी बस या वाहन संचालित नहीं कर सकता। स्रोत: FLHSMV; 49 CFR 383.25।"},"34":{"q":"यदि कोई फ्लोरिडा CDL आवेदक एयर ब्रेक ज्ञान परीक्षा नहीं देता और उत्तीर्ण नहीं करता, तो उनके लाइसेंस का क्या होता है?","options":["एयर ब्रेक वाले वाहनों को प्रतिबंधित करने वाला एक 'L' प्रतिबंध जोड़ा जाता है","उन्हें इंट्रास्टेट ड्राइविंग तक सीमित करने वाला एक 'K' प्रतिबंध जोड़ा जाता है","CDL स्वतः ही Class C में डाउनग्रेड हो जाता है","एयर ब्रेक उत्तीर्ण होने तक कोई CDL जारी नहीं किया जा सकता"],"explanation":"एयर ब्रेक परीक्षा में असफल होने या छोड़ने पर 'L' प्रतिबंध लगता है, जो चालक को एयर ब्रेक से सुसज्जित वाणिज्यिक वाहन संचालित करने से रोकता है। स्रोत: FLHSMV; FL CDL हैंडबुक।"},"35":{"q":"फ्लोरिडा में अपनाए गए संघीय एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) नियमों के अंतर्गत, किन आवेदकों को परीक्षा से पहले ELDT पूरा करना चाहिए?","options":["केवल वे चालक जो पहले से ही आउट-ऑफ़-स्टेट CDL रखते हैं","पहली बार CDL आवेदक, Class B-से-A अपग्रेड, और पहली बार H, P, या S एंडोर्समेंट चाहने वाले","केवल वे चालक जो N या T एंडोर्समेंट चाहते हैं","केवल 21 वर्ष से अधिक आयु के चालक"],"explanation":"ELDT पहली बार CDL आवेदकों, Class B से Class A अपग्रेड, और पहली बार हज़मैट, यात्री, या स्कूल बस एंडोर्समेंट के लिए आवश्यक है (7 फ़रवरी 2022 को या उसके बाद प्राप्त CLP के लिए)। स्रोत: FMCSA ELDT नियम; FLHSMV।"},"36":{"q":"फ्लोरिडा ELDT प्रशिक्षण प्रदाता को कहाँ सूचीबद्ध होना चाहिए ताकि चालक का प्रशिक्षण CDL पात्रता के लिए गिना जाए?","options":["FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर","केवल FLHSMV अनुमोदित-स्कूल सूची पर","TSA विक्रेता रजिस्ट्री पर","किसी भी राज्य सामुदायिक-कॉलेज रोस्टर पर"],"explanation":"ELDT सिद्धांत और बिहाइंड-द-व्हील प्रशिक्षण एक ऐसे प्रदाता द्वारा प्रदान किया जाना चाहिए जो FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री (TPR) पर सूचीबद्ध हो, जो पूर्णता को इलेक्ट्रॉनिक रूप से प्रस्तुत करता है। स्रोत: FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री; FLHSMV।"},"37":{"q":"विशेष रूप से हज़मैट (H) एंडोर्समेंट के लिए, एक फ्लोरिडा आवेदक को कौन सा ELDT चरण पूरा करना चाहिए?","options":["रोड टेस्ट से पहले बिहाइंड-द-व्हील रेंज प्रशिक्षण","हज़मैट ज्ञान परीक्षा देने से पहले ELDT सिद्धांत (ज्ञान) भाग","एक टैंक वाहन में पूर्ण कौशल परीक्षा","हज़मैट के लिए कभी भी कोई ELDT आवश्यक नहीं है"],"explanation":"हज़मैट आवेदकों को हज़मैट ज्ञान परीक्षा देने से पहले एक पंजीकृत प्रदाता के माध्यम से ELDT सिद्धांत भाग पूरा करना चाहिए। स्रोत: FMCSA ELDT नियम; FLHSMV।"},"38":{"q":"एक फ्लोरिडा CDL चालक जो राज्य की सीमाओं के पार संचालन करता है और जिसे एक संघीय मेडिकल प्रमाणपत्र बनाए रखना आवश्यक है, वह किस श्रेणी के अंतर्गत स्व-प्रमाणन करेगा?","options":["Excepted Interstate (EI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)"],"explanation":"Non-Excepted Interstate (NI) इंटरस्टेट कॉमर्स में उन चालकों पर लागू होता है जिन्हें FMCSA राष्ट्रीय रजिस्ट्री परीक्षक से एक वैध मेडिकल परीक्षक प्रमाणपत्र रखना आवश्यक है। स्रोत: FLHSMV स्व-प्रमाणन; FMCSA 49 CFR 383.71।"},"39":{"q":"REAL ID-अनुपालक CDL आवेदन के लिए फ्लोरिडा किस दस्तावेज़ को पहचान के प्राथमिक प्रमाण के रूप में स्वीकार करता है?","options":["एक प्रमाणित यू.एस. जन्म प्रमाणपत्र या वैध यू.एस. पासपोर्ट","आवेदक के नाम पर एक वर्तमान उपयोगिता बिल","एक फ्लोरिडा मतदाता पंजीकरण कार्ड","एक नियोक्ता-जारी फ़ोटो ID बैज"],"explanation":"REAL ID-अनुपालक CDL के लिए, फ्लोरिडा एक प्राथमिक पहचान दस्तावेज़ जैसे प्रमाणित यू.एस. जन्म प्रमाणपत्र या वैध यू.एस. पासपोर्ट/पासपोर्ट कार्ड की आवश्यकता रखता है, साथ ही सोशल सिक्योरिटी नंबर का प्रमाण और आवासीय पते के दो प्रमाण। स्रोत: FLHSMV What to Bring / REAL ID।"},"40":{"q":"फ्लोरिडा में, किस अधिकतम रक्त अल्कोहल सांद्रता (BAC) पर एक CDL धारक क़ानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) संचालित कर सकता है?","options":["0.08 प्रतिशत","0.02 प्रतिशत","0.10 प्रतिशत","0.04 प्रतिशत"],"explanation":"फ्लोरिडा में CMV संचालित करना अवैध है यदि आपका BAC 0.04 प्रतिशत या उससे अधिक है, जो ग़ैर-वाणिज्यिक चालकों पर लागू होने वाली 0.08 सीमा का आधा है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV), चालक अयोग्यताएँ; 49 CFR 383.51।"},"41":{"q":"फ्लोरिडा के निहित-सहमति क़ानून के अंतर्गत, जिस क्षण कोई व्यक्ति राज्य में एक वाणिज्यिक मोटर वाहन संचालित करता है, उस समय क्या होता है?","options":["उन्हें हर समय एक अलग ब्रेथ-टेस्ट परमिट रखना चाहिए","उन्हें अल्कोहल परीक्षण के लिए सहमति देने वाला माना जाता है","वे पूरी तरह से CDL सुनवाई के अधिकार को त्याग देते हैं","दुर्घटना होने तक वे परीक्षण से छूट प्राप्त हैं"],"explanation":"फ्लोरिडा में एक CMV संचालित करके, एक चालक को अल्कोहल के लिए परीक्षण की सहमति देने वाला माना जाता है। परीक्षण से इनकार करने पर DUI दोषसिद्धि के समान ही अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); फ्लोरिडा क़ानून अध्याय 322 (निहित सहमति)।"},"42":{"q":"एक CDL धारक को पहले प्रमुख अपराध, जैसे DUI, के लिए दोषी ठहराया जाता है, जबकि वे ख़तरनाक सामग्री नहीं ले जा रहे थे। फ्लोरिडा में न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["60 दिन","3 वर्ष","1 वर्ष","आजीवन"],"explanation":"पहला प्रमुख अपराध (DUI, CMV में BAC 0.04 या उससे अधिक, परीक्षण से इनकार, दुर्घटना स्थल छोड़ना, या अपराध करने के लिए वाहन का उपयोग) कम से कम 1-वर्ष की CDL अयोग्यता में परिणत होता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"43":{"q":"यदि कोई पहला प्रमुख अपराध तब होता है जब एक CDL चालक ख़तरनाक सामग्री के लिए प्लेकार्डेड CMV संचालित कर रहा हो, तो फ्लोरिडा में न्यूनतम अयोग्यता अवधि क्या है?","options":["3 वर्ष","1 वर्ष","120 दिन","आजीवन"],"explanation":"ख़तरनाक सामग्री के लिए प्लेकार्डेड CMV संचालित करते समय किया गया पहला प्रमुख अपराध न्यूनतम अयोग्यता को 1 वर्ष से बढ़ाकर कम से कम 3 वर्ष कर देता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"44":{"q":"फ्लोरिडा में एक CDL धारक के लिए क्या परिणाम होता है जिसे अपने ड्राइविंग करियर के दौरान किसी भी समय दूसरे प्रमुख अपराध के लिए दोषी ठहराया जाता है?","options":["3-वर्ष की अयोग्यता","आजीवन CDL का नुक़सान","1-वर्ष की अयोग्यता","120-दिन की अयोग्यता"],"explanation":"दूसरा प्रमुख अपराध आजीवन CDL अयोग्यता में परिणत होता है। फ्लोरिडा सीमित परिस्थितियों में न्यूनतम अवधि के बाद पुनर्बहाली पर विचार की अनुमति दे सकता है, लेकिन नियम आजीवन प्रतिबंध का है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"45":{"q":"फ्लोरिडा में एक CDL चालक से क़ानूनी रूप से रक्त अल्कोहल परीक्षण के लिए कहा जाता है और वह इनकार कर देता है। CDL अयोग्यता उद्देश्यों के लिए इसे कैसे माना जाता है?","options":["यह केवल एक गंभीर उल्लंघन है, जो 60 दिनों के लिए अयोग्य करता है","यह एक प्रमुख अपराध है, जो कम से कम 1 वर्ष के लिए अयोग्य करता है","यदि चालक ड्यूटी पर नहीं था तो इसमें कोई CDL दंड नहीं है","इसमें केवल 24-घंटे का आउट-ऑफ़-सर्विस आदेश होता है"],"explanation":"अल्कोहल परीक्षण के लिए प्रस्तुत होने से इनकार करना एक प्रमुख अपराध माना जाता है, जिसमें DUI दोषसिद्धि के समान ही न्यूनतम 1-वर्ष की अयोग्यता (हज़मैट के लिए प्लेकार्डेड होने पर 3 वर्ष) होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"46":{"q":"निम्नलिखित में से कौन सा एक फ्लोरिडा CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत है?","options":["CMV में 0.04 प्रतिशत BAC के साथ ड्राइविंग","एक क़ानूनी अल्कोहल परीक्षण से इनकार","आउट-ऑफ़-सर्विस आदेश के तहत CMV संचालित करना","अत्यधिक तेज़ गति, निर्धारित सीमा से 15 mph या उससे अधिक"],"explanation":"अत्यधिक तेज़ गति (सीमा से 15 mph या उससे अधिक) एक गंभीर यातायात उल्लंघन है। अन्य विकल्प प्रमुख अपराध या आउट-ऑफ़-सर्विस उल्लंघन हैं, जिनमें अलग, अधिक गंभीर दंड होते हैं। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"47":{"q":"3-वर्ष की अवधि के भीतर कितने गंभीर यातायात उल्लंघन फ्लोरिडा में CDL अयोग्यता को सक्रिय करेंगे, और दूसरे के लिए कितने समय के लिए?","options":["2 उल्लंघन कम से कम 120-दिन की अयोग्यता में परिणत होते हैं","3 उल्लंघन कम से कम 60-दिन की अयोग्यता में परिणत होते हैं","2 उल्लंघन कम से कम 60-दिन की अयोग्यता में परिणत होते हैं","2 उल्लंघन कम से कम 1-वर्ष की अयोग्यता में परिणत होते हैं"],"explanation":"3-वर्ष की अवधि के भीतर दूसरा गंभीर यातायात उल्लंघन कम से कम 60 दिनों की अयोग्यता में परिणत होता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"48":{"q":"3-वर्ष की अवधि के भीतर किए गए तीसरे गंभीर यातायात उल्लंघन के लिए फ्लोरिडा में न्यूनतम CDL अयोग्यता क्या है?","options":["60 दिन","1 वर्ष","120 दिन","30 दिन"],"explanation":"3-वर्ष की अवधि के भीतर तीसरा गंभीर यातायात उल्लंघन कम से कम 120 दिनों की अयोग्यता में परिणत होता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"49":{"q":"निम्नलिखित में से कौन सा एक फ्लोरिडा CDL धारक के लिए प्रमुख अपराध के बजाय एक गंभीर यातायात उल्लंघन है?","options":["अनुचित या अनियमित लेन परिवर्तन","दुर्घटना स्थल छोड़ना","अपराध करने के लिए वाहन का उपयोग","किसी नियंत्रित पदार्थ के प्रभाव में ड्राइविंग"],"explanation":"अनुचित या अनियमित लेन परिवर्तन एक गंभीर यातायात उल्लंघन है। अन्य तीन प्रमुख अपराध हैं जिनमें न्यूनतम 1-वर्ष (या आजीवन) की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"50":{"q":"फ्लोरिडा और संघीय CDL नियमों के तहत, CMV चलाते समय टेक्स्टिंग करने को अयोग्यता (disqualification) के प्रयोजनों के लिए कैसे वर्गीकृत किया जाता है?","options":["1-वर्ष की अयोग्यता वाले एक प्रमुख अपराध के रूप में","एक गंभीर यातायात उल्लंघन के रूप में","एक आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के रूप में","अयोग्यता का कोई प्रभाव न डालने वाले एक गैर-CDL उल्लंघन के रूप में"],"explanation":"CMV चलाते समय टेक्स्टिंग पर रोक लगाने वाले कानून का उल्लंघन एक गंभीर यातायात उल्लंघन है। 3 वर्षों के भीतर अन्य गंभीर उल्लंघनों के साथ मिलकर, यह 60- या 120-दिन की अयोग्यता का कारण बन सकता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51 और 392.80।"},"51":{"q":"CMV चलाते समय हैंडहेल्ड मोबाइल टेलीफोन का उपयोग करना फ्लोरिडा में CDL ड्राइवरों के लिए निषिद्ध है। अयोग्यता के प्रयोजनों के लिए, इस अपराध को इस रूप में माना जाता है:","options":["आजीवन अयोग्यता की आवश्यकता वाला एक प्रमुख अपराध","एक रेलरोड-क्रॉसिंग उल्लंघन","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस ऑर्डर उल्लंघन"],"explanation":"CMV चलाते समय हैंडहेल्ड मोबाइल टेलीफोन के उपयोग पर रोक लगाने वाले कानून का उल्लंघन एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर बार-बार गंभीर उल्लंघन 60- या 120-दिन की अयोग्यता का कारण बनते हैं। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51 और 392.82।"},"52":{"q":"फ्लोरिडा में रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन की पहली (FIRST) दोषसिद्धि के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["120 दिन","60 दिन","1 वर्ष","30 दिन"],"explanation":"पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 60 दिन की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"53":{"q":"एक फ्लोरिडा CDL धारक 3-वर्ष की अवधि के भीतर दूसरा (SECOND) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["60 दिन","1 वर्ष","180 दिन","120 दिन"],"explanation":"3 वर्षों के भीतर दूसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 120 दिन की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"54":{"q":"फ्लोरिडा में 3-वर्ष की अवधि के भीतर तीसरे (THIRD) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["120 दिन","60 दिन","1 वर्ष","आजीवन"],"explanation":"3-वर्ष की अवधि के भीतर तीसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप कम से कम 1 वर्ष की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"55":{"q":"एक फ्लोरिडा CDL ड्राइवर खतरनाक सामग्री या यात्रियों का परिवहन न करते हुए पहली (FIRST) बार किसी आउट-ऑफ-सर्विस ऑर्डर का उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["180 दिन","60 दिन","90 दिन","120 दिन"],"explanation":"पहले आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के परिणामस्वरूप कम से कम 180 दिन की अयोग्यता होती है (HazMat या यात्रियों का परिवहन करने पर अधिक लंबी)। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"56":{"q":"फ्लोरिडा में 10-वर्ष की अवधि के भीतर दूसरे (SECOND) आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["180 दिन","1 वर्ष","3 वर्ष","2 वर्ष"],"explanation":"10-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के परिणामस्वरूप कम से कम 2 वर्ष की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"57":{"q":"एक फ्लोरिडा CDL ड्राइवर 10-वर्ष की अवधि के भीतर तीसरा (THIRD) या उसके बाद का आउट-ऑफ-सर्विस ऑर्डर उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["3 वर्ष","2 वर्ष","1 वर्ष","180 दिन"],"explanation":"10-वर्ष की अवधि के भीतर तीसरे या उसके बाद के आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के परिणामस्वरूप कम से कम 3 वर्ष की अयोग्यता होती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"58":{"q":"यदि फ्लोरिडा में किसी CDL ड्राइवर के पास ड्यूटी पर रहते हुए शराब की कोई भी पता लगाने योग्य मात्रा (0.04 BAC से नीचे) पाई जाती है, तो तत्काल परिणाम क्या है?","options":["24 घंटे के लिए आउट ऑफ सर्विस कर दिया जाता है","CDL का स्थायी नुकसान","60-दिन की अयोग्यता","एक अनिवार्य 1-वर्ष की अयोग्यता"],"explanation":"0.04 से कम शराब की किसी भी पता लगाने योग्य मात्रा वाले ड्राइवर को 24 घंटे के लिए आउट ऑफ सर्विस कर दिया जाता है। 0.04 या उससे अधिक का BAC एक प्रमुख अपराध है जो ड्राइवर को कम से कम 1 वर्ष के लिए अयोग्य ठहराता है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 392.5 और 383.51।"},"59":{"q":"फ्लोरिडा में कौन-सा अपराध बिना पुनर्बहाली की किसी संभावना के अनिवार्य आजीवन CDL अयोग्यता का परिणाम देता है?","options":["CMV में पहली DUI दोषसिद्धि","3 वर्षों के भीतर दो गंभीर यातायात उल्लंघन","पहला रेलरोड-क्रॉसिंग उल्लंघन","किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण के लिए CMV का उपयोग करना"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण से जुड़े अपराध (felony) को अंजाम देने में CMV का उपयोग करने पर बिना पुनर्बहाली के अनिवार्य आजीवन अयोग्यता लगती है। स्रोत: फ्लोरिडा CDL हैंडबुक (FLHSMV); 49 CFR 383.51।"},"60":{"q":"फ्लोरिडा के मूव ओवर एक्ट के तहत, आप एक मल्टी-लेन हाईवे पर एक ट्रैक्टर-ट्रेलर चला रहे हैं और आपातकालीन लाइटें चमकाते हुए एक रुकी हुई पेट्रोल कार के पास पहुँचते हैं। कानून आपको सबसे पहले क्या करने की आवश्यकता रखता है?","options":["आपातकालीन वाहन के चले जाने तक अपनी वर्तमान लेन में पूरी तरह रुक जाना","जैसे ही ऐसा करना सुरक्षित हो, आपातकालीन वाहन के सबसे निकट वाली लेन खाली कर देना","अधिकारी को अपने आगमन के बारे में चेतावनी देने के लिए हॉर्न बजाना","अपनी गति बनाए रखना लेकिन अपनी हैज़र्ड लाइटें चालू करना"],"explanation":"फ्लोरिडा का मूव ओवर एक्ट (Fla. Stat. 316.126) मल्टी-लेन सड़क पर ड्राइवरों से अपेक्षा करता है कि जैसे ही ऐसा करना सुरक्षित हो, वे रुके हुए आपातकालीन या सेवा वाहन के सबसे निकट वाली लेन खाली कर दें; केवल यदि लेन बदलना संभव न हो तभी आपको गति धीमी करनी चाहिए।"},"61":{"q":"55 mph पर पोस्ट की गई एक टू-लेन फ्लोरिडा सड़क पर, आप एम्बर लाइटें दिखा रहे एक रुके हुए रेकर (wrecker) के पास पहुँचते हैं और सुरक्षित रूप से लेन नहीं बदल सकते। आपको अपनी गति कितने मील प्रति घंटा तक कम करनी चाहिए?","options":["45 mph","25 mph","35 mph","55 mph; टू-लेन सड़क पर किसी कमी की आवश्यकता नहीं है"],"explanation":"Fla. Stat. 316.126 के तहत, जब आप लेन नहीं बदल सकते, तो जब पोस्ट की गई गति 25 mph या उससे अधिक हो, तो आपको पोस्ट की गई सीमा से 20 mph नीचे तक गति धीमी करनी चाहिए। 55 mph वाली सड़क पर इसका अर्थ है 35 mph।"},"62":{"q":"फ्लोरिडा का मूव ओवर एक्ट तब गति कम करने की आवश्यकता रखता है जब आप लेन नहीं बदल सकते। ऐसी सड़क पर जहाँ पोस्ट की गई गति सीमा 20 mph या उससे कम है, किसी योग्य रुके हुए वाहन से गुज़रते समय आपको किस गति तक धीमा होना चाहिए?","options":["5 mph","10 mph","0 mph (पूर्ण विराम)","15 mph"],"explanation":"Fla. Stat. 316.126 प्रावधान करता है कि जब पोस्ट की गई गति सीमा 20 mph या उससे कम हो, तो जो ड्राइवर लेन नहीं बदल सकता उसे रुके हुए वाहन से गुज़रते समय 5 mph तक धीमा होना चाहिए।"},"63":{"q":"आपातकालीन वाहनों के अतिरिक्त, फ्लोरिडा का मूव ओवर कानून (Fla. Stat. 316.126) उचित संकेत दिखा रहे निम्नलिखित में से किन रुके हुए वाहनों की भी रक्षा करता है?","options":["सैनिटेशन, उपयोगिता सेवा, और सड़क या पुल रखरखाव वाहन, और हैज़र्ड लाइटों वाले खराब (disabled) वाहन","केवल चिह्नित कानून प्रवर्तन और अग्निशमन वाहन","केवल एम्बुलेंस और टो ट्रक","सड़क के किनारे खड़ी कोई भी निजी स्वामित्व वाली यात्री कार"],"explanation":"Fla. Stat. 316.126 आपातकालीन वाहनों के अतिरिक्त मूव ओवर सुरक्षा को सैनिटेशन वाहनों, उपयोगिता सेवा वाहनों, रेकर्स, सड़क और पुल रखरखाव/निर्माण वाहनों, और हैज़र्ड लाइटें दिखा रहे खराब (disabled) मोटर वाहनों तक विस्तारित करता है।"},"64":{"q":"आप यात्रियों को ले जा रही एक बस चला रहे हैं और फ्लोरिडा में एक रेलरोड ग्रेड क्रॉसिंग के पास पहुँचते हैं। निकटतम रेल से कितनी दूरी पर आपको रुकना चाहिए?","options":["5 और 15 फ़ुट के बीच","50 और 100 फ़ुट के बीच","15 और 50 फ़ुट के बीच","ठीक 25 फ़ुट, न अधिक निकट और न अधिक दूर"],"explanation":"यात्रियों को ले जा रही बसों और प्लेकार्ड लगे खतरनाक सामग्री वाहनों को निकटतम रेल से 15 फ़ुट से अधिक निकट और 50 फ़ुट से अधिक दूर नहीं रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए (फ्लोरिडा CDL हैंडबुक; FMCSR 392.10)।"},"65":{"q":"किसी अपवाद के लागू न होने पर फ्लोरिडा में हर रेलरोड क्रॉसिंग पर अनिवार्य रूप से रुकने के लिए कौन-सा वाणिज्यिक वाहन आवश्यक है?","options":["बिना कार्गो वाला एक खाली फ्लैटबेड ट्रक","प्लेकार्ड लगी मात्रा में खतरनाक सामग्री का परिवहन करने वाला एक वाहन","सामान्य माल ले जाने वाली एक डिलीवरी वैन","रेत ढो रहा एक डंप ट्रक"],"explanation":"फ्लोरिडा CDL हैंडबुक में अपनाए गए संघीय नियमों (FMCSR 392.10) के तहत, खतरनाक सामग्री के लिए प्लेकार्ड लगाने हेतु आवश्यक वाहनों, और यात्रियों को ले जा रही बसों को रेलरोड क्रॉसिंग पर रुकना चाहिए; सामान्य माल वाहनों को रुकने की आवश्यकता नहीं है।"},"66":{"q":"किस रेलरोड क्रॉसिंग पर एक प्लेकार्ड लगे हैज़मैट ड्राइवर या बस ड्राइवर को रुकने की आवश्यकता नहीं है?","options":["ऐसा क्रॉसिंग जहाँ एक चालू ट्रैफ़िक सिग्नल हरा दिखाता है, या जो एक आधिकारिक Exempt चिह्न से अंकित है","ग्रामीण टू-लेन सड़क पर कोई भी क्रॉसिंग","क्रॉसबक्स वाला लेकिन बिना फ्लैशिंग लाइटों वाला एक क्रॉसिंग","सूर्यास्त के तुरंत बाद एक क्रॉसिंग"],"explanation":"फ्लोरिडा CDL हैंडबुक (FMCSR 392.10) अनिवार्य रुकावट के अपवादों को सूचीबद्ध करती है: एक हरा ट्रैफ़िक-नियंत्रण सिग्नल, एक आधिकारिक Exempt चिह्न से अंकित क्रॉसिंग, एक पुलिस अधिकारी या फ्लैगर द्वारा निर्देशित क्रॉसिंग, और केवल स्ट्रीटकार या औद्योगिक स्विचिंग के लिए उपयोग किए जाने वाले ट्रैक।"},"67":{"q":"मैनुअल ट्रांसमिशन वाले एक वाणिज्यिक वाहन में रेलरोड ट्रैक पार करते समय, आपको क्या करना चाहिए?","options":["ट्रैक को तेज़ी से पार करने के लिए बीच में किसी ऊँचे गियर में शिफ्ट करें","आगे बढ़ने से पहले अपने मिरर जाँचने के लिए ट्रैक पर रुकें","न्यूट्रल में शिफ्ट करें और ट्रैक के पार कोस्ट करें","निचले गियर में पार करें और ट्रैक पर रहते हुए गियर न बदलें"],"explanation":"फ्लोरिडा CDL हैंडबुक ड्राइवरों को निर्देश देती है कि वे ऐसा गियर चुनें जो वाहन को पूरी तरह ट्रैक के पार ले जाए और पार करते समय कभी गियर न बदलें, ताकि ट्रैक पर रुकने (stalling) से बचा जा सके।"},"68":{"q":"बिना मीडियन या बैरियर वाली एक फ्लोरिडा दो-तरफ़ा सड़क पर, एक स्कूल बस अपनी लाल लाइटें चमकाते हुए और स्टॉप आर्म बाहर निकाले हुए रुकती है। विपरीत दिशा से आ रहे यातायात को क्या करना चाहिए?","options":["10 mph तक धीमा हों लेकिन बस के पास से आगे बढ़ना जारी रख सकते हैं","सामान्य रूप से जारी रखें क्योंकि विपरीत दिशा के यातायात को कभी रुकना नहीं पड़ता","रुकें और तब तक रुके रहें जब तक लाइटें चमकना बंद न कर दें और स्टॉप आर्म वापस न ले लिया जाए","केवल तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पार करते दिखाई दें"],"explanation":"Fla. Stat. 316.172 अपेक्षा करता है कि सभी यातायात, जिसमें एक अविभाजित दो-तरफ़ा सड़क पर विपरीत दिशा का यातायात भी शामिल है, चमकती लाल लाइटों के साथ रुकी हुई स्कूल बस के लिए रुके, और तब तक रुका रहे जब तक लाइटें बंद न हो जाएँ और स्टॉप आर्म वापस न ले लिया जाए।"},"69":{"q":"फ्लोरिडा कानून के तहत, विपरीत दिशा में चल रहे ड्राइवरों को एक रुकी हुई स्कूल बस के लिए रुकने की आवश्यकता तब नहीं होती जब सड़क निम्नलिखित में से किससे विभाजित हो?","options":["एक अकेली ठोस पीली केंद्र रेखा","एक पेंट की हुई दो-तरफ़ा बाएँ-मुड़ाव लेन","एक उठा हुआ मीडियन, एक भौतिक बैरियर, या कम से कम 5 फ़ुट का बिना पक्की की हुई जगह","रिफ्लेक्टिव लेन मार्करों की एक पंक्ति"],"explanation":"Fla. Stat. 316.172(2) विपरीत दिशा के यातायात को रुकने से केवल तभी छूट देता है जब विभाजित हाईवे यातायात को एक उठे हुए मीडियन, एक भौतिक बैरियर, या कम से कम 5 फ़ुट की बिना पक्की की हुई जगह से अलग करता है। केवल पेंट रेखाएँ योग्य नहीं हैं।"},"70":{"q":"यदि आपको अपने वाणिज्यिक मोटर वाहन को एक तरफ़ा या विभाजित फ्लोरिडा हाईवे के शोल्डर पर रोकना पड़े, तो आपको अपने तीन आपातकालीन चेतावनी उपकरण कहाँ रखने चाहिए?","options":["आ रहे यातायात की ओर 5 फ़ुट, 50 फ़ुट और 150 फ़ुट","सभी तीनों वाहन के पिछले हिस्से के 10 फ़ुट के भीतर","वाहन के आगे 25 फ़ुट, 75 फ़ुट और 125 फ़ुट","आ रहे यातायात की ओर 10 फ़ुट, 100 फ़ुट और 200 फ़ुट"],"explanation":"फ्लोरिडा CDL हैंडबुक (FMCSR 392.22) एक तरफ़ा या विभाजित हाईवे पर आ रहे यातायात की ओर 10 फ़ुट, 100 फ़ुट और 200 फ़ुट पर चेतावनी उपकरण रखने की आवश्यकता रखती है।"},"71":{"q":"अपने वाणिज्यिक वाहन को किसी फ्लोरिडा हाईवे के चलित भाग या शोल्डर पर रोकने के बाद, आपको कितने सेकंड के भीतर अपनी हैज़र्ड (चार-तरफ़ा फ्लैशर) चेतावनी लाइटें सक्रिय करनी चाहिए?","options":["30 मिनट के भीतर, केवल रात में","केवल तभी जब चेतावनी त्रिकोण पहले ही रखे जा चुके हों","तुरंत, और 10 मिनट के भीतर चेतावनी उपकरण रखें","हैज़र्ड लाइटों के लिए कोई समय आवश्यकता नहीं है"],"explanation":"फ्लोरिडा CDL हैंडबुक में अपनाए गए FMCSR 392.22 के तहत, एक रुके हुए CMV को तुरंत अपनी हैज़र्ड चेतावनी फ्लैशर चालू करनी चाहिए और 10 मिनट के भीतर चेतावनी उपकरण (त्रिकोण/फ्लेयर) रखने चाहिए।"},"72":{"q":"दोनों दिशाओं में यातायात ले जा रही एक टू-लेन फ्लोरिडा सड़क पर, आपका CMV रुका होने पर चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["वाहन के 10 फ़ुट के भीतर और उसके 100 फ़ुट पीछे और आगे","केवल वाहन के 200 फ़ुट पीछे","केवल वाहन के अगले बंपर पर","केवल 50 फ़ुट पीछे और 50 फ़ुट आगे"],"explanation":"फ्लोरिडा CDL हैंडबुक (FMCSR 392.22) निर्देश देती है कि टू-लेन या अविभाजित सड़क पर आप एक चेतावनी उपकरण वाहन के 10 फ़ुट के भीतर और एक रुके हुए वाहन के 100 फ़ुट पीछे और एक 100 फ़ुट आगे रखें।"},"73":{"q":"आपकी दिशा में तीन या अधिक लेन वाली एक फ्लोरिडा सड़क पर, सामान्य दायीं-लेन नियम धीमी गति वाले वाहनों, जिनमें ट्रक भी शामिल हैं, से क्या करने की अपेक्षा करता है?","options":["गति की परवाह किए बिना हमेशा केंद्र लेन में चलें","दायीं-लेन के यातायात को साफ़ रखने के लिए सबसे बायीं लेन का उपयोग करें","बिना किसी प्रतिबंध के किसी भी लेन को स्वतंत्र रूप से चुनें","ओवरटेक करने, पास करने, या बाएँ मुड़ने की तैयारी को छोड़कर दायीं-हाथ की लेन में रहें"],"explanation":"Fla. Stat. 316.081 अपेक्षा करता है कि यातायात की सामान्य गति से धीमे चल रहे किसी भी वाहन को ओवरटेक करने/पास करने या बाएँ मुड़ने की तैयारी के अलावा दायीं-हाथ की लेन (या दायें किनारे के यथासंभव निकट) का उपयोग करना चाहिए।"},"74":{"q":"व्यवसायिक या आवासीय जिलों के बाहर, जहाँ कोई अन्य सीमा पोस्ट नहीं की गई है, वहाँ फ्लोरिडा की वैधानिक डिफ़ॉल्ट अधिकतम गति सीमा क्या है?","options":["55 mph","70 mph","65 mph","45 mph"],"explanation":"Fla. Stat. 316.183/316.187 व्यवसायिक या आवासीय जिलों के बाहर के स्थानों पर वैधानिक अधिकतम 55 mph निर्धारित करते हैं जब तक कि कोई अलग सीमा पोस्ट न की गई हो; व्यवसायिक या आवासीय जिलों में 30 mph लागू होती है।"},"75":{"q":"70 mph पर पोस्ट की गई कम से कम चार लेन वाली एक फ्लोरिडा इंटरस्टेट हाईवे पर, वैधानिक न्यूनतम गति सीमा क्या है?","options":["40 mph","55 mph","45 mph","50 mph"],"explanation":"Fla. Stat. 316.183 कम से कम चार लेन वाली विभाजित इंटरस्टेट हाईवे पर, जहाँ अधिकतम पोस्ट की गई सीमा 70 mph है, 50 mph की न्यूनतम गति स्थापित करता है।"},"76":{"q":"फ्लोरिडा के डिस्ट्रैक्टेड ड्राइविंग कानून (Fla. Stat. 316.305) के तहत, चलते हुए मोटर वाहन का संचालन करते समय क्या निषिद्ध है?","options":["फ़ोन कॉल के लिए हैंड्स-फ़्री ब्लूटूथ स्पीकर का कोई भी उपयोग","गैर-आवाज़ संचार जैसे टेक्स्टिंग, ई-मेलिंग, या इंस्टेंट मैसेजिंग के लिए मैन्युअल रूप से डेटा टाइप करना या पढ़ना","नेविगेशन वॉइस निर्देश सुनना","कैब में एक माउंट किया हुआ फ़ोन दिखाई देना"],"explanation":"Fla. Stat. 316.305 ड्राइविंग करते समय गैर-आवाज़ अंतर-व्यक्तिगत संचार (टेक्स्टिंग, ई-मेल, इंस्टेंट मैसेजिंग) के लिए किसी वायरलेस डिवाइस पर अक्षरों को मैन्युअल रूप से टाइप या दर्ज करने और डेटा भेजने या पढ़ने पर रोक लगाता है।"},"77":{"q":"फ्लोरिडा के टेक्स्टिंग-व्हाइल-ड्राइविंग कानून (Fla. Stat. 316.305) के प्रवर्तन के बारे में कौन-सा कथन सही है?","options":["यह एक द्वितीयक (secondary) अपराध है जिसके लिए पहले किसी अन्य उल्लंघन की आवश्यकता होती है","यह एक प्राथमिक (primary) अपराध है, इसलिए एक अधिकारी केवल टेक्स्टिंग के लिए ही किसी ड्राइवर को रोक सकता है और चालान कर सकता है","यह केवल 18 वर्ष से कम आयु के ड्राइवरों पर लागू होता है","यह केवल सूर्यास्त और सूर्योदय के बीच लागू होता है"],"explanation":"2019 से, Fla. Stat. 316.305 ड्राइविंग करते समय टेक्स्टिंग को एक प्राथमिक अपराध बनाता है, जो अधिकारियों को केवल उस उल्लंघन के लिए ही किसी ड्राइवर को रोकने और चालान करने का अधिकार देता है।"},"78":{"q":"जब फ्लोरिडा किसी तूफ़ान के दौरान एक निकासी मार्ग पर इमरजेंसी शोल्डर यूज़ (ESU) सक्रिय करता है, तो किन वाहनों को खोली गई शोल्डर लेन का उपयोग करने की अनुमति नहीं है?","options":["यात्री कारें और पिकअप ट्रक","बड़े ट्रक, बसें और ट्रेलर","मोटरसाइकिल और SUV","सभी वाहनों को शोल्डर का समान रूप से उपयोग करने की अनुमति है"],"explanation":"फ्लोरिडा की FDOT इमरजेंसी शोल्डर यूज़ योजना (जिसने कॉन्ट्राफ़्लो का स्थान लिया) के तहत, बड़े ट्रक, बसों और ट्रेलरों को छोड़कर सभी मोटर चालक किसी तूफ़ान निकासी के दौरान पक्के शोल्डर का अस्थायी यात्रा लेन के रूप में उपयोग कर सकते हैं।"},"79":{"q":"भारी-शुल्क वाणिज्यिक वाहनों के विस्तारित आइडलिंग के संबंध में, कौन-सा कथन वर्तमान फ्लोरिडा कानून को दर्शाता है?","options":["फ्लोरिडा राज्यव्यापी रूप से 3 मिनट से अधिक की सभी ट्रक आइडलिंग पर प्रतिबंध लगाता है","फ्लोरिडा हर समय राज्यव्यापी रूप से आइडलिंग को 5 मिनट तक सीमित करता है","फ्लोरिडा अपेक्षा करता है कि राज्य में कहीं भी ट्रक पार्क होने पर इंजन बंद रहें","फ्लोरिडा में कोई राज्यव्यापी भारी-शुल्क वाहन आइडलिंग-कमी सीमा नहीं है; इसका पूर्व आइडलिंग नियम निरस्त कर दिया गया था"],"explanation":"फ्लोरिडा का भारी-शुल्क वाहन आइडलिंग-कमी नियम (Fla. Admin. Code 62-285.420) निरस्त कर दिया गया था, इसलिए कोई राज्यव्यापी आइडलिंग समय सीमा नहीं है; ड्राइवरों को फिर भी स्थानीय अध्यादेशों की जाँच करनी चाहिए। यह राज्यव्यापी एंटी-आइडलिंग कानूनों वाले राज्यों से भिन्न है।"},"80":{"q":"फ्लोरिडा में वाणिज्यिक ड्राइवर लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["फ्लोरिडा डिपार्टमेंट ऑफ़ ट्रांसपोर्टेशन (FDOT)","फ्लोरिडा डिपार्टमेंट ऑफ़ हाईवे सेफ़्टी एंड मोटर व्हीकल्स (FLHSMV)","फ़ेडरल मोटर कैरियर सेफ़्टी एडमिनिस्ट्रेशन (FMCSA)","यू.एस. डिपार्टमेंट ऑफ़ मोटर व्हीकल्स"],"explanation":"फ्लोरिडा में, CDL फ्लोरिडा डिपार्टमेंट ऑफ़ हाईवे सेफ़्टी एंड मोटर व्हीकल्स (FLHSMV) द्वारा जारी और प्रशासित किए जाते हैं। FMCSA संघीय मानक निर्धारित करता है, लेकिन राज्य एजेंसी वास्तविक क्रेडेंशियल जारी करती है। स्रोत: FLHSMV, कमर्शियल ड्राइवर लाइसेंस पेज।"},"81":{"q":"मूल फ्लोरिडा CDL या कमर्शियल लर्नर परमिट के लिए आवेदन करते समय, आवेदक को FLHSMV को कौन-सा दस्तावेज़ों का सेट प्रस्तुत करना चाहिए?","options":["केवल एक वर्तमान फ्लोरिडा क्लास E ड्राइवर लाइसेंस और एक फ़ोटो","एक पासपोर्ट और एक अकेला उपयोगिता बिल, बिना किसी सोशल सिक्योरिटी दस्तावेज़ के","केवल एक DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र और एक फ़िंगरप्रिंट कार्ड","पहचान का प्रमाण, सोशल सिक्योरिटी नंबर का प्रमाण, और फ्लोरिडा आवासीय पते के दो प्रमाण"],"explanation":"FLHSMV द्वारा लागू संघीय REAL ID अधिनियम के तहत, मूल CDL/CLP आवेदकों को पहचान, अपना सोशल सिक्योरिटी नंबर, और फ्लोरिडा आवासीय पते के दो प्रमाण साबित करने वाले मूल दस्तावेज़ प्रस्तुत करने चाहिए। स्रोत: FLHSMV, What to Bring / कमर्शियल ड्राइवर लाइसेंस पेज।"},"82":{"q":"फ्लोरिडा CDL और CLP क्रेडेंशियल REAL ID अनुपालक हैं। REAL ID अधिनियम आवेदकों से क्या अपेक्षा करता है?","options":["किसी भी पहचान दस्तावेज़ के बजाय एक नोटरीकृत शपथपत्र प्रस्तुत करना","पहचान, सोशल सिक्योरिटी नंबर, और आवासीय पते को सत्यापित करने वाले मूल दस्तावेज़ प्रस्तुत करना","सभी आवश्यकताओं के एकमात्र स्वीकार्य प्रमाण के रूप में एक संघीय पासपोर्ट कार्ड प्रदान करना","व्यक्तिगत रूप से दस्तावेज़ समीक्षा के स्थान पर एक ऑनलाइन पहचान क्विज़ पूरी करना"],"explanation":"REAL ID आवेदकों से अपेक्षा करता है कि वे पहले बार कार्यालय में जारी होने पर पहचान, सोशल सिक्योरिटी नंबर, और आवासीय पते को मान्य करने वाले मूल दस्तावेज़ प्रस्तुत करें। एक बार प्रदान किए जाने के बाद, उन्हें आम तौर पर तभी फिर से दिखाने की आवश्यकता होती है जब जानकारी बदल जाए। स्रोत: FLHSMV, REAL ID पेज।"},"83":{"q":"एक CDL या CLP आवेदक को FLHSMV को फ्लोरिडा आवासीय पते के कितने प्रमाण प्रस्तुत करने चाहिए?","options":["CDL के लिए आवासीय पते के किसी प्रमाण की आवश्यकता नहीं है","आवासीय पते के चार प्रमाण, सभी उपयोगिता बिल","एक प्रमाण, लेकिन वह एक पासपोर्ट होना चाहिए","आवेदक के नाम पर फ्लोरिडा आवासीय पते के दो प्रमाण"],"explanation":"FLHSMV अपेक्षा करता है कि CLP और CDL आवेदक अपने नाम पर फ्लोरिडा आवासीय पते के दो प्रमाण प्रस्तुत करें (दो List A से, या एक List A से और एक List B से)। स्रोत: FLHSMV, What to Bring पेज।"},"84":{"q":"फ़ेडरल मोटर कैरियर सेफ़्टी रेगुलेशन्स अपेक्षा करते हैं कि CDL प्राप्त करने या नवीनीकृत करने वाला हर ड्राइवर FLHSMV के साथ संचालन की कितनी श्रेणियों में स्वयं-प्रमाणित (self-certify) करे?","options":["दो श्रेणियाँ","चार श्रेणियाँ","छह श्रेणियाँ","तीन श्रेणियाँ"],"explanation":"ड्राइवरों को चार श्रेणियों में से एक में स्वयं-प्रमाणित करना चाहिए: non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। स्रोत: FLHSMV, CDL मेडिकल सर्टिफिकेशन पेज।"},"85":{"q":"निम्नलिखित में से कौन-सी FLHSMV द्वारा उपयोग की जाने वाली चार CDL स्वयं-प्रमाणन श्रेणियों में से एक है?","options":["Non-excepted interstate","Excepted federal hazmat","Restricted intrastate agricultural-only","Provisional interstate commerce"],"explanation":"चार वैध स्वयं-प्रमाणन श्रेणियाँ हैं non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। 'Non-excepted interstate' उन ड्राइवरों के लिए श्रेणी है जिन्हें एक संघीय मेडिकल प्रमाणपत्र बनाए रखना होता है। स्रोत: FLHSMV, CDL मेडिकल सर्टिफिकेशन पेज।"},"86":{"q":"एक फ्लोरिडा CDL ड्राइवर 'non-excepted interstate' के रूप में स्वयं-प्रमाणित करता है। यह कौन-सा सतत मेडिकल दायित्व उत्पन्न करता है?","options":["वे किसी भी मेडिकल प्रमाणन से स्थायी रूप से छूट प्राप्त हैं","उन्हें हर पंद्रह वर्ष में केवल एक बार मेडिकल जाँच की आवश्यकता होती है","उन्हें एक वैध DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र प्राप्त करना चाहिए और FLHSMV के साथ फ़ाइल पर रखना चाहिए","उन्हें स्वयं-प्रमाणित करना चाहिए लेकिन कभी मेडिकल एग्ज़ामिनर के प्रमाणपत्र की आवश्यकता नहीं होती"],"explanation":"non-excepted interstate (या non-excepted intrastate) के रूप में प्रमाणित करने वाले ड्राइवरों को एक वैध DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र बनाए रखना चाहिए और इसे FLHSMV के साथ फ़ाइल पर वर्तमान रखना चाहिए। स्रोत: FLHSMV, CDL मेडिकल सर्टिफिकेशन पेज।"},"87":{"q":"फ्लोरिडा CDL प्रक्रिया में DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र (जिसे अक्सर 'मेड कार्ड' कहा जाता है) किसलिए उपयोग किया जाता है?","options":["यह साबित करने के लिए कि ड्राइवर ने एंट्री-लेवल ड्राइवर ट्रेनिंग पूरी कर ली है","ड्राइवर के फ्लोरिडा निवास के प्रमाण के रूप में काम करने के लिए","अनुभवी ड्राइवरों के लिए नॉलेज और स्किल्स परीक्षणों को बदलने के लिए","यह दस्तावेज़ करने के लिए कि एक ड्राइवर एक वाणिज्यिक मोटर वाहन को संचालित करने के लिए शारीरिक योग्यता मानकों को पूरा करता है"],"explanation":"DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र यह दस्तावेज़ करता है कि एक प्रमाणित मेडिकल एग्ज़ामिनर ने ड्राइवर को एक वाणिज्यिक मोटर वाहन को संचालित करने के लिए शारीरिक रूप से योग्य पाया। यह निवास के प्रमाण और नॉलेज/स्किल्स परीक्षणों से अलग है। स्रोत: FLHSMV, CDL मेडिकल सर्टिफिकेशन पेज।"},"88":{"q":"एक फ्लोरिडा non-excepted interstate CDL धारक को अपना स्वयं-प्रमाणन और मेडिकल जानकारी वर्तमान रखने की आवश्यकता है। इसे प्रबंधित करने का एक FLHSMV-प्रदत्त तरीका क्या है?","options":["केवल FMCSA राष्ट्रीय कार्यालय को प्रमाणपत्र फ़ैक्स करना","ऑनलाइन MyDMV Portal CDL मेडिकल स्वयं-प्रमाणन सेवा","प्रमाणपत्र को किसी सोशल मीडिया खाते पर पोस्ट करना","इसे अपडेट करने का कोई तरीका नहीं है; जारी होने के बाद इसे बदला नहीं जा सकता"],"explanation":"FLHSMV MyDMV Portal के माध्यम से एक CDL मेडिकल स्वयं-प्रमाणन सेवा प्रदान करता है जहाँ ड्राइवर अपनी स्वयं-प्रमाणन श्रेणी और मेडिकल जानकारी जमा कर सकते हैं। मेडिकल एग्ज़ामिनरों को भी अब DOT परीक्षा परिणाम इलेक्ट्रॉनिक रूप से प्रेषित करना आवश्यक है। स्रोत: FLHSMV, CDL मेडिकल स्वयं-प्रमाणन (MyDMV Portal)।"},"89":{"q":"यदि एक non-excepted CDL ड्राइवर FLHSMV के साथ फ़ाइल पर एक वर्तमान मेडिकल प्रमाणन रखने में विफल रहता है तो क्या होता है?","options":["CDL विशेषाधिकार को तब तक डाउनग्रेड या अयोग्य किया जा सकता है जब तक वैध मेडिकल प्रमाणन बहाल नहीं हो जाता","कुछ नहीं होता; मेडिकल प्रमाणपत्र पूरी तरह वैकल्पिक है","ड्राइवर को स्वचालित रूप से एक हैज़मैट एंडोर्समेंट मिल जाता है","ड्राइवर की CLP होल्डिंग अवधि माफ़ कर दी जाती है"],"explanation":"यदि एक non-excepted ड्राइवर का मेडिकल प्रमाणन समाप्त हो जाता है, तो FLHSMV CDL को एक गैर-वाणिज्यिक लाइसेंस में डाउनग्रेड कर सकता है या तब तक वाणिज्यिक विशेषाधिकार को अयोग्य कर सकता है जब तक वर्तमान मेडिकल दस्तावेज़ प्रदान नहीं किए जाते। स्रोत: FLHSMV, CDL मेडिकल सर्टिफिकेशन पेज।"},"90":{"q":"पहली बार के क्लास A या क्लास B CDL के लिए परीक्षण से पहले, एक फ्लोरिडा आवेदक को कौन-सी संघीय प्रशिक्षण आवश्यकता पूरी करनी चाहिए?","options":["राज्य के साथ पंजीकृत एक चार-वर्षीय शिक्षुता (apprenticeship) पूरी करना","एक अलग FBI पृष्ठभूमि जाँच पास करना","FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर सूचीबद्ध एक प्रदाता से एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) पूरी करना","दस वर्षों तक एक अप्रतिबंधित क्लास E लाइसेंस रखना"],"explanation":"7 फ़रवरी 2022 को या उसके बाद प्राप्त कमर्शियल लर्नर परमिट के लिए, पहली बार के क्लास A/B CDL आवेदकों को CDL स्किल्स टेस्ट लेने से पहले FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर सूचीबद्ध एक प्रदाता से ELDT पूरी करनी चाहिए। स्रोत: FMCSA एंट्री-लेवल ड्राइवर ट्रेनिंग; FLHSMV कमर्शियल ड्राइवर लाइसेंस पेज।"},"91":{"q":"इनमें से कौन-सा एंडोर्समेंट आवेदन भी परीक्षण से पहले ELDT (एंट्री-लेवल ड्राइवर ट्रेनिंग) आवश्यकता को ट्रिगर करता है?","options":["पहली बार का खतरनाक सामग्री (H), यात्री (P), या स्कूल बस (S) एंडोर्समेंट","एक मौजूदा संयोजन वाहन विशेषाधिकार का नवीनीकरण","एक क्लास E लाइसेंस में एक मोटरसाइकिल एंडोर्समेंट जोड़ना","समान एंडोर्समेंट के साथ एक खोए हुए CDL को बदलना"],"explanation":"पहली बार के क्लास A/B CDL आवेदकों और क्लास B-से-क्लास A अपग्रेड के अतिरिक्त, पहली बार का खतरनाक सामग्री (H), यात्री (P), या स्कूल बस (S) एंडोर्समेंट चाहने वाले आवेदकों के लिए ELDT आवश्यक है। स्रोत: FMCSA एंट्री-लेवल ड्राइवर ट्रेनिंग; FLHSMV।"},"92":{"q":"किसी आवेदक के ELDT पूरी करने के बाद, FLHSMV को कैसे पता चलता है कि प्रशिक्षण समाप्त हो गया?","options":["आवेदक एक कागज़ी डिप्लोमा सीधे गवर्नर के कार्यालय को डाक से भेजता है","FLHSMV भौतिक रूप से उस ट्रक का निरीक्षण करता है जिसमें ड्राइवर ने प्रशिक्षण लिया","प्रशिक्षण प्रदाता प्रमाणन FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री को जमा करता है, जिसे राज्य परीक्षण से पहले जाँचता है","कोई सत्यापन नहीं होता; आवेदक बस यह बताता है कि यह पूरा हो गया"],"explanation":"प्रशिक्षण प्रदाता ड्राइवर के ELDT पूर्णता को इलेक्ट्रॉनिक रूप से FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री को जमा करता है, और राज्य स्किल्स (या, H के लिए, नॉलेज) टेस्ट की अनुमति देने से पहले रिकॉर्ड को सत्यापित करता है। स्रोत: FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री।"},"93":{"q":"फ्लोरिडा CDL के रास्ते पर एक व्यक्ति आमतौर पर कौन-सा पहला क्रेडेंशियल प्राप्त करता है, जो उन्हें एक वाणिज्यिक वाहन चलाने का अभ्यास करने की अनुमति देता है?","options":["तुरंत जारी किया गया एक पूर्ण अप्रतिबंधित CDL","एक खतरनाक सामग्री एंडोर्समेंट कार्ड","एक DOT मेडिकल एग्ज़ामिनर का प्रमाणपत्र","एक कमर्शियल लर्नर परमिट (CLP)"],"explanation":"आवेदक पहले आवश्यक नॉलेज टेस्ट पास करके एक कमर्शियल लर्नर परमिट (CLP) प्राप्त करते हैं; CLP उन्हें स्किल्स टेस्ट लेने से पहले एक योग्य CDL धारक के साथ सार्वजनिक सड़कों पर अभ्यास करने देता है। स्रोत: FLHSMV, कमर्शियल ड्राइवर लाइसेंस पेज।"},"94":{"q":"फ्लोरिडा द्वारा अनुसरण किए जाने वाले संघीय नियमों के तहत, CDL स्किल्स टेस्ट लेने से पहले एक ड्राइवर को CLP कम से कम कितने समय तक रखना चाहिए?","options":["कम से कम 90 दिन","कोई न्यूनतम प्रतीक्षा अवधि नहीं है","कम से कम 14 दिन","कम से कम एक पूरा वर्ष"],"explanation":"संघीय विनियमन अपेक्षा करता है कि एक CLP धारक CDL स्किल्स टेस्ट लेने से पहले CLP जारी होने के बाद कम से कम 14 दिन प्रतीक्षा करे। स्रोत: FMCSA 49 CFR 383.25; FLHSMV CDL प्रक्रिया।"},"95":{"q":"एक नए आवेदन की आवश्यकता होने से पहले एक कमर्शियल लर्नर परमिट कब तक वैध रह सकता है?","options":["जारी होने की तारीख से एक वर्ष तक, उस वर्ष के भीतर नवीनीकरण की अनुमति के साथ","दस वर्ष तक, एक पासपोर्ट की तरह","जारी होने से केवल 48 घंटे","एक बार जारी होने पर यह कभी समाप्त नहीं होता"],"explanation":"संघीय नियम एक CLP को प्रारंभिक जारी होने से एक वर्ष तक वैध होने की अनुमति देते हैं; एक वर्ष से कम के लिए जारी किए गए CLP को तब तक नवीनीकृत किया जा सकता है जब तक यह कुल मिलाकर एक वर्ष से अधिक वैध न हो। स्रोत: FMCSA 49 CFR 383.25; FLHSMV।"},"96":{"q":"फ्लोरिडा CDL स्किल्स टेस्ट किन तीन भागों से बना होता है?","options":["लिखित निबंध, मौखिक साक्षात्कार, और एक टाइपिंग टेस्ट","प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","दृष्टि स्क्रीनिंग, श्रवण परीक्षण, और प्रतिक्रिया-समय परीक्षण","टायर बदलना, ऑयल बदलना, और इंजन रीबिल्ड"],"explanation":"CDL स्किल्स टेस्ट तीन भागों से बना होता है: एक प्री-ट्रिप वाहन निरीक्षण, एक बेसिक वाहन नियंत्रण परीक्षण, और एक ऑन-रोड ड्राइविंग परीक्षण। स्रोत: FLHSMV, कमर्शियल ड्राइवर लाइसेंस पेज।"},"97":{"q":"फ्लोरिडा CDL स्किल्स टेस्ट किस भाषा में आयोजित किया जाना चाहिए?","options":["आवेदक द्वारा चुनी गई कोई भी भाषा","केवल स्पैनिश","अंग्रेज़ी","यह किसी भी बोली जाने वाली भाषा में आयोजित नहीं किया जाता"],"explanation":"FLHSMV अपेक्षा करता है कि CDL स्किल्स टेस्ट अंग्रेज़ी में आयोजित किया जाए, जो इस संघीय आवश्यकता के अनुरूप है कि वाणिज्यिक ड्राइवर ट्रैफ़िक संकेतों को समझ सकें और अंग्रेज़ी में संवाद कर सकें। स्रोत: FLHSMV, कमर्शियल ड्राइवर लाइसेंस पेज।"},"98":{"q":"फ्लोरिडा CDL प्राप्त करने की न्यूनतम आयु क्या है, और 21 से कम आयु के ड्राइवरों पर कौन-सा प्रतिबंध लागू होता है?","options":["कम से कम 18 वर्ष, लेकिन 21 से कम आयु के ड्राइवर आम तौर पर intrastate संचालन तक सीमित होते हैं","कम से कम 16 वर्ष, बिना किसी परिचालन प्रतिबंध के","किसी भी CDL क्लास के लिए कम से कम 25 वर्ष","कम से कम 21 वर्ष, बिना किसी अपवाद के"],"explanation":"फ्लोरिडा CDL आवेदकों की आयु कम से कम 18 वर्ष होनी चाहिए; 21 से कम आयु वाले आम तौर पर 21 वर्ष के होने तक intrastate (फ्लोरिडा के भीतर) वाणिज्य तक सीमित होते हैं। स्रोत: FLHSMV, कमर्शियल ड्राइवर लाइसेंस पेज।"},"99":{"q":"एक फ्लोरिडा CDL धारक को अपना वाणिज्यिक ड्राइवर लाइसेंस कितनी बार नवीनीकृत करना चाहिए?","options":["हर छह महीने","हर बीस वर्ष","केवल एक बार, क्योंकि एक CDL कभी समाप्त नहीं होता","हर आठ वर्ष"],"explanation":"फ्लोरिडा ड्राइवर लाइसेंस, जिनमें CDL भी शामिल हैं, हर आठ वर्ष में नवीनीकृत किए जाने चाहिए; CDL को नवीनीकृत करना होता है और इन्हें विस्तारित नहीं किया जा सकता। सटीक शुल्क बदल सकते हैं, इसलिए वर्तमान राशि के लिए FLHSMV जाँचें। स्रोत: FLHSMV, Renew or Replace Your Florida Driver License पेज।"}},"ar":{"0":{"q":"على طرق فلوريدا السريعة، ما هو الحد الأقصى للعرض الخارجي الإجمالي المسموح به للمركبة أو حمولتها (باستثناء أجهزة السلامة المطلوبة) دون تصريح للأحجام الزائدة؟","options":["96 بوصة (8 أقدام)","102 بوصة (8 أقدام و6 بوصات)","108 بوصة (9 أقدام)","114 بوصة (9 أقدام و6 بوصات)"],"explanation":"يحدد قانون فلوريدا §316.515 الحد الأقصى للعرض الخارجي الإجمالي لأي مركبة أو حمولتها بـ102 بوصة (8 أقدام و6 بوصات)، باستثناء أجهزة السلامة. ويتطلب تجاوز ذلك الحصول على تصريح للأحجام الزائدة من FDOT."},"1":{"q":"ما هو الحد الأقصى للارتفاع، شاملًا الحمولة، للمركبة على طرق فلوريدا السريعة دون تصريح؟","options":["13 قدمًا","14 قدمًا","14 قدمًا و6 بوصات","13 قدمًا و6 بوصات"],"explanation":"بموجب قانون فلوريدا §316.515، لا يجوز أن يتجاوز ارتفاع أي مركبة 13 قدمًا و6 بوصات، شاملًا الحمولة. (يُسمح لناقلات السيارات بارتفاع يصل إلى 14 قدمًا.) ويُحمّل قانون فلوريدا السائق مسؤولية تجاوز الهياكل العلوية بأمان."},"2":{"q":"في فلوريدا، ما هو الحد الأقصى لطول نصف المقطورة العاملة في تركيبة جرار شاحنة ونصف مقطورة على نظام الطرق السريعة للولاية (قبل تطبيق بدلات الطول الخاصة)؟","options":["48 قدمًا","45 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"يحدد قانون فلوريدا §316.515 طول نصف المقطورة في تركيبة جرار شاحنة ونصف مقطورة بـ48 قدمًا كأقصى بُعد إجمالي؛ ويجوز لأنصاف المقطورات التي يزيد طولها عن 48 قدمًا ولا يتجاوز 57 قدمًا العمل فقط على الطرق غير المقيّدة من قِبل FDOT أو السلطات المحلية."},"3":{"q":"ما هو الحد الأقصى لطول الشاحنة المستقيمة المفردة بأقصى بُعد إجمالي بموجب قانون فلوريدا؟","options":["35 قدمًا","45 قدمًا","40 قدمًا","48 قدمًا"],"explanation":"يحدد قانون فلوريدا §316.515 طول الشاحنة المستقيمة (مركبة مفردة) بـ40 قدمًا كأقصى بُعد إجمالي."},"4":{"q":"في تركيبة فلوريدا المكونة من جرار شاحنة ونصف مقطورة ومقطورة (مقطورة مزدوجة/توأم)، ما هو الحد الأقصى لطول كل مقطورة على حدة؟","options":["24 قدمًا","28 قدمًا","33 قدمًا","40 قدمًا"],"explanation":"ينص قانون فلوريدا §316.515 على أنه لا يجوز أن يتجاوز طول أي نصف مقطورة أو مقطورة عاملة في تركيبة جرار شاحنة ونصف مقطورة ومقطورة 28 قدمًا، بما يتوافق مع المعيار الفيدرالي للمقطورات التوأم."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي المفروض على طريق فلوريدا السريع من قِبل عجلات أي محور مفرد واحد للمركبة؟","options":["18,000 رطل","22,400 رطل","24,000 رطل","20,000 رطل"],"explanation":"يحدد قانون فلوريدا §316.535 الوزن الإجمالي المفروض من قِبل عجلات أي محور مفرد واحد بـ20,000 رطل."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي الكلي، شاملًا جميع تفاوتات الإنفاذ، لأي مركبة أو تركيبة مركبات على طرق فلوريدا السريعة؟","options":["73,280 رطل","76,000 رطل","80,000 رطل","88,000 رطل"],"explanation":"يحدد قانون فلوريدا §316.535 سقف الوزن الإجمالي الكلي لأي مركبة أو تركيبة مركبات بـ80,000 رطل، شاملًا جميع تفاوتات الإنفاذ. ويتطابق هذا مع الحد الفيدرالي لنظام الطرق السريعة بين الولايات."},"7":{"q":"على طرق فلوريدا والطرق السريعة بين الولايات، يكون الحد الأقصى للوزن المسموح به على مجموعة محاور ترادفية (محوران متتاليان متباعدان أكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة) بشكل عام:","options":["34,000 رطل","30,000 رطل","40,000 رطل","44,000 رطل"],"explanation":"بموجب معيار الوزن الفيدرالي المطبق في فلوريدا، تكون مجموعة المحاور الترادفية محدودة بـ34,000 رطل. وتطبق فلوريدا صيغة الجسور الفيدرالية وسقف الوزن الإجمالي البالغ 80,000 رطل وفق القانون §316.535 على نظام الطرق السريعة بين الولايات."},"8":{"q":"تستخدم فلوريدا صيغة الجسور الفيدرالية لتحديد الوزن بناءً على تباعد المحاور. في الصيغة W = 500[LN/(N-1) + 12N + 36]، ماذا يمثل الحرف 'L'؟","options":["وزن الحمولة القانوني بالأرطال","المسافة بالأقدام بين أطراف مجموعة من المحاور","طول المقطورة بالبوصات","الوزن الإجمالي المرخص للمركبة"],"explanation":"في صيغة الجسور الفيدرالية المعتمدة في قانون فلوريدا §316.535، يمثل L المسافة بالأقدام بين أطراف أي مجموعة من محورين أو أكثر متتاليين، ويمثل N عدد المحاور في المجموعة، ويمثل W الوزن الإجمالي المسموح به."},"9":{"q":"صُممت صيغة الجسور الفيدرالية المستخدمة في فلوريدا بشكل أساسي لحماية ماذا؟","options":["إطارات المركبة من التحميل الزائد","السائق من الإرهاق","الحمولة من الانزلاق","الجسور وسطح الطريق من الوزن المركّز"],"explanation":"توزّع صيغة الجسور الفيدرالية في قانون فلوريدا §316.535 الوزن على مسافة أكبر (محاور أكثر، تباعد أطول) لحماية الجسور والأرصفة؛ فالمحاور المتقاربة تركّز الحمل ويجب أن يكون وزنها أقل."},"10":{"q":"أي وكالة في فلوريدا تصدر تصاريح الأحجام الزائدة والأوزان الزائدة للحمولات التي تتجاوز حدود الحجم أو الوزن القانونية؟","options":["إدارة فلوريدا للسلامة على الطرق السريعة والمركبات الآلية (DHSMV)","دورية فلوريدا للطرق السريعة (FHP)","إدارة فلوريدا للنقل (FDOT)","الإدارة الفيدرالية الأمريكية لسلامة ناقلات المركبات الآلية (FMCSA)"],"explanation":"تصدر إدارة فلوريدا للنقل (FDOT) تصاريح الأحجام الزائدة/الأوزان الزائدة من خلال مكتب التصاريح ونظام طلب التصاريح عبر الإنترنت للحمولات التي تتجاوز الحدود الواردة في قانوني فلوريدا §316.515 و§316.535."},"11":{"q":"حمولة عرضها 110 بوصة. قبل نقلها على طريق فلوريدا السريع، يجب على السائق:","options":["الحصول على تصريح للأحجام الزائدة من FDOT","ألا يفعل شيئًا؛ فعرض 110 بوصة قانوني","تخفيض السرعة بمقدار 10 أميال في الساعة فقط","الحصول على موافقة الشرطة المحلية فقط"],"explanation":"بما أن 110 بوصة تتجاوز الحد القانوني للعرض البالغ 102 بوصة (8 أقدام و6 بوصات) في قانون فلوريدا §316.515، فإن النقل يتطلب تصريحًا للأحجام الزائدة من FDOT. ولا يمكن أن تتجاوز الحمولات العرض القانوني دون تصريح."},"12":{"q":"أي نوع من تصاريح FDOT يصرّح بنقل واحد للأحجام الزائدة/الأوزان الزائدة من نقطة منشأ واحدة إلى وجهة واحدة؟","options":["تصريح شامل سنوي","تصريح رحلة (رحلة واحدة)","تصريح شامل خاص بمسار محدد","تصريح شامل خاص بمركبة محددة"],"explanation":"تصدر FDOT تصريح رحلة (رحلة واحدة) لنقل واحد؛ بينما تغطي التصاريح الشاملة (السنوية أو الخاصة بمسار محدد أو الخاصة بمركبة محددة) عمليات النقل المتكررة على مدى فترة أطول. وعادةً ما تكون تصاريح الرحلة صالحة لعدد محدود من الأيام لإتمام النقل."},"13":{"q":"بموجب قواعد تصاريح فلوريدا/FDOT، عند أي عرض تبدأ الحمولة ذات الحجم الزائد عمومًا في الاحتياج إلى مركبة مرافقة (دليل) واحدة على الأقل؟","options":["أكثر من 8 أقدام و6 بوصات","أكثر من 10 أقدام","أكثر من 12 قدمًا","أكثر من 16 قدمًا"],"explanation":"وفقًا لقواعد FDOT بشأن الحمولات ذات الأحجام الزائدة، تتطلب الحمولات التي يزيد عرضها عن 12 قدمًا عمومًا مركبة مرافقة واحدة على الأقل؛ وتتطلب الحمولات التي يزيد عرضها عن 14 قدمًا عادةً مركبتي مرافقة، وقد تتطلب الحمولات الأعرض مرافقة من جهات إنفاذ القانون."},"14":{"q":"الحمولة ذات الحجم الزائد المنقولة بموجب تصريح FDOT في فلوريدا يُطلب منها عمومًا أن تعرض:","options":["المصابيح الأمامية مشغّلة فقط أثناء النهار","لافتة تصريح خضراء فقط","عدم وضع علامات خاصة إذا كان العرض أقل من 12 قدمًا","لافتات 'OVERSIZE LOAD' وأعلام تحذيرية عند الزوايا/الأطراف"],"explanation":"تتطلب شروط تصريح FDOT أن تعرض الحمولات ذات الأحجام الزائدة لافتات تحذيرية مكتوب عليها 'OVERSIZE LOAD' وأعلامًا ملوّنة (حمراء/برتقالية) عند زوايا الحمولة وأعرض نقاطها كي يتمكن باقي مستخدمي الطريق من رؤية الحمولة ذات الأبعاد الزائدة."},"15":{"q":"وفقًا للقواعد الفيدرالية لتأمين الحمولة المتّبعة في فلوريدا، يجب أن يكون حد العمل الإجمالي (WLL) لأدوات الربط على الأقل أي نسبة من وزن الحمولة المؤمّنة؟","options":["النصف (50%)","الربع (25%)","الثلثان (67%)","الوزن الكامل (100%)"],"explanation":"تتطلب القواعد الفيدرالية لتأمين الحمولة (49 CFR 393.106)، التي تنفذها فلوريدا، أن يكون حد العمل الإجمالي لجميع أدوات الربط على الأقل نصف (50%) وزن الصنف أو الحمولة الجاري تأمينها."},"16":{"q":"بموجب قواعد تأمين الحمولة المطبقة في فلوريدا، الصنف من الحمولة الذي يبلغ طوله 5 أقدام أو أقل ويزن 1,100 رطل أو أقل يتطلب على الأقل كم عدد من أدوات الربط؟","options":["أداتا ربط","أداة ربط واحدة","ثلاث أدوات ربط","لا أدوات ربط إذا كان مسنودًا"],"explanation":"بموجب 49 CFR 393.110 (المنفّذة في فلوريدا)، يتطلب الصنف الذي يبلغ طوله 5 أقدام أو أقل ووزنه 1,100 رطل أو أقل حدًا أدنى من أداة ربط واحدة؛ أما الأصناف الأطول أو الأثقل فتتطلب أداتين أو أكثر."},"17":{"q":"بعد التحميل وبدء الرحلة، متى يجب على سائق CDL في فلوريدا أن يفحص الحمولة وأدوات التأمين أول مرة؟","options":["خلال أول 25 ميلًا","خلال أول 100 ميل","خلال أول 50 ميلًا","عند الوجهة فقط"],"explanation":"تتطلب القواعد الفيدرالية المتّبعة في فلوريدا (49 CFR 392.9) من السائق أن يفحص الحمولة وأدوات التأمين خلال أول 50 ميلًا بعد بدء الرحلة، وأن يعيد فحصها دوريًا بعد ذلك."},"18":{"q":"يوفّر قانون فلوريدا بعض أحكام تخفيف العقوبة أو أحكام التفاوت بشأن حدود الوزن بشكل أساسي لناقلي أي نوع من الحمولات؟","options":["البضائع العامة في الشاحنات الجافة","المواد الخطرة","الأمتعة المنزلية","المنتجات الزراعية الطبيعية غير المصنّعة"],"explanation":"توفّر قوانين المرور والوزن في فلوريدا (الفصل 316) أحكامًا خاصة بالتفاوت/العقوبة لنقل المنتجات الزراعية الطبيعية غير المصنّعة، إقرارًا بالطبيعة الموسمية المرتبطة بالمزارع لهذه الحمولات."},"19":{"q":"السائق الذي ينقل حمولة غير قابلة للتقسيم عرضها 14 قدمًا وتزن 120,000 رطل في فلوريدا يجب أن يفعل ماذا قبل النقل؟","options":["الحصول على تصريح للأحجام الزائدة والأوزان الزائدة من FDOT","لا شيء؛ فالحمولات غير القابلة للتقسيم معفاة","السفر ليلًا فقط","تقليل الحمولة إلى الحدود القانونية رغم أنه لا يمكن تقسيمها"],"explanation":"الحمولة غير القابلة للتقسيم التي تتجاوز كلًّا من حد العرض البالغ 102 بوصة (§316.515) وحد الوزن الإجمالي البالغ 80,000 رطل (§316.535) تتطلب تصريح أحجام زائدة/أوزان زائدة من FDOT، والذي يحدد أيضًا شروط المسار والمرافقة ووقت السفر."},"20":{"q":"في فلوريدا، أي فئة من فئات CDL مطلوبة لتشغيل تركيبة مركبات بتصنيف وزن إجمالي للتركيبة يبلغ 26,001 رطل أو أكثر، حيث تتجاوز الوحدة المقطورة 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تُطلب رخصة CDL من الفئة A في فلوريدا لتشغيل تركيبات الشاحنة/المقطورة المصنّفة بـ26,001 رطل أو أكثر والتي تقطر وحدة تزيد عن 10,000 رطل (مثل الجرارات والمقطورات). المصدر: صفحة FLHSMV لرخصة القيادة التجارية؛ دليل CDL لفلوريدا."},"21":{"q":"يرغب سائق في فلوريدا في تشغيل شاحنة مستقيمة مفردة أو حافلة مصنّفة بـ26,001 رطل أو أكثر ولا تقطر مقطورة تزيد عن 10,000 رطل. أي فئة CDL تناسبه؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تغطي رخصة CDL من الفئة B في فلوريدا الشاحنات المفردة (المستقيمة) والحافلات المصنّفة بـ26,001 رطل أو أكثر والتي لا تقطر وحدة تزيد عن 10,000 رطل. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"22":{"q":"أي فئة من فئات CDL في فلوريدا مطلوبة لمركبة أصغر (لا تستوفي وزن الفئة A أو B) مصممة لنقل 16 شخصًا أو أكثر أو تحمل مواد خطرة موسومة بلافتات؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تنطبق رخصة CDL من الفئة C في فلوريدا على المركبات التي لا تستوفي معايير وزن الفئة A أو B ولكنها مصممة لحمل 16 شخصًا أو أكثر أو تنقل مواد خطرة موسومة بلافتات. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في فلوريدا المقيدة بالتشغيل داخل الولاية (ضمن فلوريدا) فقط؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"تسمح فلوريدا برخصة CDL في سن 18، لكن السائقين دون 21 عامًا مقيّدون بالتشغيل داخل الولاية (ضمن الولاية). المصدر: صفحة FLHSMV لرخصة القيادة التجارية؛ قوانين فلوريدا الفصل 322."},"24":{"q":"يرغب حامل رخصة CDL في فلوريدا يبلغ من العمر 19 عامًا في القيادة عبر حدود الولايات (بين الولايات) أو نقل المواد الخطرة. لماذا لا يستطيع ذلك؟","options":["يتطلب التشغيل بين الولايات ونقل المواد الخطرة حدًا أدنى للعمر 21 عامًا","يتطلب التشغيل بين الولايات حدًا أدنى للعمر 23 عامًا","يجب أن يحمل أولًا رخصة CDL داخل الولاية لمدة خمس سنوات","لا يجوز للسائقين دون 25 عامًا نقل أي بضائع أبدًا"],"explanation":"حاملو رخصة CDL في فلوريدا دون 21 عامًا مقيّدون بالقيادة داخل الولاية؛ ويتطلب التشغيل بين الولايات ونقل المواد الخطرة أن يكون السائق في الحادية والعشرين من عمره على الأقل. المصدر: FLHSMV؛ الفيدرالي 49 CFR 391.11."},"25":{"q":"أي تصديق يحتاجه حامل رخصة CDL في فلوريدا لنقل كميات موسومة بلافتات من المواد الخطرة؟","options":["تصديق N","تصديق T","تصديق P","تصديق H"],"explanation":"يصرّح تصديق H (المواد الخطرة) بنقل المواد الخطرة الموسومة بلافتات ويتطلب اجتياز اختبار معرفة المواد الخطرة. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"26":{"q":"أي تصديق مطلوب لقيادة مركبة صهريج في فلوريدا؟","options":["N (مركبات الصهاريج)","T (المقطورات المزدوجة/الثلاثية)","H (المواد الخطرة)","S (حافلة المدرسة)"],"explanation":"يُصدَر تصديق N للسائقين الذين يجتازون اختبار معرفة مركبات الصهاريج المطلوب والذين سيشغّلون مركبات الصهاريج. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"27":{"q":"يخطط سائق في فلوريدا لقطر تركيبات جرار ومقطورة مزدوجة أو ثلاثية. أي تصديق مطلوب؟","options":["P (الركاب)","T (المقطورات المزدوجة/الثلاثية)","N (مركبات الصهاريج)","H (المواد الخطرة)"],"explanation":"يسمح تصديق T، الذي يُكتسب باجتياز اختبار المعرفة المطلوب، بتشغيل تركيبات المقطورات المزدوجة والثلاثية. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"28":{"q":"أي تصديق تشترطه فلوريدا لقيادة مركبة مصممة لنقل 16 شخصًا أو أكثر (أكثر من 15 راكبًا بمن فيهم السائق)؟","options":["S (حافلة المدرسة)","P (الركاب)","N (مركبات الصهاريج)","T (المقطورات المزدوجة/الثلاثية)"],"explanation":"يتطلب تصديق P (الركاب) اجتياز اختباري المعرفة والمهارات معًا، وهو لازم لمركبات الركاب المصممة لأكثر من 15 شخصًا بمن فيهم السائق. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"29":{"q":"للحصول على تصديق حافلة المدرسة (S) في فلوريدا، أي تصديق إضافي يجب أن يحمله السائق أيضًا؟","options":["تصديق H (المواد الخطرة)","تصديق N (الصهاريج)","تصديق P (الركاب)","تصديق T (المزدوجة/الثلاثية)"],"explanation":"تشترط فلوريدا تصديق P (الركاب) بالإضافة إلى تصديق S (حافلة المدرسة)؛ ويتطلب تصديق S اجتياز اختباري المعرفة والمهارات الخاصين به. المصدر: صفحة FLHSMV لرخصة القيادة التجارية."},"30":{"q":"أي تصديق لرخصة CDL في فلوريدا يتطلب تقييمًا أمنيًا فيدراليًا للتهديدات من TSA، يشمل أخذ البصمات وفحصًا وطنيًا للخلفية، قبل إصداره؟","options":["P (الركاب)","T (المقطورات المزدوجة/الثلاثية)","N (مركبات الصهاريج)","H (المواد الخطرة)"],"explanation":"بموجب قانون USA PATRIOT، يتطلب تصديق H (المواد الخطرة) من المتقدمين أخذ بصماتهم واجتياز فحص الخلفية لدى TSA قبل الإصدار؛ وتُطبَّق رسوم إضافية. المصدر: صفحة FLHSMV لرخصة القيادة التجارية؛ TSA."},"31":{"q":"كم يجب أن يحمل السائق تصريح المتعلم التجاري (CLP) في فلوريدا قبل السماح له بإجراء اختبار مهارات (قيادة) CDL؟","options":["7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"تتطلب القواعد الفيدرالية المعتمدة من فلوريدا حمل تصريح CLP لمدة 14 يومًا كحد أدنى قبل إجراء اختبار مهارات CDL. المصدر: FLHSMV؛ 49 CFR 383.25."},"32":{"q":"أثناء التدرّب بتصريح CLP في فلوريدا، من الذي يجب أن يرافق حامل التصريح في المركبة التجارية؟","options":["أي سائق مرخّص يبلغ من العمر 21 عامًا أو أكثر","حامل رخصة CDL سارية بالفئة والتصديقات المناسبة، يجلس بجوار السائق أو قربه","مدرّب CDL معتمد فقط، في مسار مغلق","لا يُشترط وجود مشرف بمجرد اجتياز اختبار المعرفة"],"explanation":"يجب أن يرافق حامل تصريح CLP حاملُ رخصة CDL سارية بالمجموعة والتصديقات المناسبة، حاضرًا جسديًا بجوار السائق (أو، في الحافلات، خلفه مباشرة) تحت إشراف مباشر. المصدر: FLHSMV؛ 49 CFR 383.25."},"33":{"q":"ما هو قيد الركاب الذي ينطبق على حامل تصريح CLP في فلوريدا الذي يشغّل مركبة تجارية؟","options":["يجوز له حمل ما يصل إلى 8 ركاب لأغراض التدريب","يجوز له حمل الركاب أثناء ساعات النهار فقط","لا يجوز له حمل ركاب غير حامل رخصة CDL المشرف","يجوز له حمل الركاب إذا ارتدى الجميع أحزمة الأمان"],"explanation":"لا يجوز لحامل تصريح CLP تشغيل حافلة أو مركبة يشغلها ركاب غير حامل رخصة CDL السارية/المرشد المرافق. المصدر: FLHSMV؛ 49 CFR 383.25."},"34":{"q":"إذا لم يجتز المتقدم لرخصة CDL في فلوريدا اختبار معرفة الفرامل الهوائية، فماذا يحدث لرخصته؟","options":["يُضاف قيد 'L' يمنع المركبات ذات الفرامل الهوائية","يُضاف قيد 'K' يقصره على القيادة داخل الولاية","تُخفَّض رخصة CDL إلى الفئة C تلقائيًا","لا يمكن إصدار رخصة CDL حتى يُجتاز اختبار الفرامل الهوائية"],"explanation":"يؤدي عدم اجتياز اختبار الفرامل الهوائية أو تخطّيه إلى قيد 'L'، الذي يمنع السائق من تشغيل المركبات التجارية المزوّدة بفرامل هوائية. المصدر: FLHSMV؛ دليل CDL لفلوريدا."},"35":{"q":"بموجب قواعد التدريب الفيدرالية للسائقين المبتدئين (ELDT) المعتمدة في فلوريدا، أي من المتقدمين يجب أن يُكمل ELDT قبل الاختبار؟","options":["السائقون الذين يحملون بالفعل رخصة CDL من ولاية أخرى فقط","المتقدمون لأول مرة لرخصة CDL، والترقيات من الفئة B إلى A، وطالبو تصديق H أو P أو S لأول مرة","السائقون الساعون للحصول على تصديق N أو T فقط","السائقون الذين تتجاوز أعمارهم 21 عامًا فقط"],"explanation":"يُطلب ELDT للمتقدمين لأول مرة لرخصة CDL، والترقيات من الفئة B إلى الفئة A، وتصديقات المواد الخطرة أو الركاب أو حافلة المدرسة لأول مرة (لتصاريح CLP المحصّلة في 7 فبراير 2022 أو بعده). المصدر: قاعدة FMCSA لـELDT؛ FLHSMV."},"36":{"q":"أين يجب أن يكون مقدّم تدريب ELDT في فلوريدا مدرجًا كي يُحتسب تدريب السائق في أهلية CDL؟","options":["في سجل مقدّمي التدريب التابع لـFMCSA","في قائمة المدارس المعتمدة من FLHSMV فقط","في سجل بائعي TSA","في أي كشف لكليات المجتمع التابعة للولاية"],"explanation":"يجب أن يُقدَّم تدريب ELDT النظري والتدريب خلف المقود من قِبل مقدّم مدرج في سجل مقدّمي التدريب (TPR) التابع لـFMCSA، والذي يقدّم الإكمال إلكترونيًا. المصدر: سجل مقدّمي التدريب التابع لـFMCSA؛ FLHSMV."},"37":{"q":"بالنسبة لتصديق المواد الخطرة (H) تحديدًا، أي خطوة من ELDT يجب أن يُكملها المتقدم في فلوريدا؟","options":["التدريب على المسار خلف المقود قبل اختبار الطريق","الجزء النظري (المعرفي) من ELDT قبل إجراء اختبار معرفة المواد الخطرة","اختبار مهارات كامل في مركبة صهريج","لا يُطلب ELDT أبدًا للمواد الخطرة"],"explanation":"يجب أن يُكمل المتقدمون للمواد الخطرة الجزء النظري من ELDT عبر مقدّم مسجَّل قبل إجراء اختبار معرفة المواد الخطرة. المصدر: قاعدة FMCSA لـELDT؛ FLHSMV."},"38":{"q":"سائق CDL في فلوريدا يشغّل عبر حدود الولايات ويُطلب منه الاحتفاظ بشهادة طبية فيدرالية سيصادق ذاتيًا على نفسه تحت أي فئة؟","options":["مستثنى بين الولايات (EI)","مستثنى داخل الولاية (EA)","غير مستثنى داخل الولاية (NA)","غير مستثنى بين الولايات (NI)"],"explanation":"تنطبق فئة غير مستثنى بين الولايات (NI) على السائقين في التجارة بين الولايات الذين يجب أن يحملوا شهادة فاحص طبي سارية من فاحص مدرج في السجل الوطني لـFMCSA. المصدر: المصادقة الذاتية لـFLHSMV؛ FMCSA 49 CFR 383.71."},"39":{"q":"أي وثيقة تقبلها فلوريدا كإثبات أساسي للهوية لطلب رخصة CDL المتوافقة مع REAL ID؟","options":["شهادة ميلاد أمريكية مصدّقة أو جواز سفر أمريكي ساري","فاتورة خدمات حالية باسم المتقدم","بطاقة تسجيل ناخبين في فلوريدا","بطاقة هوية مصوّرة صادرة عن صاحب العمل"],"explanation":"لرخصة CDL المتوافقة مع REAL ID، تشترط فلوريدا وثيقة هوية أساسية مثل شهادة ميلاد أمريكية مصدّقة أو جواز سفر/بطاقة جواز سفر أمريكية سارية، إضافةً إلى إثبات رقم الضمان الاجتماعي وإثباتين لعنوان السكن. المصدر: FLHSMV ما الذي يجب إحضاره / REAL ID."},"40":{"q":"في فلوريدا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده قانونيًا لحامل رخصة CDL تشغيل مركبة آلية تجارية (CMV)؟","options":["0.08 بالمئة","0.02 بالمئة","0.10 بالمئة","0.04 بالمئة"],"explanation":"من غير القانوني تشغيل مركبة CMV في فلوريدا إذا كان تركيز الكحول في دمك 0.04 بالمئة أو أكثر، وهو نصف الحد البالغ 0.08 الذي ينطبق على السائقين غير التجاريين. المصدر: دليل CDL لفلوريدا (FLHSMV)، حالات سحب أهلية السائق؛ 49 CFR 383.51."},"41":{"q":"بموجب قانون الموافقة الضمنية في فلوريدا، ماذا يحدث في اللحظة التي يشغّل فيها الشخص مركبة آلية تجارية في الولاية؟","options":["يجب أن يحمل تصريحًا منفصلًا لاختبار النفَس في جميع الأوقات","يُعتبر أنه قد أعطى موافقته على اختبار الكحول","يتنازل عن حقه في جلسة استماع بشأن CDL كليًا","يكون معفيًا من الاختبار ما لم يقع حادث"],"explanation":"بتشغيل مركبة CMV في فلوريدا، يُعتبر السائق أنه قد أعطى موافقته على اختبار الكحول. ويحمل رفض الاختبار نفس سحب الأهلية الذي تحمله إدانة القيادة تحت تأثير الكحول. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ قوانين فلوريدا الفصل 322 (الموافقة الضمنية)."},"42":{"q":"يُدان حامل رخصة CDL بمخالفة جسيمة أولى، مثل القيادة تحت تأثير الكحول، بينما لا ينقل مواد خطرة. ما هو الحد الأدنى لفترة سحب أهلية CDL في فلوريدا؟","options":["60 يومًا","3 سنوات","سنة واحدة","مدى الحياة"],"explanation":"تؤدي المخالفة الجسيمة الأولى (القيادة تحت تأثير الكحول، أو تركيز كحول في الدم 0.04 أو أعلى في مركبة CMV، أو رفض الاختبار، أو مغادرة موقع الحادث، أو استخدام مركبة لارتكاب جناية) إلى سحب أهلية CDL لمدة سنة واحدة على الأقل. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"43":{"q":"إذا وقعت مخالفة جسيمة أولى أثناء تشغيل سائق CDL لمركبة CMV موسومة بلافتات للمواد الخطرة، فما هو الحد الأدنى لفترة سحب الأهلية في فلوريدا؟","options":["3 سنوات","سنة واحدة","120 يومًا","مدى الحياة"],"explanation":"ترفع المخالفة الجسيمة الأولى المرتكبة أثناء تشغيل مركبة CMV موسومة بلافتات للمواد الخطرة الحد الأدنى لسحب الأهلية من سنة واحدة إلى 3 سنوات على الأقل. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"44":{"q":"ما هي العاقبة في فلوريدا لحامل رخصة CDL الذي يُدان بمخالفة جسيمة ثانية في أي وقت خلال مسيرته في القيادة؟","options":["سحب الأهلية لمدة 3 سنوات","فقدان رخصة CDL مدى الحياة","سحب الأهلية لمدة سنة واحدة","سحب الأهلية لمدة 120 يومًا"],"explanation":"تؤدي المخالفة الجسيمة الثانية إلى سحب أهلية CDL مدى الحياة. وقد تسمح فلوريدا بالنظر في إعادة الإصدار بعد فترة دنيا في ظروف محدودة، لكن القاعدة هي الحظر مدى الحياة. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"45":{"q":"يُطلب من سائق CDL في فلوريدا قانونيًا الخضوع لاختبار كحول في الدم فيرفض. كيف يُعامل هذا لأغراض سحب أهلية CDL؟","options":["إنها مجرد مخالفة خطيرة، تؤدي إلى سحب الأهلية لمدة 60 يومًا","إنها مخالفة جسيمة، تؤدي إلى سحب الأهلية لمدة سنة واحدة على الأقل","لا تحمل أي عقوبة على CDL إذا كان السائق خارج الخدمة","تؤدي إلى أمر إيقاف عن الخدمة لمدة 24 ساعة فقط"],"explanation":"يُعامَل رفض الخضوع لاختبار الكحول كمخالفة جسيمة، تحمل نفس الحد الأدنى لسحب الأهلية البالغ سنة واحدة (3 سنوات إذا كانت موسومة بلافتات للمواد الخطرة HazMat) كإدانة القيادة تحت تأثير الكحول. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"46":{"q":"أي مما يلي يُصنَّف كـ'مخالفة مرورية خطيرة' لحامل رخصة CDL في فلوريدا؟","options":["القيادة بتركيز كحول في الدم 0.04 بالمئة في مركبة CMV","رفض اختبار كحول قانوني","تشغيل مركبة CMV تحت أمر إيقاف عن الخدمة","السرعة المفرطة، 15 ميلًا في الساعة أو أكثر فوق الحد المعلن"],"explanation":"السرعة المفرطة (15 ميلًا في الساعة أو أكثر فوق الحد) مخالفة مرورية خطيرة. أما الخيارات الأخرى فهي مخالفات جسيمة أو مخالفات إيقاف عن الخدمة، تحمل عقوبات مختلفة وأشد قسوة. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"47":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 سنوات الذي سيؤدي إلى سحب أهلية CDL في فلوريدا، ولأي مدة بالنسبة للمخالفة الثانية؟","options":["مخالفتان تؤديان إلى سحب الأهلية لمدة 120 يومًا على الأقل","3 مخالفات تؤدي إلى سحب الأهلية لمدة 60 يومًا على الأقل","مخالفتان تؤديان إلى سحب الأهلية لمدة 60 يومًا على الأقل","مخالفتان تؤديان إلى سحب الأهلية لمدة سنة واحدة على الأقل"],"explanation":"تؤدي المخالفة المرورية الخطيرة الثانية خلال فترة 3 سنوات إلى سحب الأهلية لمدة 60 يومًا على الأقل. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"48":{"q":"ما هو الحد الأدنى لسحب أهلية CDL في فلوريدا للمخالفة المرورية الخطيرة الثالثة المرتكبة خلال فترة 3 سنوات؟","options":["60 يومًا","سنة واحدة","120 يومًا","30 يومًا"],"explanation":"تؤدي المخالفة المرورية الخطيرة الثالثة خلال فترة 3 سنوات إلى سحب الأهلية لمدة 120 يومًا على الأقل. المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"49":{"q":"أي مما يلي يُعد مخالفة مرورية خطيرة وليس مخالفة جسيمة لحامل رخصة CDL في فلوريدا؟","options":["تغييرات حارة غير سليمة أو متقلبة","مغادرة موقع الحادث","استخدام مركبة لارتكاب جناية","القيادة تحت تأثير مادة خاضعة للرقابة"],"explanation":"تغييرات الحارة غير السليمة أو المتقلبة مخالفة مرورية خطيرة. أما الثلاثة الأخرى فهي مخالفات جسيمة تحمل حدًا أدنى لسحب الأهلية مدته سنة واحدة (أو مدى الحياة). المصدر: دليل CDL لفلوريدا (FLHSMV)؛ 49 CFR 383.51."},"50":{"q":"بموجب قواعد CDL في فلوريدا والقواعد الفيدرالية، كيف تُصنَّف المراسلة النصية أثناء قيادة مركبة تجارية (CMV) لأغراض إسقاط الأهلية؟","options":["كمخالفة كبرى مع إسقاط للأهلية لمدة سنة واحدة","كمخالفة مرورية خطيرة","كمخالفة لأمر إيقاف عن الخدمة (out-of-service)","كمخالفة لا تتعلق بـ CDL وليس لها أثر على إسقاط الأهلية"],"explanation":"انتهاك القانون الذي يحظر المراسلة النصية أثناء قيادة مركبة تجارية (CMV) يُعد مخالفة مرورية خطيرة. وعند اقترانها بمخالفات خطيرة أخرى خلال 3 سنوات، يمكن أن تؤدي إلى إسقاط الأهلية لمدة 60 أو 120 يومًا. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51 و392.80."},"51":{"q":"استخدام هاتف محمول يدوي أثناء قيادة مركبة تجارية (CMV) محظور على سائقي CDL في فلوريدا. ولأغراض إسقاط الأهلية، تُعامل هذه المخالفة على أنها:","options":["مخالفة كبرى تستوجب إسقاط الأهلية مدى الحياة","مخالفة عند معبر سكة حديدية","مخالفة مرورية خطيرة","مخالفة لأمر إيقاف عن الخدمة (out-of-service)"],"explanation":"انتهاك القانون الذي يحظر استخدام هاتف محمول يدوي أثناء قيادة مركبة تجارية (CMV) يُعد مخالفة مرورية خطيرة؛ وتكرار المخالفات الخطيرة خلال 3 سنوات يؤدي إلى إسقاط الأهلية لمدة 60 أو 120 يومًا. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51 و392.82."},"52":{"q":"ما هو الحد الأدنى لإسقاط أهلية CDL عند الإدانة الأولى بمخالفة عند معبر سكة حديدية مع الطريق السريع في فلوريدا؟","options":["120 يومًا","60 يومًا","سنة واحدة","30 يومًا"],"explanation":"تؤدي أول مخالفة عند معبر سكة حديدية مع الطريق السريع إلى إسقاط الأهلية لمدة لا تقل عن 60 يومًا. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"53":{"q":"يرتكب حامل CDL في فلوريدا مخالفة ثانية عند معبر سكة حديدية مع الطريق السريع خلال فترة 3 سنوات. ما هو الحد الأدنى لإسقاط الأهلية؟","options":["60 يومًا","سنة واحدة","180 يومًا","120 يومًا"],"explanation":"تؤدي المخالفة الثانية عند معبر سكة حديدية مع الطريق السريع خلال 3 سنوات إلى إسقاط الأهلية لمدة لا تقل عن 120 يومًا. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"54":{"q":"ما هو الحد الأدنى لإسقاط أهلية CDL عند المخالفة الثالثة عند معبر سكة حديدية مع الطريق السريع خلال فترة 3 سنوات في فلوريدا؟","options":["120 يومًا","60 يومًا","سنة واحدة","مدى الحياة"],"explanation":"تؤدي المخالفة الثالثة عند معبر سكة حديدية مع الطريق السريع خلال فترة 3 سنوات إلى إسقاط الأهلية لمدة لا تقل عن سنة واحدة. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"55":{"q":"يخالف سائق CDL في فلوريدا أمر إيقاف عن الخدمة (out-of-service) للمرة الأولى بينما لا ينقل مواد خطرة أو ركابًا. ما هو الحد الأدنى لإسقاط الأهلية؟","options":["180 يومًا","60 يومًا","90 يومًا","120 يومًا"],"explanation":"تؤدي أول مخالفة لأمر إيقاف عن الخدمة إلى إسقاط الأهلية لمدة لا تقل عن 180 يومًا (أطول إذا كان ينقل مواد خطرة HazMat أو ركابًا). المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"56":{"q":"ما هو الحد الأدنى لإسقاط أهلية CDL عند المخالفة الثانية لأمر إيقاف عن الخدمة (out-of-service) خلال فترة 10 سنوات في فلوريدا؟","options":["180 يومًا","سنة واحدة","3 سنوات","سنتان"],"explanation":"تؤدي المخالفة الثانية لأمر إيقاف عن الخدمة خلال فترة 10 سنوات إلى إسقاط الأهلية لمدة لا تقل عن سنتين. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"57":{"q":"يرتكب سائق CDL في فلوريدا مخالفة ثالثة أو لاحقة لأمر إيقاف عن الخدمة (out-of-service) خلال فترة 10 سنوات. ما هو الحد الأدنى لإسقاط الأهلية؟","options":["3 سنوات","سنتان","سنة واحدة","180 يومًا"],"explanation":"تؤدي المخالفة الثالثة أو اللاحقة لأمر إيقاف عن الخدمة خلال فترة 10 سنوات إلى إسقاط الأهلية لمدة لا تقل عن 3 سنوات. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"58":{"q":"إذا تبيّن أن سائق CDL في فلوريدا لديه أي كمية يمكن اكتشافها من الكحول أثناء العمل (أقل من 0.04 BAC)، فما هي العاقبة الفورية؟","options":["يُوضع خارج الخدمة لمدة 24 ساعة","فقدان دائم لرخصة CDL","إسقاط الأهلية لمدة 60 يومًا","إسقاط إلزامي للأهلية لمدة سنة واحدة"],"explanation":"يُوضع السائق الذي لديه أي كمية يمكن اكتشافها من الكحول أقل من 0.04 خارج الخدمة لمدة 24 ساعة. أما تركيز كحول الدم BAC البالغ 0.04 أو أعلى فهو مخالفة كبرى تُسقط أهلية السائق لمدة لا تقل عن سنة واحدة. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 392.5 و383.51."},"59":{"q":"أي مخالفة تؤدي إلى إسقاط إلزامي لأهلية CDL مدى الحياة دون إمكانية إعادة الإصدار في فلوريدا؟","options":["أول إدانة بالقيادة تحت تأثير الكحول (DUI) في مركبة تجارية CMV","مخالفتان مروريتان خطيرتان خلال 3 سنوات","أول مخالفة عند معبر سكة حديدية","استخدام مركبة تجارية CMV لتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها"],"explanation":"يحمل استخدام مركبة تجارية CMV في ارتكاب جناية تنطوي على تصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها إسقاطًا إلزاميًا للأهلية مدى الحياة دون إعادة إصدار. المصدر: دليل CDL في فلوريدا (FLHSMV)؛ 49 CFR 383.51."},"60":{"q":"بموجب قانون فلوريدا للتحرك جانبًا (Move Over Act)، أنت تقود مقطورة بجرّار على طريق سريع متعدد المسارات وتقترب من سيارة دورية متوقفة بأضوائها الطارئة الوامضة. ماذا يتطلب منك القانون أن تفعل أولًا؟","options":["التوقف توقفًا تامًا في مسارك الحالي حتى تغادر المركبة الطارئة","إخلاء المسار الأقرب إلى المركبة الطارئة حالما يكون ذلك آمنًا","إطلاق بوقك لتحذير الضابط من اقترابك","الحفاظ على سرعتك ولكن تشغيل أضواء الخطر"],"explanation":"يتطلب قانون فلوريدا للتحرك جانبًا (Fla. Stat. 316.126) من السائقين على طريق متعدد المسارات إخلاء المسار الأقرب إلى المركبة الطارئة أو الخدمية المتوقفة حالما يكون ذلك آمنًا؛ وفقط إذا تعذّر التحرك جانبًا يجب عليك تخفيف السرعة."},"61":{"q":"على طريق ذي مسارين في فلوريدا بسرعة محددة 55 ميلًا في الساعة، تقترب من شاحنة سحب متوقفة تعرض أضواء كهرمانية ولا يمكنك تغيير المسار بأمان. إلى كم ميلًا في الساعة يجب أن تخفّض سرعتك؟","options":["45 ميلًا في الساعة","25 ميلًا في الساعة","35 ميلًا في الساعة","55 ميلًا في الساعة؛ لا يلزم التخفيض على طريق ذي مسارين"],"explanation":"بموجب Fla. Stat. 316.126، عندما لا يمكنك التحرك جانبًا، يجب أن تخفّض السرعة إلى 20 ميلًا في الساعة أقل من السرعة المحددة عندما تكون السرعة المحددة 25 ميلًا في الساعة أو أعلى. وعلى طريق بسرعة 55 ميلًا في الساعة يعني ذلك 35 ميلًا في الساعة."},"62":{"q":"يتطلب قانون فلوريدا للتحرك جانبًا تخفيض السرعة عندما لا يمكنك تغيير المسار. على طريق تكون فيه السرعة المحددة 20 ميلًا في الساعة أو أقل، إلى أي سرعة يجب أن تخفّض عند المرور بمركبة متوقفة مؤهلة؟","options":["5 أميال في الساعة","10 أميال في الساعة","0 ميل في الساعة (توقف تام)","15 ميلًا في الساعة"],"explanation":"تنص Fla. Stat. 316.126 على أنه عندما تكون السرعة المحددة 20 ميلًا في الساعة أو أقل، يجب على السائق الذي لا يمكنه التحرك جانبًا أن يخفّض السرعة إلى 5 أميال في الساعة عند المرور بالمركبة المتوقفة."},"63":{"q":"بالإضافة إلى المركبات الطارئة، يحمي قانون فلوريدا للتحرك جانبًا (Fla. Stat. 316.126) أيضًا أيًّا من المركبات المتوقفة التالية التي تعرض الإشارات المناسبة؟","options":["مركبات الصرف الصحي والخدمات المرفقية وصيانة الطرق أو الجسور، والمركبات المعطلة التي تعمل أضواء الخطر بها","فقط مركبات إنفاذ القانون والإطفاء المميزة","فقط سيارات الإسعاف وشاحنات السحب","أي سيارة ركاب خاصة متوقفة على الكتف"],"explanation":"توسّع Fla. Stat. 316.126 حماية قانون التحرك جانبًا لتشمل مركبات الصرف الصحي ومركبات الخدمات المرفقية وشاحنات السحب ومركبات صيانة/إنشاء الطرق والجسور، والمركبات الآلية المعطلة التي تعرض أضواء الخطر، بالإضافة إلى المركبات الطارئة."},"64":{"q":"أنت تقود حافلة تنقل ركابًا وتقترب من معبر سكة حديدية في فلوريدا. على أي مسافة من أقرب سكة يجب أن تتوقف؟","options":["بين 5 و15 قدمًا","بين 50 و100 قدم","بين 15 و50 قدمًا","بالضبط 25 قدمًا، لا أقرب ولا أبعد"],"explanation":"يجب على الحافلات التي تنقل ركابًا والمركبات التي تنقل مواد خطرة بملصقات أن تتوقف على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب سكة، ثم تنظر وتستمع قبل العبور (دليل CDL في فلوريدا؛ FMCSR 392.10)."},"65":{"q":"أي مركبة تجارية يُطلب منها التوقف الإلزامي عند كل معبر سكة حديدية في فلوريدا ما لم ينطبق استثناء؟","options":["شاحنة مسطحة فارغة بلا حمولة","مركبة تنقل كميات من المواد الخطرة تستوجب الملصقات","شاحنة توصيل تحمل بضائع عامة","شاحنة قلابة تنقل الرمل"],"explanation":"بموجب القواعد الفيدرالية المعتمدة في دليل CDL في فلوريدا (FMCSR 392.10)، يجب على المركبات التي يُطلب وضع ملصقات عليها للمواد الخطرة، والحافلات التي تنقل ركابًا، أن تتوقف عند معابر السكك الحديدية؛ أما مركبات البضائع العادية فلا يُطلب منها التوقف."},"66":{"q":"عند أي معبر سكة حديدية لا يُطلب من سائق ينقل مواد خطرة بملصقات أو سائق حافلة أن يتوقف؟","options":["معبر تُظهر فيه إشارة مرور عاملة الضوء الأخضر، أو يكون معلَّمًا بلافتة إعفاء (Exempt) رسمية","أي معبر على طريق ريفي ذي مسارين","معبر به أذرع تقاطع (crossbucks) ولكن دون أضواء وامضة","معبر مباشرةً بعد غروب الشمس"],"explanation":"يسرد دليل CDL في فلوريدا (FMCSR 392.10) استثناءات للتوقف الإلزامي: إشارة تحكم مرورية خضراء، أو معبر معلَّم بلافتة إعفاء (Exempt) رسمية، أو معبر يوجّهه شرطي أو موجِّه، والسكك المستخدمة فقط لعربات الترام أو المناورة الصناعية."},"67":{"q":"عند عبور سكك حديدية بمركبة تجارية ذات ناقل حركة يدوي، ماذا يجب أن تفعل؟","options":["انتقل إلى ترس أعلى في منتصف المسافة لاجتياز السكك بسرعة أكبر","توقّف على السكك للتحقق من مراياك قبل المتابعة","انتقل إلى الوضع المحايد (neutral) وانزلق عبر السكك","اعبر بترس منخفض ولا تبدّل التروس أثناء وجودك على السكك"],"explanation":"يوجّه دليل CDL في فلوريدا السائقين إلى اختيار ترس يُمكِّن المركبة من اجتياز السكك بالكامل وعدم تبديل التروس أبدًا أثناء العبور، لتجنّب تعطّل المركبة على السكك."},"68":{"q":"على طريق ذي اتجاهين في فلوريدا بلا جزيرة وسطية أو حاجز، تتوقف حافلة مدرسية بأضوائها الحمراء الوامضة وذراع التوقف ممدودة. ماذا يجب على حركة المرور القادمة من الاتجاه المعاكس أن تفعل؟","options":["تخفيض السرعة إلى 10 أميال في الساعة مع جواز المتابعة بجانب الحافلة","المتابعة بشكل طبيعي لأن حركة المرور المعاكسة لا تتوقف أبدًا","التوقف والبقاء متوقفة حتى تتوقف الأضواء عن الوميض وتُسحب ذراع التوقف","التوقف فقط إذا كان الأطفال يعبرون الطريق بشكل ظاهر"],"explanation":"تتطلب Fla. Stat. 316.172 من جميع حركة المرور، بما في ذلك حركة المرور المعاكسة على طريق ذي اتجاهين غير مقسوم، أن تتوقف لحافلة مدرسية متوقفة بأضواء حمراء وامضة، وأن تبقى متوقفة حتى تتوقف الأضواء وتُسحب ذراع التوقف."},"69":{"q":"بموجب قانون فلوريدا، لا يُطلب من السائقين المسافرين في الاتجاه المعاكس التوقف لحافلة مدرسية متوقفة عندما يكون الطريق مقسومًا بأيٍّ مما يلي؟","options":["خط أصفر مركزي صلب واحد","مسار انعطاف يسار ثنائي الاتجاه مرسوم","جزيرة وسطية مرتفعة، أو حاجز مادي، أو مسافة غير معبّدة لا تقل عن 5 أقدام","صف من علامات المسار العاكسة"],"explanation":"تعفي Fla. Stat. 316.172(2) حركة المرور المعاكسة من التوقف فقط عندما يفصل الطريق المقسوم بين حركة المرور بجزيرة وسطية مرتفعة، أو حاجز مادي، أو مسافة غير معبّدة لا تقل عن 5 أقدام. أما الخطوط المرسومة وحدها فلا تُعد مؤهلة."},"70":{"q":"إذا اضطُررت إلى إيقاف مركبتك التجارية على كتف طريق سريع أحادي الاتجاه أو مقسوم في فلوريدا، فأين يجب أن تضع أجهزة التحذير الطارئة الثلاثة؟","options":["على بُعد 5 أقدام و50 قدمًا و150 قدمًا باتجاه حركة المرور القادمة","الثلاثة جميعها على بُعد 10 أقدام من مؤخرة المركبة","على بُعد 25 قدمًا و75 قدمًا و125 قدمًا أمام المركبة","على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة"],"explanation":"يتطلب دليل CDL في فلوريدا (FMCSR 392.22) وضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة على طريق سريع أحادي الاتجاه أو مقسوم."},"71":{"q":"بعد إيقاف مركبتك التجارية على الجزء المخصص للسير أو على كتف طريق سريع في فلوريدا، خلال كم ثانية يجب أن تُشغّل أضواء التحذير الطارئة (الوماضات الرباعية)؟","options":["خلال 30 دقيقة، وفقط ليلًا","فقط بعد وضع مثلثات التحذير مسبقًا","فورًا، مع وضع أجهزة التحذير خلال 10 دقائق","لا يوجد متطلب زمني لأضواء التحذير"],"explanation":"بموجب FMCSR 392.22، المعتمد في دليل CDL في فلوريدا، يجب على المركبة التجارية المتوقفة أن تُشغّل فورًا وماضات التحذير الطارئة وأن تضع أجهزة التحذير (المثلثات/الشعلات) خلال 10 دقائق."},"72":{"q":"على طريق ذي مسارين في فلوريدا يحمل حركة مرور في كلا الاتجاهين، أين يجب وضع مثلثات التحذير عندما تكون مركبتك التجارية متوقفة؟","options":["على بُعد 10 أقدام من المركبة و100 قدم خلفها وأمامها","فقط على بُعد 200 قدم خلف المركبة","فقط عند المصد الأمامي للمركبة","50 قدمًا خلفها و50 قدمًا أمامها فقط"],"explanation":"يوجّه دليل CDL في فلوريدا (FMCSR 392.22) إلى أنه على طريق ذي مسارين أو غير مقسوم تضع جهاز تحذير واحدًا على بُعد 10 أقدام من المركبة وواحدًا على بُعد 100 قدم خلف المركبة المتوقفة وواحدًا على بُعد 100 قدم أمامها."},"73":{"q":"على طريق في فلوريدا به ثلاثة مسارات أو أكثر في اتجاهك، تتطلب قاعدة المسار الأيمن العامة من المركبات الأبطأ، بما في ذلك الشاحنات، أن تفعل ماذا؟","options":["السير دائمًا في المسار الأوسط بغض النظر عن السرعة","استخدام المسار الأقصى يسارًا لإبقاء حركة المسار الأيمن سالكة","اختيار أي مسار بحرية دون أي قيد","البقاء في المسار الأيمن إلا عند التجاوز أو المرور أو التحضير لانعطاف يسار"],"explanation":"تتطلب Fla. Stat. 316.081 من أي مركبة تسير أبطأ من السرعة الطبيعية لحركة المرور أن تستخدم المسار الأيمن (أو أقرب ما يكون إلى الحافة اليمنى عمليًا) إلا عند التجاوز/المرور أو التحضير لانعطاف يسار."},"74":{"q":"خارج المناطق التجارية أو السكنية، ما هو الحد الأقصى الافتراضي للسرعة المنصوص عليه قانونًا في فلوريدا حيث لا تُوجد سرعة أخرى محددة؟","options":["55 ميلًا في الساعة","70 ميلًا في الساعة","65 ميلًا في الساعة","45 ميلًا في الساعة"],"explanation":"تحدد Fla. Stat. 316.183/316.187 الحد الأقصى القانوني عند 55 ميلًا في الساعة في المواقع خارج المناطق التجارية أو السكنية ما لم تُحدَّد سرعة مختلفة؛ وتنطبق 30 ميلًا في الساعة في المناطق التجارية أو السكنية."},"75":{"q":"على طريق سريع بين الولايات في فلوريدا لا يقل عن أربعة مسارات وبسرعة محددة 70 ميلًا في الساعة، ما هو الحد الأدنى للسرعة المنصوص عليه قانونًا؟","options":["40 ميلًا في الساعة","55 ميلًا في الساعة","45 ميلًا في الساعة","50 ميلًا في الساعة"],"explanation":"تُنشئ Fla. Stat. 316.183 حدًا أدنى للسرعة قدره 50 ميلًا في الساعة على الطرق السريعة بين الولايات المقسومة التي لا تقل عن أربعة مسارات حيث يكون الحد الأقصى المحدد 70 ميلًا في الساعة."},"76":{"q":"بموجب قانون فلوريدا للقيادة المشتتة (Fla. Stat. 316.305)، ما الذي يُحظر أثناء تشغيل مركبة آلية متحركة؟","options":["أي استخدام لمكبر صوت بلوتوث يدوي الاستخدام لإجراء مكالمة هاتفية","الكتابة اليدوية أو قراءة بيانات لاتصال غير صوتي مثل المراسلة النصية أو البريد الإلكتروني أو الرسائل الفورية","الاستماع إلى توجيهات الملاحة الصوتية","وجود هاتف مثبَّت مرئي في المقصورة"],"explanation":"تحظر Fla. Stat. 316.305 الكتابة اليدوية أو إدخال الأحرف وإرسال أو قراءة بيانات على جهاز لاسلكي لاتصال شخصي غير صوتي (المراسلة النصية، البريد الإلكتروني، الرسائل الفورية) أثناء القيادة."},"77":{"q":"أي عبارة عن إنفاذ قانون فلوريدا للمراسلة النصية أثناء القيادة (Fla. Stat. 316.305) صحيحة؟","options":["إنها مخالفة ثانوية تستوجب وقوع مخالفة أخرى أولًا","إنها مخالفة أولية، لذا يجوز للضابط إيقاف السائق ومخالفته لمجرد المراسلة النصية","تنطبق فقط على السائقين دون سن 18 عامًا","تنطبق فقط بين غروب الشمس وشروقها"],"explanation":"منذ عام 2019، تجعل Fla. Stat. 316.305 المراسلة النصية أثناء القيادة مخالفة أولية، مما يخوّل الضباط إيقاف السائق ومخالفته على تلك المخالفة وحدها."},"78":{"q":"عندما تُفعّل فلوريدا الاستخدام الطارئ للكتف (ESU) على مسار إخلاء أثناء إعصار، أي المركبات لا يُسمح لها باستخدام مسار الكتف المفتوح؟","options":["سيارات الركاب والشاحنات الصغيرة (البيك أب)","الشاحنات الكبيرة والحافلات والمقطورات","الدراجات النارية وسيارات الدفع الرباعي (SUV)","يُسمح لجميع المركبات باستخدام الكتف على قدم المساواة"],"explanation":"بموجب خطة FDOT للاستخدام الطارئ للكتف في فلوريدا (التي حلّت محل عكس اتجاه السير)، يجوز لجميع السائقين باستثناء الشاحنات الكبيرة والحافلات والمقطورات استخدام الكتف المعبّد كمسار سير مؤقت أثناء إخلاء الإعصار."},"79":{"q":"فيما يتعلق بتشغيل المحرك في وضع الخمول لفترات ممتدة للمركبات التجارية شديدة التحمل، أي عبارة تعكس قانون فلوريدا الحالي؟","options":["تحظر فلوريدا كل تشغيل خمول للشاحنات لأكثر من 3 دقائق على مستوى الولاية","تحدّ فلوريدا الخمول بـ 5 دقائق على مستوى الولاية في جميع الأوقات","تتطلب فلوريدا إيقاف المحركات كلما كانت الشاحنة متوقفة في أي مكان في الولاية","لا يوجد لدى فلوريدا حد على مستوى الولاية لتقليل خمول المركبات شديدة التحمل؛ فقد أُلغيت قاعدتها السابقة للخمول"],"explanation":"أُلغيت قاعدة فلوريدا لتقليل خمول المركبات شديدة التحمل (Fla. Admin. Code 62-285.420)، لذا لا يوجد حد زمني للخمول على مستوى الولاية؛ وينبغي للسائقين مع ذلك التحقق من اللوائح المحلية. وهذا يختلف عن الولايات التي لديها قوانين لمكافحة الخمول على مستوى الولاية."},"80":{"q":"أي وكالة تصدر رخص القيادة التجارية (CDL) في فلوريدا؟","options":["وزارة النقل في فلوريدا (FDOT)","إدارة سلامة الطرق السريعة والمركبات الآلية في فلوريدا (FLHSMV)","الإدارة الفيدرالية لسلامة ناقلي البضائع الآليين (FMCSA)","الإدارة الأمريكية للمركبات الآلية"],"explanation":"في فلوريدا، تُصدِر رخص CDL وتديرها إدارة سلامة الطرق السريعة والمركبات الآلية في فلوريدا (FLHSMV). وتضع FMCSA المعايير الفيدرالية، لكن وكالة الولاية هي التي تُصدِر الوثيقة الفعلية. المصدر: FLHSMV، صفحة رخصة القيادة التجارية."},"81":{"q":"عند التقدم بطلب للحصول على رخصة CDL أصلية في فلوريدا أو تصريح متعلم تجاري، أي مجموعة من المستندات يجب أن يقدّمها مقدّم الطلب إلى FLHSMV؟","options":["فقط رخصة قيادة من الفئة E سارية في فلوريدا وصورة فوتوغرافية","جواز سفر وفاتورة مرافق واحدة، دون أي مستندات للضمان الاجتماعي","فقط شهادة فاحص طبي معتمد من DOT وبطاقة بصمات","إثبات الهوية، وإثبات رقم الضمان الاجتماعي، وإثباتان لعنوان الإقامة في فلوريدا"],"explanation":"بموجب قانون REAL ID الفيدرالي كما تطبّقه FLHSMV، يجب على مقدّمي طلبات CDL/CLP الأصلية تقديم مستندات أصلية تثبت الهوية، ورقم الضمان الاجتماعي، وإثباتين لعنوان الإقامة في فلوريدا. المصدر: FLHSMV، صفحتا ما يجب إحضاره / رخصة القيادة التجارية."},"82":{"q":"وثائق CDL وCLP في فلوريدا متوافقة مع REAL ID. ماذا يتطلب قانون REAL ID من مقدّمي الطلبات؟","options":["تقديم إقرار موثّق بدلًا من أي مستندات هوية","تقديم مستندات أصلية تتحقق من الهوية ورقم الضمان الاجتماعي وعنوان الإقامة","تقديم بطاقة جواز سفر فيدرالية كإثبات وحيد مقبول لجميع المتطلبات","إكمال اختبار هوية عبر الإنترنت بدلًا من مراجعة المستندات شخصيًا"],"explanation":"يتطلب REAL ID من مقدّمي الطلبات تقديم مستندات أصلية تتحقق من الهوية ورقم الضمان الاجتماعي وعنوان الإقامة عند الإصدار الأول في المكتب. وبمجرد تقديمها، يلزم عمومًا إظهارها مرة أخرى فقط في حال تغيّر المعلومات. المصدر: FLHSMV، صفحة REAL ID."},"83":{"q":"كم عدد إثباتات عنوان الإقامة في فلوريدا التي يجب على مقدّم طلب CDL أو CLP تقديمها إلى FLHSMV؟","options":["لا يلزم أي إثبات لعنوان الإقامة لرخصة CDL","أربعة إثباتات لعنوان الإقامة، جميعها فواتير مرافق","إثبات واحد، لكن يجب أن يكون جواز سفر","إثباتان لعنوان الإقامة باسم مقدّم الطلب"],"explanation":"تتطلب FLHSMV من مقدّمي طلبات CLP وCDL تقديم إثباتين لعنوان الإقامة في فلوريدا باسمهم (اثنان من القائمة A، أو واحد من القائمة A وواحد من القائمة B). المصدر: FLHSMV، صفحة ما يجب إحضاره."},"84":{"q":"تتطلب لوائح سلامة ناقلي البضائع الآليين الفيدرالية من كل سائق يحصل على رخصة CDL أو يجددها أن يقرّ ذاتيًا لدى FLHSMV ضمن كم فئة من فئات التشغيل؟","options":["فئتان","أربع فئات","ست فئات","ثلاث فئات"],"explanation":"يجب على السائقين الإقرار ذاتيًا ضمن واحدة من أربع فئات: بين الولايات غير المُعفاة، وبين الولايات المُعفاة، وداخل الولاية غير المُعفاة، وداخل الولاية المُعفاة. المصدر: FLHSMV، صفحة الشهادة الطبية لـ CDL."},"85":{"q":"أي مما يلي يُعد واحدة من فئات الإقرار الذاتي الأربع لـ CDL التي تستخدمها FLHSMV؟","options":["بين الولايات غير المُعفاة","المواد الخطرة الفيدرالية المُعفاة (excepted federal hazmat)","داخل الولاية الزراعية المقيّدة فقط","التجارة بين الولايات المؤقتة (provisional)"],"explanation":"الفئات الأربع الصالحة للإقرار الذاتي هي: بين الولايات غير المُعفاة، وبين الولايات المُعفاة، وداخل الولاية غير المُعفاة، وداخل الولاية المُعفاة. وفئة \"بين الولايات غير المُعفاة\" هي فئة السائقين الذين يجب أن يحتفظوا بشهادة طبية فيدرالية. المصدر: FLHSMV، صفحة الشهادة الطبية لـ CDL."},"86":{"q":"يقرّ سائق CDL في فلوريدا ذاتيًا بأنه \"بين الولايات غير مُعفى\". ما الالتزام الطبي المستمر الذي ينشئه ذلك؟","options":["يكون مُعفى بشكل دائم من أي شهادة طبية","يحتاج فقط إلى فحص طبي مرة كل خمسة عشر عامًا","يجب أن يحصل على شهادة فاحص طبي صالحة من DOT ويبقيها على الملف لدى FLHSMV","يجب أن يقرّ ذاتيًا لكنه لا يحتاج أبدًا إلى شهادة فاحص طبي"],"explanation":"يجب على السائقين الذين يقرّون بأنهم بين الولايات غير مُعفين (أو داخل الولاية غير مُعفين) أن يحتفظوا بشهادة فاحص طبي صالحة من DOT وأن يبقوها سارية على الملف لدى FLHSMV. المصدر: FLHSMV، صفحة الشهادة الطبية لـ CDL."},"87":{"q":"ما الغرض من شهادة الفاحص الطبي من DOT (التي يُطلق عليها غالبًا \"Med Card\") في عملية CDL في فلوريدا؟","options":["لإثبات أن السائق أكمل تدريب سائقي المستوى المبتدئ","لتكون إثبات إقامة السائق في فلوريدا","لتحل محل اختباري المعرفة والمهارات للسائقين ذوي الخبرة","لتوثيق أن السائق يستوفي معايير التأهيل البدني لتشغيل مركبة تجارية آلية"],"explanation":"توثّق شهادة الفاحص الطبي من DOT أن فاحصًا طبيًا معتمدًا وجد السائق مؤهلًا بدنيًا لتشغيل مركبة تجارية آلية. وهي منفصلة عن إثبات الإقامة وعن اختباري المعرفة/المهارات. المصدر: FLHSMV، صفحة الشهادة الطبية لـ CDL."},"88":{"q":"يحتاج حامل CDL في فلوريدا من فئة بين الولايات غير المُعفاة إلى إبقاء إقراره الذاتي ومعلوماته الطبية محدثة. ما هي الطريقة التي توفرها FLHSMV لإدارة ذلك؟","options":["إرسال الشهادة بالفاكس إلى المكتب الوطني لـ FMCSA فقط","خدمة الإقرار الذاتي الطبي لـ CDL عبر بوابة MyDMV Portal الإلكترونية","نشر الشهادة على حساب وسائل تواصل اجتماعي","لا توجد طريقة لتحديثها؛ لا يمكن تغييرها بعد الإصدار"],"explanation":"توفر FLHSMV خدمة الإقرار الذاتي الطبي لـ CDL عبر بوابة MyDMV Portal حيث يمكن للسائقين تقديم فئة إقرارهم الذاتي ومعلوماتهم الطبية. والفاحصون الطبيون مطالَبون الآن أيضًا بإرسال نتائج فحص DOT إلكترونيًا. المصدر: FLHSMV، الإقرار الذاتي الطبي لـ CDL (بوابة MyDMV Portal)."},"89":{"q":"ماذا يحدث إذا لم يحتفظ سائق CDL غير مُعفى بشهادة طبية سارية على الملف لدى FLHSMV؟","options":["يمكن تخفيض رتبة امتياز CDL أو إسقاط أهليته حتى تُستعاد شهادة طبية سارية","لا يحدث شيء؛ الشهادة الطبية اختيارية تمامًا","يتلقى السائق تلقائيًا تظهيرًا للمواد الخطرة (hazmat)","تُلغى فترة احتفاظ السائق بـ CLP"],"explanation":"إذا انقضت صلاحية الشهادة الطبية لسائق غير مُعفى، يمكن لـ FLHSMV تخفيض رخصة CDL إلى رخصة غير تجارية أو إسقاط الامتياز التجاري حتى يُقدَّم مستند طبي ساري. المصدر: FLHSMV، صفحة الشهادة الطبية لـ CDL."},"90":{"q":"قبل الاختبار للحصول على رخصة CDL من الفئة A أو الفئة B لأول مرة، أي متطلب تدريبي فيدرالي يجب أن يستوفيه مقدّم الطلب في فلوريدا؟","options":["إكمال تدريب مهني لمدة أربع سنوات مسجّل لدى الولاية","اجتياز تحقيق منفصل في الخلفية من قبل FBI","إكمال تدريب سائقي المستوى المبتدئ (ELDT) من مزود مدرَج في سجل مزودي التدريب التابع لـ FMCSA","حيازة رخصة من الفئة E غير مقيّدة لمدة عشر سنوات"],"explanation":"بالنسبة لتصاريح المتعلم التجاري التي يُحصل عليها في أو بعد 7 فبراير 2022، يجب على مقدّمي طلبات CDL من الفئة A/B لأول مرة إكمال ELDT من مزود مدرَج في سجل مزودي التدريب التابع لـ FMCSA قبل إجراء اختبار مهارات CDL. المصدر: تدريب سائقي المستوى المبتدئ من FMCSA؛ صفحة رخصة القيادة التجارية لـ FLHSMV."},"91":{"q":"أي من طلبات التظهير هذه يستوجب أيضًا متطلب ELDT (تدريب سائقي المستوى المبتدئ) قبل الاختبار؟","options":["تظهير المواد الخطرة (H) أو الركاب (P) أو الحافلة المدرسية (S) لأول مرة","تجديد امتياز مركبة مركّبة قائم","إضافة تظهير دراجة نارية إلى رخصة من الفئة E","استبدال رخصة CDL مفقودة بنفس التظهيرات"],"explanation":"يُطلب ELDT لمقدّمي الطلبات لأول مرة الساعين للحصول على تظهير المواد الخطرة (H) أو الركاب (P) أو الحافلة المدرسية (S)، بالإضافة إلى مقدّمي طلبات CDL من الفئة A/B لأول مرة والترقيات من الفئة B إلى الفئة A. المصدر: تدريب سائقي المستوى المبتدئ من FMCSA؛ FLHSMV."},"92":{"q":"بعد أن يُكمل مقدّم الطلب ELDT، كيف تعلم FLHSMV أن التدريب قد انتهى؟","options":["يرسل مقدّم الطلب شهادة ورقية مباشرةً إلى مكتب الحاكم","تفحص FLHSMV ماديًا الشاحنة التي تدرّب عليها السائق","يقدّم مزود التدريب الشهادة إلى سجل مزودي التدريب التابع لـ FMCSA، الذي تتحقق منه الولاية قبل الاختبار","لا يحدث أي تحقق؛ يكتفي مقدّم الطلب بالتصريح بأنه أُكمل"],"explanation":"يقدّم مزود التدريب إكمال السائق لـ ELDT إلكترونيًا إلى سجل مزودي التدريب التابع لـ FMCSA، وتتحقق الولاية من السجل قبل السماح باختبار المهارات (أو، بالنسبة لتظهير H، اختبار المعرفة). المصدر: سجل مزودي التدريب التابع لـ FMCSA."},"93":{"q":"ما هي أول وثيقة يحصل عليها الشخص عادةً في طريق الحصول على رخصة CDL في فلوريدا، والتي تتيح له التدرّب على قيادة مركبة تجارية؟","options":["رخصة CDL كاملة غير مقيّدة تُصدر فورًا","بطاقة تظهير للمواد الخطرة","شهادة فاحص طبي من DOT","تصريح متعلم تجاري (CLP)"],"explanation":"يحصل مقدّمو الطلبات أولًا على تصريح متعلم تجاري (CLP) عبر اجتياز اختبارات المعرفة المطلوبة؛ ويتيح لهم CLP التدرّب على الطرق العامة برفقة حامل CDL مؤهل قبل إجراء اختبار المهارات. المصدر: FLHSMV، صفحة رخصة القيادة التجارية."},"94":{"q":"بموجب القواعد الفيدرالية التي تتبعها فلوريدا، ما هو الحد الأدنى للمدة التي يجب أن يحمل فيها السائق CLP قبل إجراء اختبار مهارات CDL؟","options":["14 يومًا على الأقل","لا توجد فترة انتظار دنيا","14 يومًا على الأقل","سنة كاملة واحدة على الأقل"],"explanation":"تتطلب اللائحة الفيدرالية من حامل CLP الانتظار لمدة لا تقل عن 14 يومًا بعد إصدار CLP قبل إجراء اختبار مهارات CDL. المصدر: FMCSA 49 CFR 383.25؛ عملية CDL لدى FLHSMV."},"95":{"q":"إلى متى يجوز أن يبقى تصريح المتعلم التجاري ساريًا قبل أن يُطلب تقديم طلب جديد؟","options":["حتى سنة واحدة من تاريخ الإصدار، مع السماح بالتجديد خلال تلك السنة","حتى عشر سنوات، مثل جواز السفر","فقط 48 ساعة من الإصدار","لا تنتهي صلاحيته أبدًا بمجرد إصداره"],"explanation":"تسمح القواعد الفيدرالية بأن يكون CLP ساريًا لمدة تصل إلى سنة واحدة من الإصدار الأولي؛ ويجوز تجديد CLP الذي صدر لأقل من سنة طالما أنه ليس ساريًا لأكثر من سنة واحدة إجمالًا. المصدر: FMCSA 49 CFR 383.25؛ FLHSMV."},"96":{"q":"يتكوّن اختبار مهارات CDL في فلوريدا من أي ثلاثة أجزاء؟","options":["مقال كتابي ومقابلة شفهية واختبار طباعة","فحص المركبة قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","فحص النظر واختبار السمع واختبار زمن رد الفعل","تغيير الإطار وتغيير الزيت وإعادة بناء المحرك"],"explanation":"يتكوّن اختبار مهارات CDL من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: FLHSMV، صفحة رخصة القيادة التجارية."},"97":{"q":"بأي لغة يجب أن يُجرى اختبار مهارات CDL في فلوريدا؟","options":["أي لغة يختارها مقدّم الطلب","الإسبانية فقط","الإنجليزية","لا يُجرى بأي لغة منطوقة"],"explanation":"تتطلب FLHSMV أن يُجرى اختبار مهارات CDL بالإنجليزية، بما يتفق مع المتطلبات الفيدرالية بأن يكون السائقون التجاريون قادرين على فهم إشارات المرور والتواصل بالإنجليزية. المصدر: FLHSMV، صفحة رخصة القيادة التجارية."},"98":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في فلوريدا، وما القيد الذي ينطبق على السائقين دون سن 21؟","options":["18 عامًا على الأقل، لكن السائقين دون سن 21 مقيّدون عمومًا بالتشغيل داخل الولاية","16 عامًا على الأقل، دون أي قيود تشغيلية","25 عامًا على الأقل لأي فئة CDL","21 عامًا على الأقل، دون أي استثناءات مسموح بها"],"explanation":"يجب أن يكون مقدّمو طلبات CDL في فلوريدا 18 عامًا على الأقل؛ ويُقيَّد من هم دون سن 21 عمومًا بالتجارة داخل الولاية (داخل فلوريدا) حتى يبلغوا 21 عامًا. المصدر: FLHSMV، صفحة رخصة القيادة التجارية."},"99":{"q":"كم مرة يجب على حامل CDL في فلوريدا تجديد رخصة قيادته التجارية؟","options":["كل ستة أشهر","كل عشرين عامًا","مرة واحدة فقط، لأن رخصة CDL لا تنتهي أبدًا","كل ثماني سنوات"],"explanation":"يجب تجديد رخص القيادة في فلوريدا، بما فيها رخص CDL، كل ثماني سنوات؛ ويجب تجديد رخص CDL ولا يمكن تمديدها. وقد تتغير الرسوم الدقيقة، لذا تحقق من FLHSMV للحصول على المبالغ الحالية. المصدر: FLHSMV، صفحة تجديد أو استبدال رخصة قيادتك في فلوريدا."}}};
